/* ── License lookup by unit/stand number ──────────────────────────────
   Allows matching when inspector types just the number, e.g. "101" or "P101".
   Keys are the normalised number token extracted from the seed key prefix.
   Only entries where the number is UNAMBIGUOUS (maps to exactly one license)
   are stored here; shared-number entries (same number, different restaurant,
   different licenses) are excluded to avoid wrong auto-fill.
──────────────────────────────────────────────────────────────────────── */
const LICENSE_SEED_BY_NUMBER = (() => {
  // "101 - Magic City Dogs" → token "101"
  // "P101 - Arepa Cart"     → token "P101"
  const byNum = {};  // num → Set of license values seen
  for (const [key, lic] of Object.entries(HARD_ROCK_LICENSE_SEED)) {
    const m = key.match(/^([A-Z]?\d+[A-Z]?)\s*[-–]?\s*/i);
    if (!m) continue;
    const num = m[1].toUpperCase().trim();
    if (!byNum[num]) byNum[num] = new Set();
    byNum[num].add(lic);
  }
  // Keep only numbers that unambiguously map to a single license
  const result = {};
  for (const [num, lics] of Object.entries(byNum)) {
    if (lics.size === 1) result[num] = [...lics][0];
  }
  return result;
})();

/* ── License lookup by restaurant name only (no number prefix) ────────
   Allows matching when inspector types just the restaurant name, e.g.
   "Magic City Dogs" or "Fatboy Smashburger".
   Only entries where the name maps to exactly one license are stored.
──────────────────────────────────────────────────────────────────────── */
const LICENSE_SEED_BY_NAME = (() => {
  // Strip the leading number/P-number prefix and normalise the remainder
  const byName = {};  // nameNorm → Set of license values seen
  for (const [key, lic] of Object.entries(HARD_ROCK_LICENSE_SEED)) {
    // Remove leading "101 -", "P101 -", "P101", "101" prefixes then normalise
    const stripped = key.replace(/^[A-Z]?\d+[A-Z]?\s*[-–\/]?\s*/i, "").trim();
    if (!stripped) continue;
    const norm = normaliseLocName(stripped);
    if (!norm) continue;
    if (!byName[norm]) byName[norm] = new Set();
    byName[norm].add(lic);
  }
  // Keep only names that unambiguously map to a single license
  const result = {};
  for (const [norm, lics] of Object.entries(byName)) {
    if (lics.size === 1) result[norm] = [...lics][0];
  }
  return result;
})();

/**
 * Look up a license number from the seed tables using multiple strategies:
 * 1. Exact normalised full key match (e.g. "101 MAGIC CITY DOGS")
 * 2. Unit/stand number extracted from the value (e.g. siteNumber "101")
 * 3. Restaurant name only, stripped of number prefix
 * Returns the license string or null.
 */
function lookupLicenseFromSeed(siteNameVal, siteNumberVal) {
  // Strategy 1: full normalised name
  const norm = normaliseLocName(siteNameVal);
  if (norm && LICENSE_SEED_NORM[norm]) return LICENSE_SEED_NORM[norm];

  // Strategy 2: use siteNumber field directly (exact, then normalised)
  if (siteNumberVal) {
    const numKey = String(siteNumberVal).toUpperCase().trim();
    if (LICENSE_SEED_BY_NUMBER[numKey]) return LICENSE_SEED_BY_NUMBER[numKey];
  }

  // Strategy 3: extract a leading number token from siteName itself
  if (siteNameVal) {
    const m = siteNameVal.match(/^([A-Z]?\d+[A-Z]?)\s*[-–]?\s*/i);
    if (m) {
      const numKey = m[1].toUpperCase().trim();
      if (LICENSE_SEED_BY_NUMBER[numKey]) return LICENSE_SEED_BY_NUMBER[numKey];
    }
  }

  // Strategy 4: name-only match (strip number prefix from siteName)
  if (siteNameVal) {
    const stripped = siteNameVal.replace(/^[A-Z]?\d+[A-Z]?\s*[-–\/]?\s*/i, "").trim();
    const nameNorm = normaliseLocName(stripped);
    if (nameNorm && LICENSE_SEED_BY_NAME[nameNorm]) return LICENSE_SEED_BY_NAME[nameNorm];
    // Also try the full value as a name (for no-number sites like "Main Kitchen")
    if (norm && LICENSE_SEED_BY_NAME[norm]) return LICENSE_SEED_BY_NAME[norm];
  }

  return null;
}

