function getAutofillMemory() {
  try { return JSON.parse(localStorage.getItem(AUTOFILL_KEY)) || {}; } catch { return {}; }
}

// Pull shared siteMap from Firestore and merge into local autofill memory.
// Cloud entries never overwrite locally-learned values — local wins on conflict.
async function syncSharedSiteMap() {
  if (!FIREBASE_ON) return;
  try {
    const snap = await getDoc(doc(db, "venues", VENUE_ID, "sharedMemory", "siteMap"));
    if (!snap.exists()) return;
    const cloud = snap.data()?.sites || {};
    if (!Object.keys(cloud).length) return;
    const mem = getAutofillMemory();
    if (!mem.siteMap) mem.siteMap = {};
    // Merge: cloud fills in missing entries; local overrides cloud on conflict
    let changed = false;
    for (const [name, entry] of Object.entries(cloud)) {
      if (!mem.siteMap[name]) {
        mem.siteMap[name] = entry;
        if (!mem.siteName) mem.siteName = [];
        if (!mem.siteName.includes(name)) mem.siteName.unshift(name);
        changed = true;
      }
    }
    if (changed) {
      if (mem.siteName?.length > 200) mem.siteName = mem.siteName.slice(0, 200);
      localStorage.setItem(AUTOFILL_KEY, JSON.stringify(mem));
    }
  } catch { /* ignore — non-critical */ }
}

// Push local siteMap up to Firestore shared memory (admin only, called after seeding)
async function pushSharedSiteMap(siteMap) {
  if (!FIREBASE_ON) return;
  try {
    await setDoc(
      doc(db, "venues", VENUE_ID, "sharedMemory", "siteMap"),
      { sites: siteMap, updatedAt: new Date().toISOString() },
      { merge: false }
    );
  } catch (e) { console.error("pushSharedSiteMap error:", e); }
}

