/* ── HACCP Supervisor Submissions ────────────────────────── */
async function saveHaccpSubmission(record) {
  if (FIREBASE_ON) {
    try {
      const col = IS_DEFAULT_VENUE() ? legacyCol("haccpSubmissions") : venueCol("haccpSubmissions");
      await setDoc(doc(col, record.id), record);
    } catch (e) { console.error(e); }
    return;
  }
  const list = JSON.parse(localStorage.getItem(HACCP_SUBS_KEY) || "[]");
  list.unshift(record);
  localStorage.setItem(HACCP_SUBS_KEY, JSON.stringify(list.slice(0, 200)));
}

async function loadHaccpSubmissions() {
  if (FIREBASE_ON) {
    try {
      const col = IS_DEFAULT_VENUE() ? legacyCol("haccpSubmissions") : venueCol("haccpSubmissions");
      const snap = await getDocs(query(col, orderBy("submittedAt", "desc")));
      return snap.docs.map(d => d.data());
    } catch { return []; }
  }
  try { return JSON.parse(localStorage.getItem(HACCP_SUBS_KEY) || "[]"); } catch { return []; }
}

async function loadHaccpForReport(reportId) {
  if (!reportId) return [];
  if (FIREBASE_ON) {
    try {
      // Query BOTH legacy root collection AND venue-scoped subcollection — same dual-path
      // strategy as subscribeHaccpForReport — so submissions are found regardless of which
      // Firestore path was used at write time (e.g. submissions saved before venue scoping
      // was introduced still live in the legacy root collection).
      const cols = [legacyCol("haccpSubmissions")];
      if (!IS_DEFAULT_VENUE()) cols.push(venueCol("haccpSubmissions"));
      const snaps = await Promise.all(
        cols.map(col => getDocs(query(col, where("reportId", "==", reportId), where("type", "==", "submission"))).catch(() => null))
      );
      const seen = new Set();
      const merged = snaps
        .flatMap(snap => snap ? snap.docs.map(d => d.data()) : [])
        .filter(r => { if (seen.has(r.id)) return false; seen.add(r.id); return true; })
        .sort((a, b) => (a.submittedAt || "").localeCompare(b.submittedAt || ""));
      return merged;
    } catch (e) { console.error("loadHaccpForReport:", e); return []; }
  }
  try {
    const all = JSON.parse(localStorage.getItem(HACCP_SUBS_KEY) || "[]");
    return all
      .filter(r => r.reportId === reportId && r.type === "submission")
      .sort((a, b) => (a.submittedAt || "").localeCompare(b.submittedAt || ""));
  } catch { return []; }
}

/**
 * Fallback HACCP lookup by site name + date (YYYY-MM-DD).
 * Used when loadHaccpForReport returns nothing — e.g. pre-fix records where
 * the QR's ?rid= didn't match the inspection record's id after a page reload.
 * Matches submissions where site matches and submittedAt starts with the date.
 */
async function loadHaccpBySite(siteName, inspectionDate) {
  if (!siteName || !inspectionDate) return [];
  const siteNorm = siteName.trim().toLowerCase();
  const datePrefix = inspectionDate.slice(0, 10); // "YYYY-MM-DD"
  if (FIREBASE_ON) {
    try {
      // Query BOTH legacy root + venue-scoped collections so submissions are found
      // regardless of which Firestore path was used at write time.
      const cols = [legacyCol("haccpSubmissions")];
      if (!IS_DEFAULT_VENUE()) cols.push(venueCol("haccpSubmissions"));
      const snaps = await Promise.all(
        cols.map(col => getDocs(query(col, where("type", "==", "submission"))).catch(() => null))
      );
      const seen = new Set();
      return snaps
        .flatMap(snap => snap ? snap.docs.map(d => d.data()) : [])
        .filter(r => {
          if (seen.has(r.id)) return false; seen.add(r.id);
          return (r.site || "").trim().toLowerCase() === siteNorm &&
                 (r.submittedAt || "").startsWith(datePrefix);
        })
        .sort((a, b) => (a.submittedAt || "").localeCompare(b.submittedAt || ""));
    } catch (e) { console.error("loadHaccpBySite:", e); return []; }
  }
  try {
    const all = JSON.parse(localStorage.getItem(HACCP_SUBS_KEY) || "[]");
    return all
      .filter(r =>
        r.type === "submission" &&
        (r.site || "").trim().toLowerCase() === siteNorm &&
        (r.submittedAt || "").startsWith(datePrefix)
      )
      .sort((a, b) => (a.submittedAt || "").localeCompare(b.submittedAt || ""));
  } catch { return []; }
}

// Real-time HACCP subscription for a specific reportId — returns an unsubscribe fn.
// Runs TWO parallel onSnapshot listeners (no composite index needed):
//   1. Legacy root collection:   /haccpSubmissions
//   2. Venue-scoped subcollection: /venues/{venueId}/haccpSubmissions
// Results from both are merged and de-duplicated by submission id.
// This guarantees data is found regardless of which path was used at write time.
function subscribeHaccpForReport(reportId, onUpdate) {
  if (!reportId) return () => {};

  if (FIREBASE_ON && db) {
    // Shared state: each listener writes its slice; both are merged on every update
    const slices = { legacy: [], venue: [] };
    function merge() {
      const seen = new Set();
      const merged = [...slices.legacy, ...slices.venue]
        .filter(s => { if (seen.has(s.id)) return false; seen.add(s.id); return true; })
        .sort((a, b) => (a.submittedAt || "").localeCompare(b.submittedAt || ""));
      onUpdate(merged);
    }

    const unsubs = [];

    // Helper: attach a single-collection listener (no index required for one where clause)
    function attachListener(col, sliceKey) {
      try {
        const q = query(col, where("reportId", "==", reportId));
        const u = onSnapshot(q, (snap) => {
          slices[sliceKey] = snap.docs
            .map(d => d.data())
            .filter(d => d.type === "submission");
          merge();
        }, (_err) => {
          // Listener failed — fall back to a one-time fetch for this slice
          getDocs(query(col, where("reportId", "==", reportId))).then(snap => {
            slices[sliceKey] = snap.docs.map(d => d.data()).filter(d => d.type === "submission");
            merge();
          }).catch(() => {});
        });
        unsubs.push(u);
      } catch (_e) {
        // Collection reference invalid — leave slice empty, no-op
      }
    }

    // 1. Legacy root collection
    try { attachListener(legacyCol("haccpSubmissions"), "legacy"); } catch (_) {}

    // 2. Venue-scoped subcollection (skip if same as legacy i.e. default venue)
    if (!IS_DEFAULT_VENUE()) {
      try { attachListener(venueCol("haccpSubmissions"), "venue"); } catch (_) {}
    }

    // Emit an initial empty result immediately so UI doesn't hang on first load
    onUpdate([]);

    return () => unsubs.forEach(u => { try { u(); } catch (_) {} });
  }

  // localStorage / no-Firebase fallback — poll every 4s
  loadHaccpForReport(reportId).then(onUpdate);
  const iv = setInterval(() => loadHaccpForReport(reportId).then(onUpdate), 4000);
  return () => clearInterval(iv);
}

