function withChecklist(key, extra = {}) {
  return withPhotos({ status: "OK", notes: "", checklist: (CHECKLIST_DEFAULTS[key] || []).map(i => ({ ...i })), ...extra });
}

// Map from [section][subsection] → checklist key
const CHECKLIST_KEY_MAP = {
  facility:  { ceiling: "ceiling", walls: "walls", floors: "floors", threeCompSinks: "threeCompSinks", handSink: "handSink", mopArea: "mopArea" },
  equipment: { coolers: "coolers", freezer: "freezer", warmers: "warmers", grill: "grill", fryer: "fryer", hood: "hood", iceMaker: "iceMaker", otherEquip: "otherEquip" },
  utensils:  { cleaningUtensils: "cleaningUtensils", cookingUtensils: "cookingUtensils" },
};

// Merge missing checklist arrays into a loaded/restored inspection object.
// This makes old saved records compatible with the new YES/NO checklist UI.
// Existing answers are preserved; only missing checklist arrays are filled in.
function mergeChecklistIntoInspection(inspection) {
  if (!inspection || typeof inspection !== "object") return inspection;
  const result = { ...inspection };
  for (const [section, subsections] of Object.entries(CHECKLIST_KEY_MAP)) {
    if (!result[section]) continue;
    result[section] = { ...result[section] };
    for (const [sub, key] of Object.entries(subsections)) {
      if (!result[section][sub]) continue;
      const node = result[section][sub];
      if (!Array.isArray(node.checklist) || node.checklist.length === 0) {
        result[section][sub] = { ...node, checklist: (CHECKLIST_DEFAULTS[key] || []).map(i => ({ ...i })) };
      }
    }
  }
  return result;
}

