function prettyTitle(noteType, useCase) {
  return `${NOTE_TYPES[noteType].label} → ${useCase}`;
}

function getAtPath(obj, path) {
  return path.reduce((acc, key) => (acc ? acc[key] : undefined), obj);
}

function setAtPath(obj, path, value) {
  const [head, ...rest] = path;
  if (!head) return value;
  return { ...obj, [head]: rest.length ? setAtPath(obj?.[head] ?? {}, rest, value) : value };
}

function bytesToMb(bytes) {
  return Math.round((bytes / (1024 * 1024)) * 10) / 10;
}

function fileToDataUrl(file) {
  return new Promise((resolve) => {
    const reader = new FileReader();
    reader.onload = () => resolve(String(reader.result));
    reader.readAsDataURL(file);
  });
}

// Compress an image file to a smaller data URL using canvas
function compressImage(file, maxDim = 200, quality = 0.3) {
  return new Promise((resolve) => {
    const img = new Image();
    img.onload = () => {
      let { width, height } = img;
      if (width > maxDim || height > maxDim) {
        const ratio = Math.min(maxDim / width, maxDim / height);
        width = Math.round(width * ratio);
        height = Math.round(height * ratio);
      }
      const canvas = document.createElement("canvas");
      canvas.width = width;
      canvas.height = height;
      const ctx = canvas.getContext("2d");
      ctx.drawImage(img, 0, 0, width, height);
      resolve(canvas.toDataURL("image/jpeg", quality));
    };
    img.onerror = () => resolve(null);
    img.src = URL.createObjectURL(file);
  });
}

function countPhotos(inspection) {
  let n = 0;
  const walk = (obj) => {
    if (!obj || typeof obj !== "object") return;
    if (Array.isArray(obj)) { obj.forEach(walk); return; }
    if (obj.photos?.length) n += obj.photos.length;
    for (const v of Object.values(obj)) walk(v);
  };
  walk(inspection);
  return n;
}

function sanitizeText(s) {
  return String(s || "").trim();
}

function parseActionLines(rawNotes) {
  const text = String(rawNotes || "");
  const m = text.match(/action\s*:\s*([\s\S]+)/i);
  if (!m) return [];
  const chunk = m[1].split(/next\s*chk|next\s*check|follow\s*up|owner\s*:/i)[0].trim();
  return chunk
    .split(",")
    .map((x) => sanitizeText(x))
    .filter(Boolean)
    .map((t) => ({ issue: t }));
}

function calcOverallStatus(inspection, { foodTemps, foodTempNames } = {}) {
  // Derive Pass / Needs Attention directly from the score percentage so the
  // overall status badge is always in sync with what the report shows.
  // Threshold: ≥ 80% = Pass  (Grade B or better),  < 80% = Needs Attention.
  // If the score can't be computed yet (checklist not filled in), fall back to
  // the item-scan approach so we never silently show "Pass" on a blank form.
  const score = calcInspectionScore(inspection, { foodTemps, foodTempNames });
  if (score !== null) {
    return score.pct >= 80 ? "Pass" : "Needs Attention";
  }

  // Fallback: scan for any flagged items (handles partially filled / legacy records)
  const bad = [];
  const walk = (node) => {
    if (!node || typeof node !== "object") return;
    if (node.status && (node.status === "Needs Attention" || node.status === "Not Clean" || node.status === "Maintenance")) bad.push(true);
    for (const k of Object.keys(node)) walk(node[k]);
  };
  walk(inspection?.facility);
  walk(inspection?.operations);
  walk(inspection?.equipment);
  walk(inspection?.maintenance);

  const hand = Number(inspection?.temps?.handSinkTempF);
  const three = Number(inspection?.temps?.threeCompSinkTempF);
  if (inspection?.temps?.handSinkOutOfOrder) bad.push(true);
  else if (!Number.isNaN(hand) && hand && hand < 95) bad.push(true);
  if (inspection?.temps?.threeCompSinkOutOfOrder) bad.push(true);
  else if (!Number.isNaN(three) && three && three < 110) bad.push(true);

  return bad.length ? "Needs Attention" : "Pass";
}

/* ── Inspection Score / Grade ────────────────────────────── */
function calcInspectionScore(inspection, { foodTemps, foodTempNames } = {}) {
  // Scored nodes: facility + equipment (modern checklist) + utensils
  const nodes = [
    inspection?.facility?.ceiling,
    inspection?.facility?.walls,
    inspection?.facility?.floors,
    inspection?.facility?.threeCompSinks,
    inspection?.facility?.handSink,
    inspection?.facility?.mopArea,
    inspection?.equipment?.coolers,
    inspection?.equipment?.freezer,
    inspection?.equipment?.warmers,
    inspection?.equipment?.grill,
    inspection?.equipment?.hood,
    inspection?.equipment?.iceMaker,
    inspection?.equipment?.otherEquip,
    inspection?.utensils?.cleaningUtensils,
    inspection?.utensils?.cookingUtensils,
    // Legacy nodes (old saved records)
    inspection?.facility?.lighting,
    inspection?.operations?.employeePractices,
    inspection?.operations?.handwashing,
    inspection?.operations?.labelingDating,
    inspection?.operations?.logs,
    inspection?.equipment?.doubleDoorCooler,
    inspection?.equipment?.doubleDoorFreezer,
    inspection?.equipment?.walkInCooler,
    inspection?.equipment?.walkInFreezer,
    inspection?.equipment?.prepCooler,
    inspection?.equipment?.ovens,
    inspection?.equipment?.threeCompSink,
    inspection?.equipment?.ecolab,
  ].filter(n => n?.status && n.status !== "Off / Not In Use");

  const total = nodes.length;
  if (total === 0) return null; // no scored items — inspection not filled out yet

  const PASS_STATUSES = new Set(["Pass", "OK", "Clean", "Good"]);
  const FAIL_STATUSES = new Set(["Fail", "Needs Attention", "Not Clean", "Fail / Needs Attention"]);
  // N/A and Maintenance/Follow-up don't count for or against score
  const scored = nodes.filter(n => PASS_STATUSES.has(n.status) || FAIL_STATUSES.has(n.status));
  const passed = scored.filter(n => PASS_STATUSES.has(n.status)).length;
  const scoredTotal = scored.length;
  if (scoredTotal === 0) return null;

  let pct = Math.round((passed / scoredTotal) * 100);

  // Temperature readings are tracked as follow-up items and do not affect the inspection score.
  const hasTempViolations = false;

  const grade = pct >= 90 ? "A" : pct >= 80 ? "B" : pct >= 70 ? "C" : pct >= 60 ? "D" : "F";
  const color = pct >= 90 ? "#15803d" : pct >= 80 ? "#ca8a04" : pct >= 70 ? "#ea580c" : "#dc2626";
  return { passed, scoredTotal, pct, grade, color, hasTempViolations, tempPenalty: 0 };
}

/* ── Validation: check for missing fields ────────────────── */
function validateForm({ inspectionDate, inspectorName, context, noteType, inspection, restaurantLicense, locationType, supervisorName, siteName, inspectionType, eventName }) {
  const warnings = [];
  if (!inspectionDate) warnings.push({ text: "Inspection Date is missing", fieldId: "field-inspectionDate" });
  if (!inspectorName) warnings.push({ text: "Inspector Name is missing", fieldId: "field-inspectorName" });
  if (!supervisorName?.trim()) warnings.push({ text: "Supervisor is missing", fieldId: "field-supervisorName" });
  if (!siteName?.trim()) warnings.push({ text: "Restaurant Name is missing", fieldId: "field-siteName" });
  if (!restaurantLicense?.trim()) warnings.push({ text: "Restaurant License # is missing — enter the number or tap \"No License on File\"", fieldId: "field-restaurantLicense" });
  if (inspectionType === "Event Day" && !eventName?.trim()) warnings.push({ text: "Event Name is required for Event Day inspections", fieldId: "field-eventName" });

  const ctxFields = NOTE_TYPES[noteType].contextFields;
  const optionalCtxKeys = ["kitchen", "participants"];
  for (const f of ctxFields) {
    if (optionalCtxKeys.includes(f.key)) continue;
    if (!context[f.key]?.trim()) warnings.push({ text: `${f.label} is missing`, fieldId: `field-ctx-${f.key}` });
  }

  if (inspection.temps.handSinkOutOfOrder) warnings.push({ text: "Hand sink flagged as out of order / not working", fieldId: "field-handSinkTempF" });
  else if (!inspection.temps.handSinkTempF) warnings.push({ text: "Hand sink temperature not recorded", fieldId: "field-handSinkTempF" });
  if (inspection.temps.threeCompSinkOutOfOrder) warnings.push({ text: "3-Comp sink flagged as out of order / not working", fieldId: "field-threeCompSinkTempF" });

  return warnings;
}

function buildSubject({ noteType, context, inspection, inspectionType, inspectionDate, siteName, siteNumber, eventName, foodTemps, foodTempNames }) {
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const baseLocation = siteName || context?.kitchen || "Kitchen";
  const unitTag = siteNumber ? ` (#${siteNumber})` : "";
  const date = inspectionDate || context?.date || "Date";
  const typeTag = inspectionType ? ` – ${inspectionType}` : "";
  const eventTag = eventName ? ` – ${eventName}` : "";
  return `Subject: ${baseLocation}${unitTag} Kitchen Inspection${typeTag}${eventTag} – ${date} – ${status}`;
}

function buildPhotoIndex(inspection, notesPhotos) {
  const order = [
    // ── FACILITIES ──────────────────────────────────────────────
    ["facility", "ceiling",        "Facilities > Ceiling"],
    ["facility", "walls",          "Facilities > Walls"],
    ["facility", "floors",         "Facilities > Floor"],
    ["facility", "threeCompSinks", "Facilities > 3-Compartment Sinks"],
    ["facility", "handSink",       "Facilities > Hand Sink"],
    ["facility", "mopArea",        "Facilities > Mop Area"],
    // ── EQUIPMENTS ──────────────────────────────────────────────
    ["equipment", "coolers",    "Equipments > Coolers"],
    ["equipment", "freezer",    "Equipments > Freezer"],
    ["equipment", "warmers",    "Equipments > Warmers"],
    ["equipment", "grill",      "Equipments > Grill"],
    ["equipment", "fryer",      "Equipments > Fryer"],
    ["equipment", "hood",       "Equipments > Hood"],
    ["equipment", "iceMaker",   "Equipments > Ice Maker Machine"],
    ["equipment", "otherEquip", "Equipments > Other Equipments"],
    // ── UTENSILS ────────────────────────────────────────────────
    ["utensils", "cleaningUtensils", "Utensils > Cleaning Utensils"],
    ["utensils", "cookingUtensils",  "Utensils > Cooking Utensils"],
    // ── LEGACY (for old saved records) ──────────────────────────
    ["facility", "lighting",              "Facility > Lighting"],
    ["operations", "employeePractices",   "Operations > Employee practices"],
    ["operations", "handwashing",         "Operations > Handwashing / supplies"],
    ["operations", "labelingDating",      "Operations > Labeling / dating"],
    ["operations", "logs",                "Operations > Logs / documentation"],
    ["equipment", "doubleDoorCooler",     "Equipment > Double-door cooler"],
    ["equipment", "doubleDoorFreezer",    "Equipment > Double-door freezer"],
    ["equipment", "walkInCooler",         "Equipment > Walk-in cooler"],
    ["equipment", "walkInFreezer",        "Equipment > Walk-in freezer"],
    ["equipment", "prepCooler",           "Equipment > Prep cooler"],
    ["equipment", "ovens",                "Equipment > Ovens"],
    ["equipment", "threeCompSink",        "Equipment > 3-compartment sink"],
    ["equipment", "ecolab",               "Equipment > Ecolab / chemicals"],
    ["maintenance", "hvac",               "Maintenance > HVAC"],
    ["maintenance", "plumbing",           "Maintenance > Plumbing"],
    ["maintenance", "pestControl",        "Maintenance > Pest control"],
    ["maintenance", "electricalSafety",   "Maintenance > Electrical safety"],
    ["maintenance", "dumpsterArea",       "Maintenance > Dumpster area"],
    ["maintenance", "structuralDamage",   "Maintenance > Structural damage"],
  ];
  // Add custom items from each section
  for (const sec of ["facility", "equipment", "utensils", "operations", "maintenance"]) {
    const data = inspection?.[sec] || {};
    for (const k of Object.keys(data)) {
      if (k.startsWith("custom_")) {
        const secLabel = sec.charAt(0).toUpperCase() + sec.slice(1);
        order.push([sec, k, `${secLabel} > ${data[k]?.label || "Custom"}`]);
      }
    }
  }
  let n = 0;
  const index = [];
  const mapByPath = {};
  for (const [a, b, label] of order) {
    const node = inspection?.[a]?.[b];
    const pathKey = `${a}.${b}`;
    // Section-level photos
    const photos = node?.photos || [];
    if (photos.length) {
      mapByPath[pathKey] = mapByPath[pathKey] || [];
      for (const p of photos) {
        n += 1;
        mapByPath[pathKey].push(n);
        const caption = sanitizeText(node?.notes) || sanitizeText(p?.name) || "";
        index.push({ num: n, label, caption, previewUrl: p.previewUrl || p.url || p.dataUrl || null, thumbUrl: p.thumbUrl || null });
      }
    }
    // Checklist-item photos (taken when marking an item ✗)
    const checklist = node?.checklist || [];
    for (const ci of checklist) {
      const ciPhotos = ci.photos || [];
      if (!ciPhotos.length) continue;
      mapByPath[pathKey] = mapByPath[pathKey] || [];
      const ciLabel = `${label} — ${ci.label || "Item"}`;
      for (const p of ciPhotos) {
        n += 1;
        mapByPath[pathKey].push(n);
        const caption = sanitizeText(ci.comment) || sanitizeText(p?.name) || "";
        index.push({ num: n, label: ciLabel, caption, previewUrl: p.previewUrl || p.url || p.dataUrl || null, thumbUrl: p.thumbUrl || null });
      }
    }
  }
  // Include notes photos (attached to the raw notes / inspector notes section)
  const notesPhotoArr = notesPhotos || inspection?._notesPhotos || [];
  for (const p of notesPhotoArr) {
    n += 1;
    index.push({ num: n, label: "Inspector Notes", caption: sanitizeText(p?.name) || "", previewUrl: p.previewUrl || p.url || p.dataUrl || null, thumbUrl: p.thumbUrl || null });
  }
  return { index, mapByPath };
}

function buildActionItems({ inspection, rawNotes, foodTemps: ftArg, foodTempNames: fnArg, foodTempCorrections: fcArg, foodTempSubmitted: fsArg }) {
  const items = [];
  const { mapByPath } = buildPhotoIndex(inspection);
  const pushIfBad = (pathKey, label, node) => {
    if (!node?.status) return;
    if (node.status === "Off / Not In Use") {
      items.push({
        issue: `${label}: Equipment off / not in use — verify before next service`,
        owner: "", due: "",
        priority: "Follow-up",
        photos: mapByPath[pathKey] || [],
      });
      return;
    }
    // Collect specific checklist items marked NO — use problem description so
    // readers immediately understand what the actual issue is.
    const failedChecks = Array.isArray(node.checklist)
      ? node.checklist.filter(c => c.value === "NO").map(c => {
          const base = c.problem || c.label;
          return c.comment?.trim() ? `${base} (${c.comment.trim()})` : base;
        })
      : [];
    const isFail = node.status === "Fail" || node.status === "Needs Attention" || node.status === "Not Clean" || node.status === "Maintenance";
    if (!isFail && failedChecks.length === 0) return;
    // Skip if no specific detail — avoids phantom "Issue noted" from stale statuses
    if (failedChecks.length === 0 && !sanitizeText(node.notes)) return;
    // Build issue description: list specific failed items, then other notes
    const failDetail = failedChecks.length > 0
      ? failedChecks.join(", ")
      : sanitizeText(node.notes);
    const otherNote = sanitizeText(node.notes);
    const issueText = failedChecks.length > 0 && otherNote
      ? `${failDetail} — Other: ${otherNote}`
      : failDetail;
    items.push({
      issue: `${label}: ${failDetail}`,
      notes: otherNote || "",
      owner: "", due: "",
      // Normalize old "High"/"Med" stored in node.status — those are priority values, not statuses
      status: (node.status && node.status !== "High" && node.status !== "Med" ? node.status : "") || (failedChecks.length > 0 ? "Fail" : ""),
      priority: node.status === "Maintenance" ? "Maintenance" : (node.status === "Fail" || node.status === "Not Clean" || failedChecks.length > 0) ? "High" : "Med",
      photos: mapByPath[pathKey] || [],
    });
  };
  // ── FACILITIES ────────────────────────────────────────────────
  pushIfBad("facility.ceiling",        "Facilities – Ceiling",               inspection?.facility?.ceiling);
  pushIfBad("facility.walls",          "Facilities – Walls",                 inspection?.facility?.walls);
  pushIfBad("facility.floors",         "Facilities – Floor",                 inspection?.facility?.floors);
  pushIfBad("facility.threeCompSinks", "Facilities – 3-Compartment Sinks",   inspection?.facility?.threeCompSinks);
  pushIfBad("facility.handSink",       "Facilities – Hand Sink",             inspection?.facility?.handSink);
  pushIfBad("facility.mopArea",        "Facilities – Mop Area",              inspection?.facility?.mopArea);
  // ── EQUIPMENTS ────────────────────────────────────────────────
  pushIfBad("equipment.coolers",    "Equipments – Coolers",             inspection?.equipment?.coolers);
  pushIfBad("equipment.freezer",    "Equipments – Freezer",             inspection?.equipment?.freezer);
  pushIfBad("equipment.warmers",    "Equipments – Warmers",             inspection?.equipment?.warmers);
  pushIfBad("equipment.grill",      "Equipments – Grill",               inspection?.equipment?.grill);
  pushIfBad("equipment.fryer",      "Equipments – Fryer",               inspection?.equipment?.fryer);
  pushIfBad("equipment.hood",       "Equipments – Hood",                inspection?.equipment?.hood);
  pushIfBad("equipment.iceMaker",   "Equipments – Ice Maker Machine",   inspection?.equipment?.iceMaker);
  pushIfBad("equipment.otherEquip", "Equipments – Other Equipments",    inspection?.equipment?.otherEquip);
  // ── UTENSILS ──────────────────────────────────────────────────
  pushIfBad("utensils.cleaningUtensils", "Utensils – Cleaning Utensils", inspection?.utensils?.cleaningUtensils);
  pushIfBad("utensils.cookingUtensils",  "Utensils – Cooking Utensils",  inspection?.utensils?.cookingUtensils);
  // ── LEGACY (old saved records) ────────────────────────────────
  pushIfBad("facility.lighting",              "Lighting",               inspection?.facility?.lighting);
  pushIfBad("operations.employeePractices",   "Employee practices",     inspection?.operations?.employeePractices);
  pushIfBad("operations.handwashing",         "Handwashing / supplies", inspection?.operations?.handwashing);
  pushIfBad("operations.labelingDating",      "Labeling / dating",      inspection?.operations?.labelingDating);
  pushIfBad("operations.logs",                "Logs / documentation",   inspection?.operations?.logs);
  pushIfBad("equipment.doubleDoorCooler",     "Double-door cooler",     inspection?.equipment?.doubleDoorCooler);
  pushIfBad("equipment.doubleDoorFreezer",    "Double-door freezer",    inspection?.equipment?.doubleDoorFreezer);
  pushIfBad("equipment.walkInCooler",         "Walk-in cooler",         inspection?.equipment?.walkInCooler);
  pushIfBad("equipment.walkInFreezer",        "Walk-in freezer",        inspection?.equipment?.walkInFreezer);
  pushIfBad("equipment.prepCooler",           "Prep cooler",            inspection?.equipment?.prepCooler);
  pushIfBad("equipment.ovens",                "Ovens",                  inspection?.equipment?.ovens);
  pushIfBad("equipment.threeCompSink",        "3-compartment sink",     inspection?.equipment?.threeCompSink);
  pushIfBad("equipment.ecolab",               "Ecolab / chemicals",     inspection?.equipment?.ecolab);
  // Maintenance items — priority pulled from the node itself
  const pushMaint = (pathKey, label, node) => {
    if (!node?.status) return;
    if (node.status === "Needs Attention" || node.status === "Not Clean" || node.status === "Maintenance") {
      const detail = sanitizeText(node.notes);
      if (!detail) return; // skip if no description
      items.push({
        issue: `Maintenance – ${label}: ${detail}`,
        owner: "", due: "",
        priority: "Maintenance",
        photos: mapByPath[pathKey] || [],
      });
    }
  };
  pushMaint("maintenance.hvac",             "HVAC",               inspection?.maintenance?.hvac);
  pushMaint("maintenance.plumbing",         "Plumbing",           inspection?.maintenance?.plumbing);
  pushMaint("maintenance.pestControl",      "Pest control",       inspection?.maintenance?.pestControl);
  pushMaint("maintenance.electricalSafety", "Electrical safety",  inspection?.maintenance?.electricalSafety);
  pushMaint("maintenance.dumpsterArea",     "Dumpster / waste area", inspection?.maintenance?.dumpsterArea);
  pushMaint("maintenance.structuralDamage", "Structural damage",  inspection?.maintenance?.structuralDamage);
  // Custom maintenance items
  const maintData = inspection?.maintenance || {};
  for (const [k, node] of Object.entries(maintData)) {
    if (k.startsWith("custom_")) pushMaint(`maintenance.${k}`, node?.label || k, node);
  }
  // Water temps / out-of-order
  if (inspection?.temps?.handSinkOutOfOrder) {
    const note = inspection?.temps?.handSinkNote?.trim();
    items.push({ issue: `Hand sink out of order / not working${note ? ": " + note : ""}`, owner: "", due: "", priority: "Follow-up", photos: [] });
  } else {
    const hand = Number(inspection?.temps?.handSinkTempF);
    if (!Number.isNaN(hand) && hand && hand < 95)
      items.push({ issue: `Hand sink temperature below minimum: ${hand}°F (min 95°F)`, owner: "", due: "", priority: "Follow-up", photos: [] });
  }
  if (inspection?.temps?.threeCompSinkOutOfOrder) {
    const note = inspection?.temps?.threeCompSinkNote?.trim();
    items.push({ issue: `3-Comp sink out of order / not working${note ? ": " + note : ""}`, owner: "", due: "", priority: "Follow-up", photos: [] });
  } else {
    const three = Number(inspection?.temps?.threeCompSinkTempF);
    if (!Number.isNaN(three) && three && three < 110)
      items.push({ issue: `3-compartment sink wash temperature below minimum: ${three}°F (min 110°F)`, owner: "", due: "", priority: "Follow-up", photos: [] });
  }
  // HACCP food temps — flag any reading outside safe range
  // ftArg/fnArg passed from live form; fall back to embedded fields on saved records
  const ft = ftArg || inspection?.foodTemps || {};
  const fn = fnArg || inspection?.foodTempNames || {};
  const fc = fcArg || inspection?.foodTempCorrections || {};
  const fs = fsArg || inspection?.foodTempSubmitted || {};
  for (const item of HACCP_TEMP_ITEMS) {
    const allVals = ft[item.key] || [];
    const names = fn[item.key] || [];
    const corrections = fc[item.key] || [];
    const submittedFlags = fs[item.key] || [];
    // Only consider submitted readings — skip unsubmitted (they haven't been confirmed yet)
    const vals = allVals.filter((v, i) => v !== "" && submittedFlags[i] === true);
    const submittedIndexes = allVals.map((v, i) => v !== "" && submittedFlags[i] === true ? i : -1).filter(i => i >= 0);
    vals.forEach((v, vi) => {
      const origIdx = submittedIndexes[vi];
      const pass = tempPass(item, v);
      if (pass === false) {
        const foodLabel = names[origIdx]?.trim() ? ` (${names[origIdx].trim()})` : "";
        const threshold = item.type === "hot" ? `min ${item.min}°F` : `max ${item.max}°F`;
        const corrective = (corrections[origIdx] || "").trim();
        const correctiveText = corrective ? ` — Corrective action: ${corrective}` : "";
        items.push({
          issue: `HACCP – ${item.label}${foodLabel}: out-of-range reading ${Number(v)}°F (${threshold})${correctiveText}`,
          owner: "", due: "",
          priority: "Follow-up",
          photos: [],
        });
      }
    });
  }
  // Per-equipment cold temps — 3-zone: good / warn / bad
  for (const et of collectEquipTemps(inspection)) {
    if (et.zone === "bad") {
      items.push({ issue: `${et.label} temperature too warm: ${et.tempNum}°F (safe limit ${et.max}°F — monitor and recheck)`, owner: "", due: "", priority: "Follow-up", photos: [] });
    } else if (et.zone === "warn") {
      items.push({ issue: `${et.label} temperature elevated: ${et.tempNum}°F (above ${et.max}°F — monitor closely and recheck in 30 min)`, owner: "", due: "", priority: "Follow-up", photos: [] });
    }
  }
  for (const a of parseActionLines(rawNotes))
    items.push({ issue: a.issue, owner: "", due: "", priority: "Med", photos: [] });
  const seen = new Set();
  return items.filter((it) => { const k = it.issue.toLowerCase(); if (seen.has(k)) return false; seen.add(k); return true; });
}

function tableMarkdown(rows) {
  const header = "| Issue | Owner | Due | Priority | Photo # |\n|---|---|---|---|---|";
  const body = rows
    .map((r) => {
      const photos = (r.photos || []).length ? r.photos.join(", ") : "";
      return `| ${sanitizeText(r.issue)} | ${sanitizeText(r.owner)} | ${sanitizeText(r.due)} | ${sanitizeText(r.priority)} | ${photos} |`;
    })
    .join("\n");
  return `${header}\n${body || "|  |  |  |  |  |"}`;
}

function emailPreview({ noteType, context, inspection, rawNotes, inspectionType, inspectionDate, inspectorName, participantName, siteName, siteNumber, sitePhone, supervisorName, floor, eventName, reportLang, foodTemps, foodTempNames }) {
  const lbl = REPORT_LABELS[reportLang] || REPORT_LABELS.en;
  const playbook = INSPECTION_PLAYBOOK[inspectionType] || INSPECTION_PLAYBOOK["Regular Inspection"];
  const subject = buildSubject({ noteType, context, inspection, inspectionType, inspectionDate, siteName, siteNumber, eventName, foodTemps, foodTempNames });
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const actionItems = buildActionItems({ inspection, rawNotes, foodTemps, foodTempNames });
  const { index: photoIndexList } = buildPhotoIndex(inspection);
  const location = siteName || context?.kitchen || "Kitchen";
  const unit = siteNumber ? ` (#${siteNumber})` : "";
  const date = inspectionDate || context?.date || "—";
  const snapshotLines = [
    `- ${lbl.inspectionType || "Inspection Type"}: ${inspectionType || "—"}`,
    eventName ? `- ${lbl.event || "Event"}: ${eventName}` : null,
    `- ${lbl.site || "Site"}: ${location}${unit}`,
    floor ? `- ${lbl.floor || "Floor"}: ${floor}` : null,
    `- ${lbl.date || "Date"}: ${date}`,
    `- ${lbl.inspector}: ${inspectorName || "—"}`,
    participantName ? `- ${lbl.participant}: ${participantName}` : null,
    `- ${lbl.supervisor || "Supervisor"}: ${supervisorName || "—"}`,
    sitePhone ? `- ${lbl.phone || "Site Phone"}: ${sitePhone}` : null,
    `- ${lbl.status}: ${status}`,
  ].filter(Boolean).join("\n");
  const ctxLines = [
    `- siteName: ${siteName || "—"}`,
    `- siteNumber: ${siteNumber || "—"}`,
    `- supervisorName: ${supervisorName || "—"}`,
    sitePhone ? `- sitePhone: ${sitePhone}` : null,
    ...Object.entries(context || {}).map(([k, v]) => `- ${k}: ${v || "—"}`),
  ].filter(Boolean).join("\n");
  const photoIndex = photoIndexList.length
    ? photoIndexList.map((p) => `Photo ${p.num} — ${p.label}${p.caption ? ` — ${p.caption}` : ""}`).join("\n")
    : "No photos attached.";
  const findings = [];
  const addFinding = (label, node) => {
    if (!node) return;
    if (node.status && node.status !== "OK" && node.status !== "N/A")
      findings.push(`- ${label}: ${node.status}${node.notes ? ` — ${node.notes}` : ""}`);
  };
  addFinding(`${lbl.facility} > ${lbl.ceiling}`, inspection?.facility?.ceiling);
  addFinding(`${lbl.facility} > ${lbl.walls}`, inspection?.facility?.walls);
  addFinding(`${lbl.facility} > ${lbl.floors}`, inspection?.facility?.floors);
  addFinding(`${lbl.facility} > ${lbl.lighting}`, inspection?.facility?.lighting);
  addFinding(`${lbl.operations} > ${lbl.employeePractices}`, inspection?.operations?.employeePractices);
  addFinding(`${lbl.operations} > ${lbl.handwashing}`, inspection?.operations?.handwashing);
  addFinding(`${lbl.operations} > ${lbl.labelingDating}`, inspection?.operations?.labelingDating);
  addFinding(`${lbl.operations} > ${lbl.logs}`, inspection?.operations?.logs);
  addFinding(`${lbl.equipment} > ${lbl.doubleDoorCooler}`, inspection?.equipment?.doubleDoorCooler);
  addFinding(`${lbl.equipment} > ${lbl.doubleDoorFreezer}`, inspection?.equipment?.doubleDoorFreezer);
  addFinding(`${lbl.equipment} > ${lbl.walkInCooler}`, inspection?.equipment?.walkInCooler);
  addFinding(`${lbl.equipment} > ${lbl.warmers}`, inspection?.equipment?.warmers);
  addFinding(`${lbl.equipment} > ${lbl.ovens}`, inspection?.equipment?.ovens);
  addFinding(`${lbl.equipment} > ${lbl.threeCompSink}`, inspection?.equipment?.threeCompSink);
  addFinding(`${lbl.equipment} > ${lbl.ecolab}`, inspection?.equipment?.ecolab);
  const handT = Number(inspection?.temps?.handSinkTempF);
  const threeT = Number(inspection?.temps?.threeCompSinkTempF);
  if (!Number.isNaN(handT) && handT && handT < 95) findings.push(`- Temps > Hand sink: ${handT}°F (below 95°F minimum)`);
  if (!Number.isNaN(threeT) && threeT && threeT < 110) findings.push(`- Temps > 3-comp wash: ${threeT}°F (below 110°F minimum)`);
  const findingsText = findings.length ? findings.join("\n") : "- No exceptions noted from checklist/temps.";
  const critical = actionItems.filter((a) => a.priority === "High").map((a) => `- ${a.issue}${a.photos?.length ? ` (Photo ${a.photos.join(", ")})` : ""}`).join("\n");
  const criticalText = critical || (inspectionType === "Event Day" ? "- No critical blockers identified for service." : "- No critical issues flagged.");
  return [
    subject, "", `Hi team,`, "", playbook.opening, "",
    `## ${playbook.headline} — ${lbl.summary || "Snapshot"}`, snapshotLines, "",
    `## ${lbl.context || "Context (from sit-down notes)"}`, ctxLines || "- —", "",
    `## ${lbl.criticalRisks || "Critical Risks"}`, criticalText, "",
    `## ${lbl.findingsByArea || "Findings by Area"}`, findingsText, "",
    `## ${lbl.actionItems} (${lbl.assignNote || "please assign Owner + Due"})`, tableMarkdown(actionItems), "",
    `## ${lbl.photoIndex || "Photo Index"}`, photoIndex, "",
    `## ${lbl.notes} (${lbl.organized || "organized"})`, formatNotesText(rawNotes) || "—",
  ].join("\n");
}

