/* ── Local Transform (no backend needed) ─────────────────── */
function transformLocally({ noteType, useCase, context, inspection, rawNotes, inspectionType, inspectionDate, inspectorName, participantName, siteName, siteNumber, sitePhone, supervisorName, floor, eventName, reportLang, foodTemps, foodTempNames }) {
  const lbl = REPORT_LABELS[reportLang] || REPORT_LABELS.en;
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const actionItems = buildActionItems({ inspection, rawNotes, foodTemps, foodTempNames });
  const expandedNotes = expandAbbreviations(rawNotes);
  const location = siteName || context?.kitchen || "Kitchen";
  const date = inspectionDate || context?.date || "—";
  const eventTag = eventName ? ` — ${eventName}` : "";

  if (useCase === "Email Summary") {
    return emailPreview({ noteType, context, inspection, rawNotes, inspectionType, inspectionDate, inspectorName, participantName, siteName, siteNumber, sitePhone, supervisorName, floor, eventName, reportLang, foodTemps, foodTempNames });
  }

  if (useCase === "Slack Update") {
    const lines = [
      `*${inspectionType || "Inspection"}${eventTag} — ${location} — ${date}*`,
      `${lbl.inspector}: ${inspectorName || "—"}${participantName ? ` | ${lbl.participant}: ${participantName}` : ""} | ${lbl.status}: *${status}*`,
      "",
      `*${lbl.summary}:*`,
      formatNotesText(rawNotes),
      "",
    ];
    if (actionItems.length) {
      lines.push(`*${lbl.actionItems} (${actionItems.length}):*`);
      for (const a of actionItems) lines.push(`  • [${a.priority}] ${a.issue}`);
    } else {
      lines.push(lbl.none);
    }
    return lines.join("\n");
  }

  if (useCase === "Google Doc") {
    const lines = [
      `# ${inspectionType || "Inspection"}${eventTag} — ${location}`,
      `Date: ${date} | ${lbl.inspector}: ${inspectorName || "—"}${participantName ? ` | ${lbl.participant}: ${participantName}` : ""} | ${lbl.supervisor}: ${supervisorName || "—"}`,
      `${lbl.overall} ${lbl.status}: ${status}`,
      "",
      `## ${lbl.notes}`,
      formatNotesText(rawNotes),
      "",
      `## ${lbl.findings}`,
    ];
    const addFinding = (label, node) => {
      if (node?.status && node.status !== "OK" && node.status !== "N/A")
        lines.push(`- **${label}**: ${node.status}${node.notes ? ` — ${node.notes}` : ""}`);
    };
    addFinding("Ceiling", inspection?.facility?.ceiling);
    addFinding("Walls", inspection?.facility?.walls);
    addFinding("Floors", inspection?.facility?.floors);
    addFinding("Lighting", inspection?.facility?.lighting);
    addFinding("Employee practices", inspection?.operations?.employeePractices);
    addFinding("Handwashing", inspection?.operations?.handwashing);
    addFinding("Labeling / dating", inspection?.operations?.labelingDating);
    addFinding("Logs", inspection?.operations?.logs);
    addFinding("Double-Door Cooler", inspection?.equipment?.doubleDoorCooler);
    addFinding("Double-Door Freezer", inspection?.equipment?.doubleDoorFreezer);
    addFinding("Walk-In Cooler", inspection?.equipment?.walkInCooler);
    addFinding("Warmers / Hot Holding", inspection?.equipment?.warmers);
    addFinding("Ovens", inspection?.equipment?.ovens);
    addFinding("3-Compartment Sink", inspection?.equipment?.threeCompSink);
    addFinding("Ecolab / Chemicals", inspection?.equipment?.ecolab);
    if (lines[lines.length - 1] === `## ${lbl.findings}`) lines.push("- All areas OK.");
    lines.push("", `## ${lbl.actionItems}`);
    if (actionItems.length) {
      lines.push(tableMarkdown(actionItems));
    } else {
      lines.push(lbl.none);
    }
    return lines.join("\n");
  }

  if (useCase === "Evaluation Scorecard") {
    const sections = [
      { title: "Facility", items: [
        ["Ceiling", inspection?.facility?.ceiling],
        ["Walls", inspection?.facility?.walls],
        ["Floors", inspection?.facility?.floors],
        ["Lighting", inspection?.facility?.lighting],
      ]},
      { title: "Operations", items: [
        ["Employee practices", inspection?.operations?.employeePractices],
        ["Handwashing", inspection?.operations?.handwashing],
        ["Labeling / dating", inspection?.operations?.labelingDating],
        ["Logs", inspection?.operations?.logs],
      ]},
      { title: "Equipment", items: [
        ["Double-Door Cooler", inspection?.equipment?.doubleDoorCooler],
        ["Double-Door Freezer", inspection?.equipment?.doubleDoorFreezer],
        ["Walk-In Cooler", inspection?.equipment?.walkInCooler],
        ["Warmers / Hot Holding", inspection?.equipment?.warmers],
        ["Ovens", inspection?.equipment?.ovens],
        ["3-Compartment Sink", inspection?.equipment?.threeCompSink],
        ["Ecolab / Chemicals", inspection?.equipment?.ecolab],
      ]},
    ];
    const lines = [
      lbl.scorecard,
      `${"=".repeat(50)}`,
      `${inspectionType || "Inspection"}${eventTag} — ${location} — ${date}`,
      `${lbl.inspector}: ${inspectorName || "—"}${participantName ? ` | ${lbl.participant}: ${participantName}` : ""}`,
      `${lbl.overall}: ${status}`,
      "",
    ];
    for (const sec of sections) {
      lines.push(`--- ${sec.title.toUpperCase()} ---`);
      for (const [label, node] of sec.items) {
        const s = node?.status || "N/A";
        const icon = s === "OK" ? "[PASS]" : s === "N/A" ? "[ -- ]" : "[FAIL]";
        lines.push(`  ${icon} ${label}${node?.notes ? ` — ${node.notes}` : ""}`);
      }
      lines.push("");
    }
    lines.push(`--- ${lbl.temperatures.toUpperCase()} ---`);
    const hs = inspection?.temps?.handSinkTempF;
    const ts = inspection?.temps?.threeCompSinkTempF;
    const hsNote = inspection?.temps?.handSinkNote?.trim();
    const tsNote = inspection?.temps?.threeCompSinkNote?.trim();
    lines.push(`  Hand sink water temperature: ${hs || "—"}°F ${Number(hs) >= 95 ? "[PASS]" : hs ? "[FAIL]" : ""}${hsNote ? `\n    Note: ${hsNote}` : ""}`);
    lines.push(`  3-compartment sink wash temperature: ${ts || "—"}°F ${Number(ts) >= 110 ? "[PASS]" : ts ? "[FAIL]" : ""}${tsNote ? `\n    Note: ${tsNote}` : ""}`);
    lines.push("", `--- ${lbl.actionItems.toUpperCase()} (${actionItems.length}) ---`);
    for (const a of actionItems) lines.push(`  [${a.priority}] ${a.issue}`);
    if (!actionItems.length) lines.push(`  ${lbl.none}`);
    lines.push("", `--- ${lbl.notes.toUpperCase()} ---`, formatNotesText(rawNotes));
    return lines.join("\n");
  }

  return emailPreview({ noteType, context, inspection, rawNotes, inspectionType, inspectionDate, inspectorName, participantName, siteName, siteNumber, sitePhone, supervisorName, floor, eventName, reportLang, foodTemps, foodTempNames });
}

/* ── AI Assist: smart suggestions from checklist + notes ── */
function aiAssist({ inspection, rawNotes, context, noteType }) {
  const tips = [];
  const notes = (rawNotes || "").toLowerCase();

  // Check for items flagged "Needs Attention" without notes
  const checkNode = (label, node) => {
    if (node?.status === "Needs Attention" && !node?.notes?.trim()) {
      tips.push(`"${label}" is flagged Needs Attention but has no notes — add details so corrective actions are clear.`);
    }
    if (node?.status === "Not Clean" && !node?.notes?.trim()) {
      tips.push(`"${label}" is flagged Not Clean but has no notes — describe the issue for the report.`);
    }
  };
  checkNode("Ceiling", inspection?.facility?.ceiling);
  checkNode("Walls", inspection?.facility?.walls);
  checkNode("Floors", inspection?.facility?.floors);
  checkNode("Lighting", inspection?.facility?.lighting);
  checkNode("Employee practices", inspection?.operations?.employeePractices);
  checkNode("Handwashing", inspection?.operations?.handwashing);
  checkNode("Labeling / dating", inspection?.operations?.labelingDating);
  checkNode("Logs", inspection?.operations?.logs);
  checkNode("Double-Door Cooler", inspection?.equipment?.doubleDoorCooler);
  checkNode("Double-Door Freezer", inspection?.equipment?.doubleDoorFreezer);
  checkNode("Walk-In Cooler", inspection?.equipment?.walkInCooler);
  checkNode("Walk-In Freezer", inspection?.equipment?.walkInFreezer);
  checkNode("Prep Cooler", inspection?.equipment?.prepCooler);
  checkNode("Warmers / Hot Holding", inspection?.equipment?.warmers);
  checkNode("Ovens", inspection?.equipment?.ovens);
  checkNode("3-Compartment Sink", inspection?.equipment?.threeCompSink);
  checkNode("Ecolab / Chemicals", inspection?.equipment?.ecolab);

  // Water temperature checks
  const hs = Number(inspection?.temps?.handSinkTempF);
  const ts = Number(inspection?.temps?.threeCompSinkTempF);
  if (hs && hs < 95) tips.push(`Hand sink temp is ${hs}°F (below 95°F min). Flag for immediate maintenance.`);
  if (ts && ts < 110) tips.push(`3-comp sink wash temp is ${ts}°F (below 110°F min). Check water heater.`);
  if (hs && hs >= 95 && hs < 100) tips.push(`Hand sink temp is ${hs}°F — passes but is close to the 95°F minimum. Monitor.`);
  if (ts && ts >= 110 && ts < 115) tips.push(`3-comp wash temp is ${ts}°F — passes but is close to the 110°F minimum. Monitor.`);
  // Per-equipment cold temps — 3-zone tips
  for (const et of collectEquipTemps(inspection)) {
    if (et.zone === "bad") {
      tips.push(`${et.label} temp is ${et.tempNum}°F — above ${et.max}°F. ${et.type === "freezer" ? "Check compressor and door seals immediately." : "Do not store food here — fix refrigeration immediately."}`);
    } else if (et.zone === "warn") {
      tips.push(`${et.label} temp is ${et.tempNum}°F — above the ${et.max}°F safe limit but not yet critical. Recheck in 30 minutes and monitor door seals.`);
    } else if (et.type === "cooler" && et.tempNum > 35) {
      tips.push(`${et.label} temp is ${et.tempNum}°F — passes but close to the 40°F maximum. Monitor.`);
    } else if (et.type === "freezer" && et.tempNum > 15) {
      tips.push(`${et.label} temp is ${et.tempNum}°F — passes but close to the 20°F maximum. Monitor.`);
    }
  }

  // Raw notes analysis
  if (notes.includes("allergen")) tips.push("Allergen concerns detected in notes — ensure allergen training is scheduled and documented.");
  if (notes.includes("haccp")) tips.push("HACCP mentioned — verify all HACCP logs are complete and signed before next inspection.");
  if (notes.includes("pest") || notes.includes("trap")) tips.push("Pest control mentioned — document trap locations and schedule pest vendor follow-up.");
  if (notes.includes("cutting board") || notes.includes("scored")) tips.push("Scored cutting boards noted — replace immediately per food safety protocol.");
  if (notes.includes("calibrat")) tips.push("Thermometer calibration mentioned — document last calibration date and schedule next.");

  // Action items without specific owners
  const actionLines = parseActionLines(rawNotes);
  if (actionLines.length > 3) tips.push(`${actionLines.length} action items found in notes — consider prioritizing the top 3 for immediate follow-up.`);

  if (!tips.length) tips.push("No issues detected. Inspection looks clean!");

  return tips;
}

/* ── AI Export Summary: executive summary for documents ───── */
function buildExportSummary({ inspection, rawNotes, inspectionType, inspectionDate, siteName, foodTemps, foodTempNames }) {
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const actionItems = buildActionItems({ inspection, rawNotes, foodTemps, foodTempNames });
  const tips = aiAssist({ inspection, rawNotes, context: {}, noteType: "Kitchen Inspection" });
  const date = inspectionDate || new Date().toLocaleDateString();
  const loc = siteName || "the inspected location";

  // Count statuses
  let okCount = 0, attentionCount = 0, notCleanCount = 0;
  const sections = ["facility", "operations", "equipment"];
  for (const sec of sections) {
    const data = inspection?.[sec] || {};
    for (const k of Object.keys(data)) {
      const s = data[k]?.status;
      if (s === "OK") okCount++;
      else if (s === "Needs Attention") attentionCount++;
      else if (s === "Not Clean") notCleanCount++;
    }
  }
  const total = okCount + attentionCount + notCleanCount;
  const passRate = total > 0 ? Math.round((okCount / total) * 100) : 100;

  // Build summary paragraphs
  const lines = [];
  if (status === "Pass") {
    lines.push(`This ${inspectionType || "inspection"} of ${loc} on ${date} resulted in an overall PASS with a ${passRate}% compliance rate. ${okCount} of ${total} items met standards.`);
  } else {
    lines.push(`This ${inspectionType || "inspection"} of ${loc} on ${date} requires attention. ${notCleanCount + attentionCount} of ${total} items were flagged, resulting in a ${passRate}% compliance rate.`);
  }

  const followUpCount = actionItems.filter(a => a.priority === "Follow-up").length;
  const otherActionCount = actionItems.filter(a => a.priority !== "Follow-up").length;
  if (otherActionCount > 0) {
    lines.push(`${otherActionCount} corrective action${otherActionCount !== 1 ? "s" : ""} identified. Follow-up recommended.`);
  }

  // Temp summary
  const handT = Number(inspection?.temps?.handSinkTempF);
  const threeT = Number(inspection?.temps?.threeCompSinkTempF);
  const eTemps = collectEquipTemps(inspection);
  const tempIssues = [];
  if (!Number.isNaN(handT) && inspection?.temps?.handSinkTempF !== "" && handT < 95) tempIssues.push(`hand sink at ${handT}\u00B0F (below 95\u00B0F)`);
  if (!Number.isNaN(threeT) && inspection?.temps?.threeCompSinkTempF !== "" && threeT < 110) tempIssues.push(`3-comp wash at ${threeT}\u00B0F (below 110\u00B0F)`);
  for (const et of eTemps) {
    if (!et.pass) tempIssues.push(`${et.label} at ${et.tempNum}\u00B0F (above ${et.max}\u00B0F)`);
  }
  if (tempIssues.length > 0) {
    lines.push(`Temperature follow-up items noted: ${tempIssues.join("; ")}. These have been logged as follow-up action items.`);
  } else {
    const tempOk = [];
    if (!Number.isNaN(handT) && inspection?.temps?.handSinkTempF !== "") tempOk.push("hand sink");
    if (!Number.isNaN(threeT) && inspection?.temps?.threeCompSinkTempF !== "") tempOk.push("3-comp wash");
    for (const et of eTemps) tempOk.push(et.label.toLowerCase());
    if (tempOk.length) lines.push(`All recorded temperatures (${tempOk.join(", ")}) are within acceptable ranges.`);
  }

  // Smart recommendations
  const recs = [];
  if (notCleanCount > 0) recs.push("Schedule re-inspection within 48 hours for all Not Clean items.");
  if (attentionCount >= 3) recs.push("Consider additional staff training — multiple areas flagged for attention.");
  if (tempIssues.length > 0) recs.push("Monitor and recheck out-of-range temperatures. Contact maintenance if issue persists.");
  if (actionItems.length === 0 && status === "Pass") recs.push("No corrective actions needed. Continue current maintenance schedule.");
  if (recs.length) lines.push("Recommendations: " + recs.join(" "));

  return lines.join("\n\n");
}

/* ── Rendered Output Component (visual, not code) ────────── */
function RenderedOutput({ noteType, useCase, context, inspection, rawNotes, inspectionType, inspectionDate, inspectorName, participantName, siteName, siteNumber, restaurantLicense, sitePhone, supervisorName, locationType, floor, eventName, reportLang, foodTemps, foodTempNames }) {
  const lbl = REPORT_LABELS[reportLang] || REPORT_LABELS.en;
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const actionItems = buildActionItems({ inspection, rawNotes, foodTemps, foodTempNames });
  const expandedNotes = expandAbbreviations(rawNotes);
  const location = siteName || context?.kitchen || "Kitchen";
  const date = inspectionDate || context?.date || new Date().toLocaleDateString();
  const playbook = INSPECTION_PLAYBOOK[inspectionType] || INSPECTION_PLAYBOOK["Regular Inspection"];
  const { index: photoIndexList } = buildPhotoIndex(inspection);
  const [lightboxSrc, setLightboxSrc] = React.useState(null);
  // Stable report ID — generated once per render mount, not on every re-render
  const reportId = React.useMemo(() => Date.now().toString(36).toUpperCase(), []);

  const handT = Number(inspection?.temps?.handSinkTempF);
  const threeT = Number(inspection?.temps?.threeCompSinkTempF);
  const equipTemps = collectEquipTemps(inspection);

  // Collect custom items from each section
  function getCustomItems(sectionKey, sectionLabel) {
    const data = inspection?.[sectionKey] || {};
    return Object.keys(data).filter(k => k.startsWith("custom_")).map(k => ({
      section: sectionLabel, label: data[k]?.label || "Custom", node: data[k],
    }));
  }

  const allItems = [
    { section: "Facility", label: lbl.ceiling, node: inspection?.facility?.ceiling },
    { section: "Facility", label: lbl.walls, node: inspection?.facility?.walls },
    { section: "Facility", label: lbl.floors, node: inspection?.facility?.floors },
    { section: "Facility", label: lbl.lighting, node: inspection?.facility?.lighting },
    ...getCustomItems("facility", "Facility"),
    { section: "Operations", label: lbl.employeePractices, node: inspection?.operations?.employeePractices },
    { section: "Operations", label: lbl.handwashing, node: inspection?.operations?.handwashing },
    { section: "Operations", label: lbl.labelingDating, node: inspection?.operations?.labelingDating },
    { section: "Operations", label: lbl.logs, node: inspection?.operations?.logs },
    ...getCustomItems("operations", "Operations"),
    { section: "Equipment", label: lbl.coolers, node: inspection?.equipment?.coolers },
    { section: "Equipment", label: lbl.freezer, node: inspection?.equipment?.freezer },
    { section: "Equipment", label: lbl.warmers, node: inspection?.equipment?.warmers },
    { section: "Equipment", label: lbl.grill, node: inspection?.equipment?.grill },
    { section: "Equipment", label: lbl.fryer, node: inspection?.equipment?.fryer },
    { section: "Equipment", label: lbl.hood, node: inspection?.equipment?.hood },
    { section: "Equipment", label: lbl.iceMaker, node: inspection?.equipment?.iceMaker },
    { section: "Equipment", label: lbl.otherEquip, node: inspection?.equipment?.otherEquip },
    ...getCustomItems("equipment", "Equipment"),
  ];

  const findings = allItems.filter(it => it.node?.status && it.node.status !== "OK" && it.node.status !== "N/A");
  if (!Number.isNaN(handT) && inspection?.temps?.handSinkTempF !== "" && handT < 95) findings.push({ section: "Temperature", label: "Hand Sink", node: { status: "Follow-up", notes: `${handT}\u00B0F (below 95\u00B0F minimum) — logged as follow-up` } });
  if (!Number.isNaN(threeT) && inspection?.temps?.threeCompSinkTempF !== "" && threeT < 110) findings.push({ section: "Temperature", label: "3-Comp Wash", node: { status: "Follow-up", notes: `${threeT}\u00B0F (below 110\u00B0F minimum) — logged as follow-up` } });
  for (const et of equipTemps) {
    if (!et.pass) findings.push({ section: "Temperature", label: et.label, node: { status: "Follow-up", notes: `${et.tempNum}\u00B0F (above ${et.max}\u00B0F maximum) — logged as follow-up` } });
  }

  const sections = ["Facility", "Operations", "Equipment"];

  return (
    <div className="rpt">
      {/* Report Header Bar */}
      <div className="rptHeader">
        <img src={LOGO_DARK} alt="Sodexo" className="rptLogo" />
        <div className="rptHeaderRight">
          <div className="rptDocType">{inspectionType || lbl.inspectionScorecard}</div>
          <div className="rptDocId">Report #{reportId}</div>
        </div>
      </div>

      {/* Title + Status */}
      <div className="rptTitleBar">
        <div>
          <div className="rptTitle">{location || "Inspection Report"}</div>
          <div className="rptDate">{date}</div>
        </div>
        <div className={cx("rptStatus", status === "Pass" ? "rptStatusPass" : "rptStatusFail")}>
          {status === "Pass" ? lbl.passed : lbl.needsAttention}
        </div>
      </div>

      {/* Info Grid */}
      <div className="rptInfoGrid">
        <div className="rptInfoItem">
          <div className="rptInfoLabel">{lbl.inspector}</div>
          <div className="rptInfoValue">{inspectorName || "\u2014"}</div>
        </div>
        {participantName && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.participant}</div>
            <div className="rptInfoValue">{participantName}</div>
          </div>
        )}
        <div className="rptInfoItem">
          <div className="rptInfoLabel">{lbl.supervisor}</div>
          <div className="rptInfoValue">{supervisorName || "\u2014"}</div>
        </div>
        <div className="rptInfoItem">
          <div className="rptInfoLabel">{lbl.unitLocation}</div>
          <div className="rptInfoValue">{siteNumber || "\u2014"}</div>
        </div>
        {restaurantLicense && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.licenseNum}</div>
            <div className="rptInfoValue">{restaurantLicense}</div>
          </div>
        )}
        {locationType && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.type}</div>
            <div className="rptInfoValue">{locationType}</div>
          </div>
        )}
        {floor && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.floor}</div>
            <div className="rptInfoValue">{floor}</div>
          </div>
        )}
        {sitePhone && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.phone}</div>
            <div className="rptInfoValue">{sitePhone}</div>
          </div>
        )}
        {eventName && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.event}</div>
            <div className="rptInfoValue">{eventName}</div>
          </div>
        )}
        <div className="rptInfoItem">
          <div className="rptInfoLabel">{lbl.handSinkTemp}</div>
          <div className="rptInfoValue">
            {inspection?.temps?.handSinkTempF ? `${inspection.temps.handSinkTempF}\u00B0F` : "\u2014"}
            {handT >= 95 && <span className="rptCheck">{" \u2705"}</span>}
            {handT > 0 && handT < 95 && <span className="rptWarn">{` \u26A0\uFE0F ${lbl.below95}`}</span>}
          </div>
        </div>
        <div className="rptInfoItem">
          <div className="rptInfoLabel">{lbl.threeCompTemp}</div>
          <div className="rptInfoValue">
            {inspection?.temps?.threeCompSinkTempF ? `${inspection.temps.threeCompSinkTempF}\u00B0F` : "\u2014"}
            {threeT >= 110 && <span className="rptCheck">{" \u2705"}</span>}
            {threeT > 0 && threeT < 110 && <span className="rptWarn">{` \u26A0\uFE0F ${lbl.below110}`}</span>}
          </div>
        </div>
        {inspection?.temps?.iceMakerCleanedDate && (
          <div className="rptInfoItem">
            <div className="rptInfoLabel">{lbl.iceMakerCleaned}</div>
            <div className="rptInfoValue">{inspection.temps.iceMakerCleanedDate}</div>
          </div>
        )}
        {equipTemps.map(et => (
          <div className="rptInfoItem" key={et.key}>
            <div className="rptInfoLabel">{et.label}</div>
            <div className="rptInfoValue">
              {et.tempF}{"\u00B0F"}
              {et.pass && <span className="rptCheck">{" \u2705"}</span>}
              {!et.pass && <span className="rptWarn">{` \u26A0\uFE0F ${lbl.above} ${et.max}\u00B0F ${lbl.maximum}`}</span>}
            </div>
          </div>
        ))}
      </div>

      {/* Opening message for Email/Doc */}
      {(useCase === "Email Summary" || useCase === "Google Doc") && playbook.opening && (
        <div className="rptBlock">
          <p className="rptParagraph">{playbook.opening}</p>
        </div>
      )}

      {/* Full Scorecard Table */}
      <div className="rptBlock">
        <div className="rptBlockTitle">{lbl.inspectionScorecard}</div>
        <div className="rptTableWrap">
          <table className="rptTable">
            <thead>
              <tr>
                <th>{lbl.section}</th>
                <th>{lbl.item}</th>
                <th>{lbl.status}</th>
                <th>{lbl.notes2}</th>
              </tr>
            </thead>
            <tbody>
              {sections.map(sec => {
                const secLabel = sec === "Facility" ? lbl.facility : sec === "Operations" ? lbl.operations : sec === "Equipment" ? lbl.equipment : sec;
                const items = allItems.filter(it => it.section === sec);
                return items.map((it, i) => (
                  <tr key={it.label} className={it.node?.status === "Not Clean" ? "rptRowFail" : it.node?.status === "Needs Attention" ? "rptRowWarn" : ""}>
                    {i === 0 && <td rowSpan={items.length} className="rptSectionCell">{secLabel}</td>}
                    <td>{it.label}</td>
                    <td>
                      <span className={cx("rptStatusPill",
                        it.node?.status === "OK" ? "rptPillPass" :
                        it.node?.status === "Not Clean" ? "rptPillFail" :
                        it.node?.status === "Needs Attention" ? "rptPillWarn" : "rptPillNa"
                      )}>
                        {it.node?.status === "OK" ? lbl.statusOk :
                         it.node?.status === "Not Clean" ? lbl.statusNotClean :
                         it.node?.status === "Needs Attention" ? lbl.statusNeedsAttention :
                         it.node?.status ? it.node.status : lbl.statusNa}
                      </span>
                    </td>
                    <td className="rptNoteCell">
                      {it.node?.notes && <div>{it.node.notes}</div>}
                      {Array.isArray(it.node?.checklist) && it.node.checklist.length > 0 && (
                        <div style={{ marginTop: it.node?.notes ? "0.25rem" : 0, fontSize: "0.78rem", lineHeight: 1.5 }}>
                          {it.node.checklist.filter(c => c.value === "NO").map((c, ci) => (
                            <div key={ci} style={{ color: "#dc2626" }}>❌ {c.label}</div>
                          ))}
                          {it.node.checklist.filter(c => c.value === "YES").map((c, ci) => (
                            <div key={ci} style={{ color: "#15803d" }}>✅ {c.label}</div>
                          ))}
                        </div>
                      )}
                      {!it.node?.notes && (!Array.isArray(it.node?.checklist) || it.node.checklist.length === 0) && "\u2014"}
                    </td>
                  </tr>
                ));
              })}
              {/* Temperature rows */}
              <tr className={handT > 0 && handT < 95 ? "rptRowWarn" : ""}>
                <td rowSpan={2} className="rptSectionCell">{lbl.temps}</td>
                <td>{lbl.handSinkTemp}</td>
                <td><span className={cx("rptStatusPill", handT >= 95 ? "rptPillPass" : handT ? "rptPillFollowup" : "rptPillNa")}>{inspection?.temps?.handSinkTempF ? `${inspection.temps.handSinkTempF}\u00B0F` : lbl.statusNa}</span></td>
                <td className="rptNoteCell">{handT >= 95 ? lbl.meetsMin : handT ? `${lbl.below95} — follow-up` : "\u2014"}</td>
              </tr>
              <tr className={threeT > 0 && threeT < 110 ? "rptRowWarn" : ""}>
                <td>{lbl.threeCompTemp}</td>
                <td><span className={cx("rptStatusPill", threeT >= 110 ? "rptPillPass" : threeT ? "rptPillFollowup" : "rptPillNa")}>{inspection?.temps?.threeCompSinkTempF ? `${inspection.temps.threeCompSinkTempF}\u00B0F` : lbl.statusNa}</span></td>
                <td className="rptNoteCell">{threeT >= 110 ? lbl.meetsMin : threeT ? `${lbl.below110} — follow-up` : "\u2014"}</td>
              </tr>
              {/* HACCP Food Temperatures — inline from current session */}
              {foodTemps && HACCP_TEMP_ITEMS.flatMap((item) => {
                const vals = (foodTemps[item.key] || []).filter(v => v !== "" && v != null);
                const names = foodTempNames?.[item.key] || [];
                return vals.map((v, idx) => {
                  const pass = tempPass(item, v);
                  const foodName = names[idx] || item.label;
                  const rangeNote = item.type === "hot" ? `Min ${item.min}°F` : `Max ${item.max}°F`;
                  return (
                    <tr key={`${item.key}-${idx}`} className={pass === false ? "rptRowWarn" : ""}>
                      {idx === 0 && vals.length === 1 && <td className="rptSectionCell">HACCP</td>}
                      {idx === 0 && vals.length > 1 && <td rowSpan={vals.length} className="rptSectionCell">HACCP</td>}
                      {idx > 0 && null}
                      <td style={{ fontSize: "0.82rem" }}>{foodName} <span style={{ color: "#94a3b8", fontSize: "0.75rem" }}>({item.label})</span></td>
                      <td><span className={cx("rptStatusPill", pass === true ? "rptPillPass" : pass === false ? "rptPillFollowup" : "rptPillNa")}>{v}°F</span></td>
                      <td className="rptNoteCell">{pass === true ? "✓ Safe" : pass === false ? `📋 Follow-up (${rangeNote})` : rangeNote}</td>
                    </tr>
                  );
                });
              })}
            </tbody>
          </table>
        </div>
      </div>

      {/* Findings Summary (only if issues) */}
      {findings.length > 0 && (
        <div className="rptBlock rptBlockAlert">
          <div className="rptBlockTitle rptBlockTitleAlert">{lbl.issuesFound} ({findings.length})</div>
          {findings.map((f, i) => (
            <div className="rptIssueRow" key={i}>
              <span className="rptIssueNum">{i + 1}</span>
              <div className="rptIssueContent">
                <div className="rptIssueName">{f.label} <span className="rptIssueSection">({f.section})</span></div>
                {f.node?.notes && <div className="rptIssueDetail">{f.node.notes}</div>}
                {Array.isArray(f.node?.checklist) && f.node.checklist.some(c => c.value === "NO") && (
                  <div style={{ marginTop: "0.2rem", fontSize: "0.78rem", lineHeight: 1.5 }}>
                    {f.node.checklist.filter(c => c.value === "NO").map((c, ci) => (
                      <div key={ci} style={{ color: "#dc2626" }}>❌ {c.label}</div>
                    ))}
                  </div>
                )}
              </div>
              <span className={cx("rptStatusPill", f.node?.status === "Not Clean" ? "rptPillFail" : f.node?.status === "Follow-up" ? "rptPillFollowup" : "rptPillWarn")}>{f.node?.status}</span>
            </div>
          ))}
        </div>
      )}

      {/* Action Items */}
      {actionItems.length > 0 && (
        <div className="rptBlock">
          <div className="rptBlockTitle">{lbl.correctiveActions}</div>
          {actionItems.map((a, i) => (
            <div className="rptActionRow" key={i}>
              <span className={cx("rptPriorityDot",
                a.priority === "Critical" ? "rptDotCritical" :
                a.priority === "High" ? "rptDotHigh" :
                a.priority === "Follow-up" ? "rptDotFollowup" :
                a.priority === "Maintenance" ? "rptDotMaintenance" :
                "rptDotMed"
              )} />
              <div className="rptActionContent">
                <span className="rptActionText">{a.issue}</span>
                <span className={cx("rptPriorityLabel",
                  a.priority === "Critical" ? "rptLabelCritical" :
                  a.priority === "High" ? "rptLabelHigh" :
                  a.priority === "Follow-up" ? "rptLabelFollowup" :
                  a.priority === "Maintenance" ? "rptLabelMaintenance" :
                  "rptLabelMed"
                )}>
                  {a.priority === "Critical" ? "⚠ Critical" :
                   a.priority === "High" ? `${lbl.high} ${lbl.priority}` :
                   a.priority === "Follow-up" ? "Follow-up" :
                   a.priority === "Maintenance" ? "Maintenance" :
                   `${lbl.medium} ${lbl.priority}`}
                </span>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Photo Evidence */}
      {photoIndexList.length > 0 && (
        <div className="rptBlock">
          <div className="rptBlockTitle">{lbl.photoEvidence} ({photoIndexList.length})</div>
          <div className="rptPhotoGallery">
            {photoIndexList.map(p => (
              <div className="rptPhotoCard" key={p.num}>
                {p.previewUrl ? (
                  <img src={p.previewUrl} alt={`Photo #${p.num}`} className="rptPhotoImg" style={{cursor:"zoom-in"}} onClick={() => setLightboxSrc(p.previewUrl)} />
                ) : (
                  <div className="rptPhotoPlaceholder">{lbl.noPreview}</div>
                )}
                <div className="rptPhotoCaption">
                  <span className="rptPhotoNum">#{p.num}</span>
                  <span>{p.label}{p.caption ? ` \u2014 ${p.caption}` : ""}</span>
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Notes – organized by category with bullet points */}
      {rawNotes && (() => {
        const { grouped } = formatNotesStructured(rawNotes);
        const hasBullets = Object.values(grouped).some(arr => arr.length > 0);
        if (!hasBullets) return null;
        return (
          <div className="rptBlock">
            <div className="rptBlockTitle">{lbl.notes}</div>
            <div className="rptNotesOrganized">
              {CATEGORY_ORDER.map(cat => {
                if (!grouped[cat] || !grouped[cat].length) return null;
                return (
                  <div className="rptNoteCategory" key={cat}>
                    <div className={cx("rptNoteCatLabel", `rptNoteCat--${cat}`)}>{CATEGORY_LABELS[cat]}</div>
                    <ul className="rptNoteBullets">
                      {grouped[cat].map((b, i) => <li key={i}>{b}</li>)}
                    </ul>
                  </div>
                );
              })}
            </div>
          </div>
        );
      })()}

      {/* Footer */}
      <div className="rptFooter">
        <div>{lbl.generated} {new Date().toLocaleDateString()} {new Date().toLocaleTimeString()} &middot; Sodexo Kitchen Inspection System</div>
        <div>{lbl.confidential}</div>
      </div>

      {/* Photo Lightbox */}
      {lightboxSrc && (
        <div onClick={() => setLightboxSrc(null)} style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.9)",zIndex:9999,display:"flex",alignItems:"center",justifyContent:"center",cursor:"zoom-out"}}>
          <img src={lightboxSrc} alt="Full size photo" style={{maxWidth:"95vw",maxHeight:"95vh",objectFit:"contain",borderRadius:8,boxShadow:"0 4px 32px rgba(0,0,0,0.5)"}} />
          <button onClick={() => setLightboxSrc(null)} style={{position:"absolute",top:16,right:16,background:"rgba(255,255,255,0.15)",border:"none",color:"#fff",fontSize:28,width:44,height:44,borderRadius:"50%",cursor:"pointer",lineHeight:1}}>×</button>
        </div>
      )}
    </div>
  );
}

/* ── CSV export from inspection data ─────────────────────── */
function buildCsvRows({ inspection, rawNotes, inspectionType, inspectionDate, inspectorName, siteName, siteNumber, supervisorName }) {
  const rows = [["Section", "Item", "Status", "Checklist Details", "Notes", "Priority", "Item Photo URLs"]];

  // Add a subsection row — expands checklist items as a comma-separated detail string
  const add = (section, label, node) => {
    if (!node) return;
    const st = node.status || "";
    const priority = st === "Fail" || st === "Not Clean" ? "High" : st === "Needs Attention" ? "Med" : st === "Maintenance" ? "Maintenance" : "";
    // Build checklist detail: issues first (❌), then passed (✅), one per line
    let checkDetail = "";
    let photoUrls = "";
    if (Array.isArray(node.checklist) && node.checklist.length > 0) {
      const lines = [];
      const allPhotos = [];
      node.checklist.filter(c => c.value === "NO").forEach(c => {
        const note = c.comment?.trim() ? ` — ${c.comment.trim()}` : "";
        lines.push(`❌ ${c.label}${note}`);
        (c.photos || []).forEach(p => { if (p.url || p.dataUrl) allPhotos.push(p.url || p.dataUrl); });
      });
      node.checklist.filter(c => c.value === "YES").forEach(c => {
        const note = c.comment?.trim() ? ` — ${c.comment.trim()}` : "";
        lines.push(`✅ ${c.label}${note}`);
        (c.photos || []).forEach(p => { if (p.url || p.dataUrl) allPhotos.push(p.url || p.dataUrl); });
      });
      checkDetail = lines.join("\n");
      photoUrls = allPhotos.join("\n");
    }
    rows.push([section, label, st, checkDetail, (node.notes || "").replace(/"/g, '""'), priority, photoUrls]);
  };

  // ── FACILITIES ─────────────────────────────────────────────────────────
  add("Facilities", "Ceiling",               inspection?.facility?.ceiling);
  add("Facilities", "Walls",                 inspection?.facility?.walls);
  add("Facilities", "Floors",                inspection?.facility?.floors);
  add("Facilities", "3-Compartment Sinks",   inspection?.facility?.threeCompSinks);
  add("Facilities", "Hand Sink",             inspection?.facility?.handSink);
  add("Facilities", "Mop Area",              inspection?.facility?.mopArea);
  // legacy
  add("Facilities", "Lighting",              inspection?.facility?.lighting);

  // ── EQUIPMENTS ─────────────────────────────────────────────────────────
  add("Equipments", "Coolers",              inspection?.equipment?.coolers);
  add("Equipments", "Freezer",              inspection?.equipment?.freezer);
  add("Equipments", "Warmers",              inspection?.equipment?.warmers);
  add("Equipments", "Grill",               inspection?.equipment?.grill);
  add("Equipments", "Fryer",               inspection?.equipment?.fryer);
  add("Equipments", "Hood",                inspection?.equipment?.hood);
  add("Equipments", "Ice Maker Machine",   inspection?.equipment?.iceMaker);
  add("Equipments", "Other Equipments",    inspection?.equipment?.otherEquip);
  // legacy equipment
  add("Equipments", "Double-door cooler",  inspection?.equipment?.doubleDoorCooler);
  add("Equipments", "Double-door freezer", inspection?.equipment?.doubleDoorFreezer);
  add("Equipments", "Walk-in cooler",      inspection?.equipment?.walkInCooler);
  add("Equipments", "Walk-in freezer",     inspection?.equipment?.walkInFreezer);
  add("Equipments", "Prep cooler",         inspection?.equipment?.prepCooler);
  add("Equipments", "Ovens",               inspection?.equipment?.ovens);
  add("Equipments", "3-compartment sink",  inspection?.equipment?.threeCompSink);
  add("Equipments", "Ecolab / chemicals",  inspection?.equipment?.ecolab);

  // ── UTENSILS ───────────────────────────────────────────────────────────
  add("Utensils", "Cleaning Utensils", inspection?.utensils?.cleaningUtensils);
  add("Utensils", "Cooking Utensils",  inspection?.utensils?.cookingUtensils);

  // ── OPERATIONS (legacy) ────────────────────────────────────────────────
  add("Operations", "Employee practices",     inspection?.operations?.employeePractices);
  add("Operations", "Handwashing / supplies", inspection?.operations?.handwashing);
  add("Operations", "Labeling / dating",      inspection?.operations?.labelingDating);
  add("Operations", "Logs / documentation",   inspection?.operations?.logs);

  // ── TEMPS ──────────────────────────────────────────────────────────────
  const handT = Number(inspection?.temps?.handSinkTempF);
  const threeT = Number(inspection?.temps?.threeCompSinkTempF);
  if (inspection?.temps?.handSinkOutOfOrder) {
    rows.push(["Temps", "Hand Sink", "Out of Order", "", inspection?.temps?.handSinkNote || "", "Critical"]);
  } else if (inspection?.temps?.handSinkTempF) {
    rows.push(["Temps", "Hand Sink (°F)", inspection.temps.handSinkTempF, "", handT >= 95 ? "Meets min 95°F" : `Below min — ${handT}°F`, handT >= 95 ? "" : "High"]);
  }
  if (inspection?.temps?.threeCompSinkOutOfOrder) {
    rows.push(["Temps", "3-Comp Sink", "Out of Order", "", inspection?.temps?.threeCompSinkNote || "", "Critical"]);
  } else if (inspection?.temps?.threeCompSinkTempF) {
    rows.push(["Temps", "3-Comp Wash (°F)", inspection.temps.threeCompSinkTempF, "", threeT >= 110 ? "Meets min 110°F" : `Below min — ${threeT}°F`, threeT >= 110 ? "" : "High"]);
  }
  for (const et of collectEquipTemps(inspection)) {
    rows.push(["Temps", `${et.label} (°F)`, et.tempF, "", et.pass ? `OK ≤${et.max}°F` : et.zone === "warn" ? `Elevated — monitor` : `Above max ${et.max}°F`, et.pass ? "" : et.zone === "warn" ? "Med" : "High"]);
  }

  return rows;
}

/**
 * Convert a Blob to a base64 data-URL.
 */
function blobToDataUrl(blob) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = () => resolve(reader.result);
    reader.onerror = () => reject(reader.error);
    reader.readAsDataURL(blob);
  });
}

/**
 * Fetch an image URL and return a base64 data-URL so Office apps can embed it
 * without needing network access.
 *
 * Strategy (in order):
 * 1. If already a data-URL → return as-is.
 * 2. If it's a Firebase Storage URL AND the Storage SDK is available →
 *    use getBlob() via the SDK (no CORS, authenticated, full-resolution).
 * 3. Otherwise → plain fetch with mode:"cors" (works for public CDN URLs).
 * 4. On any failure → fall back to the compressed thumb data-URL.
 */
async function fetchAsDataUrl(src, fallback) {
  const useFallback = () => (fallback && fallback.startsWith("data:") ? fallback : null);

  if (!src) return useFallback();
  if (src.startsWith("data:")) return src; // already base64 — use directly

  // Detect Firebase Storage URLs (both legacy googleapis.com and new firebasestorage.app)
  const isFirebaseUrl = src.includes("firebasestorage.googleapis.com") ||
                        src.includes("firebasestorage.app");

  // ── Path 1: Firebase SDK getBlob — bypasses CORS entirely ─────────────────
  if (isFirebaseUrl && fbStorage) {
    try {
      const fileRef = storageRef(fbStorage, src);
      const blob = await storageGetBlob(fileRef);
      return await blobToDataUrl(blob);
    } catch (sdkErr) {
      // SDK download failed (permissions, deleted file, etc.) — try plain fetch next
      console.warn("fetchAsDataUrl SDK fallback:", sdkErr?.code || sdkErr?.message);
    }
  }

  // ── Path 2: Plain fetch (works for public CDN / non-Firebase URLs) ─────────
  try {
    const res = await fetch(src, { mode: "cors" });
    if (!res.ok) return useFallback();
    const blob = await res.blob();
    return await blobToDataUrl(blob);
  } catch {
    return useFallback();
  }
}

async function exportAsCsv({ inspection, notesPhotos, rawNotes, inspectionType, inspectionDate, inspectorName, participantName, siteName, siteNumber, sitePhone, supervisorName, floor, locationType, restaurantLicense, licenseMissing, eventName, foodTemps, foodTempNames, haccpSubs }) {
  const ExcelJS = (await import("exceljs")).default;
  const dataRows = buildCsvRows({ inspection, rawNotes, inspectionType, inspectionDate, inspectorName, siteName, siteNumber, supervisorName });
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const actionItems = buildActionItems({ inspection, rawNotes, foodTemps, foodTempNames });
  const { index: photoListRaw } = buildPhotoIndex(inspection, notesPhotos || inspection?._notesPhotos);
  const execSummary = buildExportSummary({ inspection, rawNotes, inspectionType, inspectionDate, siteName, foodTemps, foodTempNames });

  const photoList = await Promise.all(
    photoListRaw.map(async p => ({ ...p, dataUrl: await fetchAsDataUrl(p.previewUrl, p.thumbUrl) }))
  );

  const str = v => (v == null ? "" : String(v));

  // ── Sodexo Brand colours ─────────────────────────────────────────────────
  const NAVY    = "1C2B5E"; // Sodexo deep blue — primary brand color
  const RED     = "A8192E"; // Sodexo red — muted crimson accent, section dividers
  const BLUE_LT = "E8EDF7"; // light tint of navy — Executive Summary / Notes rows
  const RED_LT  = "FAEAEC"; // light tint of red — metadata block background
  const SILVER  = "F4F5F7"; // alternating row fill (light gray)
  const PASS_G  = "C6EFCE"; // status = Pass / OK background (Excel-standard green)
  const PASS_GT = "276221"; // Pass text (dark green)
  const FAIL_R  = "FFC7CE"; // status = Not Clean / FLAG background (Excel-standard red)
  const FAIL_RT = "9C0006"; // Fail text (dark red)
  const ATTN_Y  = "FFEB9C"; // status = Needs Attention background (Excel-standard yellow)
  const ATTN_YT = "9C6500"; // Attention text (dark amber)
  const WHITE   = "FFFFFF";

  const hdr = (bold = true, sz = 12, color = WHITE, bgColor = NAVY) => ({
    font: { bold, size: sz, color: { argb: "FF" + color }, name: "Calibri" },
    fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + bgColor } },
    alignment: { vertical: "middle", wrapText: true },
  });
  const subHdr = (bgColor = RED) => ({
    font: { bold: true, size: 10, color: { argb: "FF" + WHITE }, name: "Calibri" },
    fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + bgColor } },
    alignment: { vertical: "middle" },
  });
  const metaLabel = () => ({
    font: { bold: true, size: 10, color: { argb: "FF" + NAVY }, name: "Calibri" },
    fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + RED_LT } },
    alignment: { vertical: "middle" },
    border: { bottom: { style: "thin", color: { argb: "FFFDE8EC" } } },
  });
  const metaVal = () => ({
    font: { size: 10, name: "Calibri" },
    fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + RED_LT } },
    alignment: { vertical: "middle", wrapText: true },
    border: { bottom: { style: "thin", color: { argb: "FFFDE8EC" } } },
  });
  const bodyCell = (bg = WHITE) => ({
    font: { size: 10, name: "Calibri", color: { argb: "FF333333" } },
    fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + bg } },
    alignment: { vertical: "top", wrapText: true },
    border: { bottom: { style: "hair", color: { argb: "FFD1D5DB" } } },
  });
  const statusCell = (s) => {
    const isPass   = s === "OK" || s === "Pass";
    const isFail   = s === "Not Clean" || s === "FLAG";
    const isAttn   = s === "Needs Attention";
    const bg   = isPass ? PASS_G : isFail ? FAIL_R : isAttn ? ATTN_Y : WHITE;
    const text = isPass ? PASS_GT : isFail ? FAIL_RT : isAttn ? ATTN_YT : "333333";
    return {
      font: { bold: true, size: 10, name: "Calibri", color: { argb: "FF" + text } },
      fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + bg } },
      alignment: { vertical: "top", horizontal: "center", wrapText: true },
    };
  };
  const applyStyle = (cell, style) => Object.assign(cell, style);

  const wb = new ExcelJS.Workbook();
  wb.creator = "Sodexo Kitchen Inspection";

  // ══════════════════════════════════════════════════════════════════════════
  // SHEET 1: Report
  // ══════════════════════════════════════════════════════════════════════════
  const ws1 = wb.addWorksheet("Report");
  ws1.columns = [
    { width: 20 }, { width: 32 }, { width: 18 }, { width: 42 }, { width: 42 }, { width: 13 },
  ];

  // Title row
  const titleRow = ws1.addRow(["SODEXO KITCHEN INSPECTION REPORT"]);
  titleRow.height = 28;
  const titleCell = titleRow.getCell(1);
  applyStyle(titleCell, hdr(true, 14, WHITE, NAVY));
  ws1.mergeCells(`A${titleRow.number}:F${titleRow.number}`);

  ws1.addRow([]); // spacer

  // Metadata block
  const metaFields = [
    ["Inspection Type", str(inspectionType)],
    ...(eventName ? [["Event", str(eventName)]] : []),
    ["Date", str(inspectionDate)],
    ["Inspector", str(inspectorName)],
    ...(participantName ? [["Participant", str(participantName)]] : []),
    ["Site / Location", str(siteName)],
    ["Unit #", str(siteNumber)],
    ["Floor", str(floor)],
    ...(locationType ? [["Location Type", str(locationType)]] : []),
    ...(restaurantLicense && restaurantLicense !== "NO LICENSE"
      ? [["License #", str(restaurantLicense)], ["License Missing", licenseMissing ? "Yes" : "No"]]
      : []),
    ["Supervisor", str(supervisorName)],
    ...(sitePhone ? [["Site Phone", str(sitePhone)]] : []),
  ];
  for (const [label, val] of metaFields) {
    const r = ws1.addRow([label, val]);
    r.height = 18;
    applyStyle(r.getCell(1), metaLabel());
    applyStyle(r.getCell(2), metaVal());
  }

  // Overall Status — coloured badge
  const statusRow = ws1.addRow(["Overall Status", status]);
  statusRow.height = 20;
  applyStyle(statusRow.getCell(1), metaLabel());
  applyStyle(statusRow.getCell(2), statusCell(status));

  // Compliance Score
  const scoreData = calcInspectionScore(inspection);
  if (scoreData) {
    const scoreRow = ws1.addRow(["Compliance Score", `${scoreData.pct}% — Grade ${scoreData.grade} (${scoreData.passed}/${scoreData.scoredTotal} items)`]);
    scoreRow.height = 18;
    applyStyle(scoreRow.getCell(1), metaLabel());
    applyStyle(scoreRow.getCell(2), metaVal());
  }

  ws1.addRow([]);

  // ── Executive Summary ──────────────────────────────────────────────────
  const esTitleRow = ws1.addRow(["Executive Summary"]);
  esTitleRow.height = 22;
  ws1.mergeCells(`A${esTitleRow.number}:F${esTitleRow.number}`);
  applyStyle(esTitleRow.getCell(1), subHdr(NAVY));

  const execLines = execSummary.split(/\n+/).filter(l => l.trim());
  for (const line of execLines) {
    const r = ws1.addRow([line.trim()]);
    r.height = 15;
    ws1.mergeCells(`A${r.number}:F${r.number}`);
    applyStyle(r.getCell(1), { font: { size: 10, name: "Calibri", color: { argb: "FF333333" } }, alignment: { wrapText: true, vertical: "top" }, fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + BLUE_LT } } });
  }

  ws1.addRow([]);

  // ── Inspector Notes ────────────────────────────────────────────────────
  const inTitleRow = ws1.addRow(["Inspector Notes"]);
  inTitleRow.height = 22;
  ws1.mergeCells(`A${inTitleRow.number}:F${inTitleRow.number}`);
  applyStyle(inTitleRow.getCell(1), subHdr(NAVY));

  const noteLines = formatNotesText(rawNotes).split(/\n/);
  for (const line of noteLines) {
    if (!line.trim()) { ws1.addRow([]); continue; }
    const isCatHeader = line.trim().endsWith(":");
    const r = ws1.addRow([line]);
    r.height = isCatHeader ? 18 : 15;
    ws1.mergeCells(`A${r.number}:F${r.number}`);
    if (isCatHeader) {
      applyStyle(r.getCell(1), { font: { bold: true, size: 10, color: { argb: "FF" + WHITE }, name: "Calibri" }, fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + RED } }, alignment: { wrapText: true, vertical: "middle" } });
    } else {
      applyStyle(r.getCell(1), { font: { size: 10, name: "Calibri", color: { argb: "FF333333" } }, fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + BLUE_LT } }, alignment: { wrapText: true, vertical: "top" } });
    }
  }

  ws1.addRow([]);

  // ── Inspection Scorecard ────────────────────────────────────────────────
  const scHdrTitleRow = ws1.addRow(["INSPECTION SCORECARD"]);
  scHdrTitleRow.height = 20;
  ws1.mergeCells(`A${scHdrTitleRow.number}:F${scHdrTitleRow.number}`);
  applyStyle(scHdrTitleRow.getCell(1), hdr(true, 11, WHITE, NAVY));

  const scorecardHeader = ["Section", "Item", "Status", "Checklist Details", "Notes", "Priority"];
  const scHeaderRow = ws1.addRow(scorecardHeader);
  scHeaderRow.height = 20;
  scorecardHeader.forEach((_, ci) => applyStyle(scHeaderRow.getCell(ci + 1), subHdr(RED)));

  ws1.autoFilter = { from: { row: scHeaderRow.number, column: 1 }, to: { row: scHeaderRow.number, column: 6 } };
  ws1.views = [{ state: "normal", activeCell: "A1" }];

  const scorecardRows = dataRows.slice(1);
  scorecardRows.forEach((r, ri) => {
    const bg = ri % 2 === 0 ? WHITE : SILVER;
    const clText = str(r[3] || "");
    const rowData = [str(r[0]), str(r[1]), str(r[2]), clText, str(r[4] || ""), str(r[5] || "")];
    const row = ws1.addRow(rowData);
    // Auto-height: 18pt baseline + 14pt per extra checklist line
    const lineCount = clText ? clText.split("\n").length : 0;
    row.height = lineCount > 1 ? 18 + (lineCount - 1) * 14 : 18;
    row.getCell(1).style = bodyCell(bg);
    row.getCell(2).style = bodyCell(bg);
    row.getCell(3).style = statusCell(str(r[2]));
    row.getCell(4).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
    row.getCell(5).style = bodyCell(bg);
    row.getCell(6).style = { ...bodyCell(bg), alignment: { horizontal: "center", vertical: "top" } };
  });

  // ── HACCP Temps ──────────────────────────────────────────────────────────
  const ftItems = HACCP_TEMP_ITEMS.filter(item => ((foodTemps || {})[item.key] || []).some(v => v !== ""));
  if (ftItems.length) {
    ws1.addRow([]);
    const haccpTitleRow = ws1.addRow(["HACCP FOOD TEMPERATURES"]);
    haccpTitleRow.height = 20;
    ws1.mergeCells(`A${haccpTitleRow.number}:F${haccpTitleRow.number}`);
    applyStyle(haccpTitleRow.getCell(1), hdr(true, 11, WHITE, NAVY));

    const haccpHeader = ["Item", "Food Name", "Temperature (°F)", "Result", "", ""];
    const hHdrRow = ws1.addRow(haccpHeader);
    hHdrRow.height = 18;
    [1, 2, 3, 4].forEach(ci => applyStyle(hHdrRow.getCell(ci), subHdr(RED)));

    for (const item of ftItems) {
      const vals = ((foodTemps || {})[item.key] || []).filter(v => v !== "");
      const names = (foodTempNames || {})[item.key] || [];
      vals.forEach((v, vi) => {
        const pass = tempPass(item, v);
        const result = pass === true ? "OK" : pass === false ? "FLAG" : "";
        const row = ws1.addRow([str(item.label), str(names[vi] || ""), str(v), result, "", ""]);
        row.height = 16;
        row.getCell(1).style = bodyCell();
        row.getCell(2).style = bodyCell();
        row.getCell(3).style = { ...bodyCell(), alignment: { horizontal: "center" } };
        row.getCell(4).style = statusCell(result);
      });
    }
  }

  // ══════════════════════════════════════════════════════════════════════════
  // SHEET 2: Action Items
  // ══════════════════════════════════════════════════════════════════════════
  if (actionItems.length > 0) {
    const ws2 = wb.addWorksheet("Action Items");
    ws2.columns = [{ width: 5 }, { width: 22 }, { width: 50 }, { width: 38 }, { width: 14 }];

    const ws2TitleRow = ws2.addRow(["ACTION ITEMS"]);
    ws2TitleRow.height = 24;
    ws2.mergeCells(`A${ws2TitleRow.number}:E${ws2TitleRow.number}`);
    applyStyle(ws2TitleRow.getCell(1), hdr(true, 13, WHITE, NAVY));

    const ws2Header = ["#", "Area / Section", "Issue", "Inspector Notes", "Priority"];
    const ws2HRow = ws2.addRow(ws2Header);
    ws2HRow.height = 20;
    ws2Header.forEach((_, ci) => applyStyle(ws2HRow.getCell(ci + 1), subHdr(RED)));
    ws2.autoFilter = { from: { row: ws2HRow.number, column: 1 }, to: { row: ws2HRow.number, column: 5 } };
    ws2.views = [{ state: "frozen", ySplit: ws2HRow.number, topLeftCell: `A${ws2HRow.number + 1}`, activeCell: "A1" }];

    const priStyle = (p) => {
      const n = (p || "").toLowerCase();
      let bg, text;
      if (n === "high" || n === "fail")                                     { bg = FAIL_R; text = FAIL_RT; }
      else if (n === "med" || n === "medium" || n === "needs attention")    { bg = ATTN_Y; text = ATTN_YT; }
      else if (n === "low")                                                 { bg = "D6E4F7"; text = "1C4A7A"; }
      else if (n === "maintenance")                                         { bg = "FCE4D6"; text = "843C0C"; }
      else if (n === "follow-up" || n === "followup")                       { bg = "E8EAF6"; text = "3949AB"; }
      else                                                                  { bg = PASS_G;  text = PASS_GT; }
      return { font: { bold: true, size: 10, name: "Calibri", color: { argb: "FF" + text } },
               fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + bg } },
               alignment: { vertical: "top", horizontal: "center", wrapText: true } };
    };

    actionItems.forEach((a, i) => {
      const raw = str(a.issue);
      const colonIdx = raw.indexOf(":");
      const area = colonIdx > 0 && colonIdx < 40 ? raw.slice(0, colonIdx).trim() : (str(a.area) || "General");
      const issue = colonIdx > 0 && colonIdx < 40 ? raw.slice(colonIdx + 1).trim() : raw;
      const pri = str(a.priority);
      const notes = str(a.notes || a.corrective || "");
      const bg = i % 2 === 0 ? WHITE : SILVER;
      const row = ws2.addRow([i + 1, area, issue, notes, pri]);
      row.height = 18;
      row.getCell(1).style = { ...bodyCell(bg), alignment: { horizontal: "center", vertical: "top" } };
      row.getCell(2).style = bodyCell(bg);
      row.getCell(3).style = bodyCell(bg);
      row.getCell(4).style = { ...bodyCell(bg), font: { size: 10, name: "Calibri", color: { argb: "FF555555" }, italic: true } };
      row.getCell(5).style = priStyle(pri);
    });
  }

  // ══════════════════════════════════════════════════════════════════════════
  // SHEET 3: Photos (with embedded images)
  // ══════════════════════════════════════════════════════════════════════════
  if (photoList.length > 0) {
    const ws3 = wb.addWorksheet("Photos");
    // col widths: #(5), Section(30), Caption(40), Photo(80)
    ws3.columns = [{ width: 5 }, { width: 30 }, { width: 40 }, { width: 80 }];

    const ws3TitleRow = ws3.addRow(["PHOTO LOG"]);
    ws3TitleRow.height = 24;
    ws3.mergeCells(`A${ws3TitleRow.number}:D${ws3TitleRow.number}`);
    applyStyle(ws3TitleRow.getCell(1), hdr(true, 13, WHITE, NAVY));

    const ws3Header = ["#", "Section", "Caption", "Photo"];
    const ws3HRow = ws3.addRow(ws3Header);
    ws3HRow.height = 20;
    ws3Header.forEach((_, ci) => applyStyle(ws3HRow.getCell(ci + 1), subHdr(RED)));
    ws3.views = [{ state: "frozen", ySplit: ws3HRow.number, topLeftCell: `A${ws3HRow.number + 1}`, activeCell: "A1" }];

    // Image cell height in points. ExcelJS row height is in points; 1pt ≈ 1.333px.
    // We want images ~160px tall → ~120pt row height.
    const IMG_HEIGHT_PT = 120;
    // Image display size in EMU (English Metric Units). 1px = 9525 EMU.
    const IMG_W_PX = 200;
    const IMG_H_PX = 160;

    for (let i = 0; i < photoList.length; i++) {
      const p = photoList[i];
      const bg = i % 2 === 0 ? WHITE : SILVER;

      const row = ws3.addRow([p.num, str(p.label), str(p.caption), ""]);
      row.height = IMG_HEIGHT_PT;

      row.getCell(1).style = { ...bodyCell(bg), alignment: { horizontal: "center", vertical: "top" } };
      row.getCell(2).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
      row.getCell(3).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
      row.getCell(4).style = { fill: { type: "pattern", pattern: "solid", fgColor: { argb: "FF" + bg } } };

      // Embed image — prefer high-quality exportUrl, fall back to previewUrl/thumbUrl
      let dataUrl = p.exportUrl || p.dataUrl || "";
      if (!dataUrl || !dataUrl.startsWith("data:")) {
        // previewUrl may be a Firebase URL — try to fetch it
        const candidate = p.previewUrl || p.thumbUrl || "";
        if (candidate.startsWith("http")) {
          try { const resp = await fetch(candidate); const blob = await resp.blob(); dataUrl = await new Promise(r => { const rd = new FileReader(); rd.onload = () => r(rd.result); rd.readAsDataURL(blob); }); } catch { dataUrl = p.thumbUrl || ""; }
        } else if (candidate.startsWith("data:")) { dataUrl = candidate; }
      }
      if (dataUrl && dataUrl.startsWith("data:image")) {
        try {
          const commaIdx = dataUrl.indexOf(",");
          const base64 = commaIdx >= 0 ? dataUrl.slice(commaIdx + 1) : dataUrl;
          const ext = dataUrl.includes("image/png") ? "png" : "jpeg";
          const imageId = wb.addImage({ base64, extension: ext });
          ws3.addImage(imageId, {
            tl: { col: 3, row: row.number - 1 },
            br: { col: 4, row: row.number },
            editAs: "oneCell",
          });
        } catch (_) {
          row.getCell(4).value = str(p.previewUrl || "");
          row.getCell(4).style = { ...bodyCell(bg), font: { size: 9, color: { argb: "FF1B5EAF" }, name: "Calibri" } };
        }
      }
    }
  }

  // ══════════════════════════════════════════════════════════════════════════
  // SHEET 4: HACCP Supervisor Submissions
  // ══════════════════════════════════════════════════════════════════════════
  if (Array.isArray(haccpSubs) && haccpSubs.length > 0) {
    const ws4 = wb.addWorksheet("HACCP Supervisor Logs");
    // col widths: Submission#(6), Supervisor(24), Time(20), Item(22), Food Name(24), Temp°F(10), Result(12), Problem Report(40)
    ws4.columns = [{ width: 6 }, { width: 24 }, { width: 20 }, { width: 22 }, { width: 24 }, { width: 10 }, { width: 12 }, { width: 40 }];

    const ws4TitleRow = ws4.addRow(["HACCP SUPERVISOR TEMPERATURE LOGS"]);
    ws4TitleRow.height = 24;
    ws4.mergeCells(`A${ws4TitleRow.number}:H${ws4TitleRow.number}`);
    applyStyle(ws4TitleRow.getCell(1), hdr(true, 13, WHITE, NAVY));

    const ws4Headers = ["#", "Supervisor", "Submitted At", "Item", "Food Name", "Temp (°F)", "Result", "Problem Report"];
    const ws4HRow = ws4.addRow(ws4Headers);
    ws4HRow.height = 20;
    ws4Headers.forEach((_, ci) => applyStyle(ws4HRow.getCell(ci + 1), subHdr(RED)));
    ws4.views = [{ state: "frozen", ySplit: ws4HRow.number, topLeftCell: `A${ws4HRow.number + 1}`, activeCell: "A1" }];

    let rowNum = 0;
    haccpSubs.forEach((sub, si) => {
      const allItems = [
        ...HACCP_TEMP_ITEMS,
        ...(sub.customItems || []).filter(ci => !HACCP_TEMP_ITEMS.find(d => d.key === ci.key)),
      ];
      const submittedAt = sub.submittedAt ? new Date(sub.submittedAt).toLocaleString() : "";
      const problemText = sub.problemReport?.text ? `${sub.problemReport.severity === "urgent" ? "🔴" : sub.problemReport.severity === "issue" ? "🟡" : "🔵"} ${sub.problemReport.text}` : "";

      // Collect all readings for this submission
      const readings = [];
      allItems.forEach(item => {
        const temps = (sub.temps?.[item.key] || []).filter(v => v !== "");
        const names = sub.foodNames?.[item.key] || [];
        const label = sub.itemLabels?.[item.key] || item.label;
        temps.forEach((v, ri) => {
          readings.push({ item: label, foodName: names[ri] || "", temp: v, itemDef: item });
        });
      });

      if (readings.length === 0) {
        // Submission with no temp readings — still show the row
        const bg = rowNum % 2 === 0 ? WHITE : SILVER;
        const row = ws4.addRow([si + 1, str(sub.supervisorName), submittedAt, "—", "—", "—", "—", problemText]);
        row.height = 18;
        [1,2,3,4,5,6,7,8].forEach(c => {
          row.getCell(c).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
        });
        rowNum++;
      } else {
        readings.forEach((r, ri) => {
          const bg = rowNum % 2 === 0 ? WHITE : SILVER;
          const pass = tempPass(r.itemDef, parseFloat(r.temp));
          const resultLabel = pass === true ? "✅ Pass" : pass === false ? "🚨 Flag" : "—";
          const row = ws4.addRow([
            ri === 0 ? si + 1 : "",          // submission # only on first reading row
            ri === 0 ? str(sub.supervisorName) : "",
            ri === 0 ? submittedAt : "",
            r.item,
            r.foodName,
            r.temp,
            resultLabel,
            ri === 0 ? problemText : "",      // problem report only on first row
          ]);
          row.height = 18;
          row.getCell(1).style = { ...bodyCell(bg), alignment: { horizontal: "center", vertical: "top" } };
          row.getCell(2).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
          row.getCell(3).style = { ...bodyCell(bg), alignment: { vertical: "top" } };
          row.getCell(4).style = { ...bodyCell(bg), alignment: { vertical: "top" } };
          row.getCell(5).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
          row.getCell(6).style = { ...bodyCell(bg), alignment: { horizontal: "center", vertical: "top" } };
          row.getCell(7).style = statusCell(pass === true ? "OK" : pass === false ? "Not Clean" : "Needs Attention");
          row.getCell(8).style = { ...bodyCell(bg), alignment: { wrapText: true, vertical: "top" } };
          rowNum++;
        });
      }
    });
  }

  // ══════════════════════════════════════════════════════════════════════════
  // SHEET 5: Equipment Temperatures
  // ══════════════════════════════════════════════════════════════════════════
  {
    const handT = Number(inspection?.temps?.handSinkTempF);
    const threeT = Number(inspection?.temps?.threeCompSinkTempF);
    const eTemps = collectEquipTemps(inspection);
    const equipDataRows = [];
    if (!isNaN(handT) && handT > 0) equipDataRows.push(["Hand Sink", handT, "—"]);
    if (!isNaN(threeT) && threeT > 0) equipDataRows.push(["3-Comp Sink", threeT, "—"]);
    eTemps.forEach(e => equipDataRows.push([e.label, e.tempF, e.pass ? "OK" : "Flag"]));
    if (equipDataRows.length > 0) {
      const wsEq = wb.addWorksheet("Equipment Temps");
      wsEq.columns = [{ width: 32 }, { width: 12 }, { width: 10 }];
      const eqTitleRow = wsEq.addRow(["EQUIPMENT TEMPERATURES"]);
      eqTitleRow.height = 24;
      wsEq.mergeCells(`A${eqTitleRow.number}:C${eqTitleRow.number}`);
      applyStyle(eqTitleRow.getCell(1), hdr(true, 13, WHITE, NAVY));
      const eqHRow = wsEq.addRow(["Equipment", "Temp (°F)", "Status"]);
      eqHRow.height = 20;
      ["Equipment", "Temp (°F)", "Status"].forEach((_, ci) => applyStyle(eqHRow.getCell(ci + 1), subHdr(RED)));
      wsEq.views = [{ state: "frozen", ySplit: eqHRow.number, topLeftCell: `A${eqHRow.number + 1}`, activeCell: "A1" }];
      equipDataRows.forEach((rowData, ri) => {
        const bg = ri % 2 === 0 ? WHITE : SILVER;
        const r = wsEq.addRow(rowData);
        r.height = 18;
        r.getCell(1).style = bodyCell(bg);
        r.getCell(2).style = { ...bodyCell(bg), alignment: { horizontal: "center" } };
        r.getCell(3).style = statusCell(rowData[2] === "OK" ? "OK" : rowData[2] === "Flag" ? "Not Clean" : "Needs Attention");
      });
    }
  }

  // ── Write workbook to blob ───────────────────────────────────────────────
  const buffer = await wb.xlsx.writeBuffer();
  const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
  const numSuffix = siteNumber ? `_${String(siteNumber).replace(/\s+/g, "_")}` : "";
  const filename = `inspection_${inspectionDate || "undated"}_${(siteName || "site").replace(/\s+/g, "_")}${numSuffix}.xlsx`;
  return { blob, filename };
}

async function exportAsHtml({ output, inspection, notesPhotos, rawNotes, inspectionType, inspectionDate, siteName, siteNumber, sitePhone, inspectorName, participantName, supervisorName, eventName, foodTemps, foodTempNames, haccpSubs, locationType, floor, restaurantLicense, licenseMissing }) {
  const status = calcOverallStatus(inspection, { foodTemps, foodTempNames });
  const actionItems = buildActionItems({ inspection, rawNotes, foodTemps, foodTempNames });
  const expandedNotes = expandAbbreviations(rawNotes);
  const { index: photoListRaw } = buildPhotoIndex(inspection, notesPhotos || inspection?._notesPhotos);
  const execSummary = buildExportSummary({ inspection, rawNotes, inspectionType, inspectionDate, siteName, foodTemps, foodTempNames });

  // Pre-fetch all photos as base64 data URLs so Office apps can embed them without network access
  const photoList = await Promise.all(
    photoListRaw.map(async p => ({ ...p, previewUrl: await fetchAsDataUrl(p.previewUrl, p.thumbUrl) }))
  );

  // Helper: collapse checklist array into readable HTML — issues first, then passed
  // Each item may have per-item photos shown as thumbnails
  const checklistDetail = (node) => {
    if (!Array.isArray(node?.checklist) || node.checklist.length === 0) return "";
    const renderCi = (c, emoji) => {
      const note = c.comment?.trim() ? ` — ${esc(c.comment.trim())}` : "";
      const ciPhotos = (c.photos || []).filter(p => p.url || p.dataUrl);
      const photoHtml = ciPhotos.length > 0
        ? `<span class="ci-photos">${ciPhotos.map(p =>
            `<img src="${p.url || p.dataUrl}" alt="item photo" style="width:52px;height:52px;object-fit:cover;border-radius:5px;border:1px solid #e2e8f0;vertical-align:middle;margin:2px 3px 2px 0;">`
          ).join("")}</span>`
        : "";
      return `${emoji} ${esc(c.label)}${note}${photoHtml ? `<br>${photoHtml}` : ""}`;
    };
    const lines = [];
    node.checklist.filter(c => c.value === "NO").forEach(c => lines.push(renderCi(c, "❌")));
    node.checklist.filter(c => c.value === "YES").forEach(c => lines.push(renderCi(c, "✅")));
    return lines.join("<br>");
  };

  const allItems = [
    // Facilities
    ["Facilities", "Ceiling",             inspection?.facility?.ceiling],
    ["Facilities", "Walls",               inspection?.facility?.walls],
    ["Facilities", "Floors",              inspection?.facility?.floors],
    ["Facilities", "3-Comp Sinks",        inspection?.facility?.threeCompSinks],
    ["Facilities", "Hand Sink",           inspection?.facility?.handSink],
    ["Facilities", "Mop Area",            inspection?.facility?.mopArea],
    // legacy facility
    ["Facilities", "Lighting",            inspection?.facility?.lighting],
    // Equipments
    ["Equipments", "Coolers",             inspection?.equipment?.coolers],
    ["Equipments", "Freezer",             inspection?.equipment?.freezer],
    ["Equipments", "Warmers",             inspection?.equipment?.warmers],
    ["Equipments", "Grill",               inspection?.equipment?.grill],
    ["Equipments", "Fryer",               inspection?.equipment?.fryer],
    ["Equipments", "Hood",                inspection?.equipment?.hood],
    ["Equipments", "Ice Maker Machine",   inspection?.equipment?.iceMaker],
    ["Equipments", "Other Equipments",    inspection?.equipment?.otherEquip],
    // legacy equipment
    ["Equipments", "Double-Door Cooler",  inspection?.equipment?.doubleDoorCooler],
    ["Equipments", "Double-Door Freezer", inspection?.equipment?.doubleDoorFreezer],
    ["Equipments", "Walk-In Cooler",      inspection?.equipment?.walkInCooler],
    ["Equipments", "Walk-In Freezer",     inspection?.equipment?.walkInFreezer],
    ["Equipments", "Prep Cooler",         inspection?.equipment?.prepCooler],
    ["Equipments", "Ovens",               inspection?.equipment?.ovens],
    ["Equipments", "3-Comp Sink",         inspection?.equipment?.threeCompSink],
    ["Equipments", "Ecolab / Chemicals",  inspection?.equipment?.ecolab],
    // Utensils
    ["Utensils",   "Cleaning Utensils",   inspection?.utensils?.cleaningUtensils],
    ["Utensils",   "Cooking Utensils",    inspection?.utensils?.cookingUtensils],
    // Operations (legacy)
    ["Operations", "Employee Practices",    inspection?.operations?.employeePractices],
    ["Operations", "Handwashing / Supplies", inspection?.operations?.handwashing],
    ["Operations", "Labeling / Dating",     inspection?.operations?.labelingDating],
    ["Operations", "Logs / Documentation",  inspection?.operations?.logs],
    // Maintenance (legacy)
    ["Maintenance", "General Maintenance",  inspection?.maintenance?.generalMaintenance],
  ].filter(([,,node]) => node !== undefined);
  const findings = allItems.filter(([,,node]) => node?.status && node.status !== "OK" && node.status !== "N/A");
  const handT = Number(inspection?.temps?.handSinkTempF);
  const threeT = Number(inspection?.temps?.threeCompSinkTempF);
  const eTemps = collectEquipTemps(inspection);

  // Generate Word-compatible HTML document
  const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40">
<head><meta charset="utf-8">
<!--[if gte mso 9]><xml><w:WordDocument><w:View>Print</w:View><w:Zoom>100</w:Zoom></w:WordDocument></xml><![endif]-->
<style>
  @page { size: letter; margin: 1in; }
  body { font-family: Calibri, Arial, sans-serif; font-size: 11pt; color: #1F2937; line-height: 1.5; }
  h1 { color: #2A295C; font-size: 22pt; margin-bottom: 4px; }
  h2 { color: #2A295C; font-size: 14pt; border-bottom: 2px solid #2A295C; padding-bottom: 4px; margin-top: 24px; }
  .red-line { border-bottom: 3px solid #EE0000; margin-bottom: 20px; }
  .info-table { width: 100%; border-collapse: collapse; margin: 16px 0; }
  .info-table td { padding: 8px 12px; border: 1px solid #E5E7EB; font-size: 10pt; }
  .info-label { background: #F7F8FA; font-weight: bold; color: #2A295C; width: 30%; }
  .status-pass { background: #ECFDF5; color: #15803D; font-weight: bold; font-size: 12pt; text-align: center; padding: 10px; }
  .status-fail { background: #FEF2F2; color: #DC2626; font-weight: bold; font-size: 12pt; text-align: center; padding: 10px; }
  table.scorecard { width: 100%; border-collapse: collapse; margin: 12px 0; }
  table.scorecard th { background: #2A295C; color: white; padding: 8px 12px; text-align: left; font-size: 10pt; }
  table.scorecard td { padding: 7px 12px; border: 1px solid #E5E7EB; font-size: 10pt; }
  .sc-section { background: #F0F1F5; font-weight: bold; color: #2A295C; }
  .pill-pass { background: #ECFDF5; color: #15803D; font-weight: bold; padding: 2px 8px; }
  .pill-fail { background: #FEF2F2; color: #DC2626; font-weight: bold; padding: 2px 8px; }
  .pill-warn { background: #FFFBEB; color: #D97706; font-weight: bold; padding: 2px 8px; }
  .pill-na { background: #F3F4F6; color: #9CA3AF; padding: 2px 8px; }
  .issue-num { background: #DC2626; color: white; font-weight: bold; padding: 2px 8px; text-align: center; width: 30px; }
  .notes-box { background: #F7F8FA; padding: 16px; border-left: 3px solid #2A295C; white-space: pre-wrap; font-size: 10pt; line-height: 1.7; }
  .exec-summary { background: #F0F4FF; border: 1px solid #C7D2FE; border-radius: 6px; padding: 16px 20px; margin: 16px 0; font-size: 10pt; line-height: 1.7; color: #1E293B; }
  .exec-summary p { margin: 0 0 8px 0; }
  .photo-grid { display: flex; flex-wrap: wrap; gap: 12px; margin: 12px 0; }
  .photo-card { width: 200px; border: 1px solid #E5E7EB; border-radius: 6px; overflow: hidden; break-inside: avoid; page-break-inside: avoid; }
  .photo-card img { width: 100%; height: 150px; object-fit: cover; display: block; }
  .photo-caption { padding: 6px 8px; font-size: 8pt; color: #4B5563; background: #F9FAFB; }
  .photo-num { font-weight: bold; color: #2A295C; }
  .footer { margin-top: 32px; padding-top: 12px; border-top: 1px solid #E5E7EB; font-size: 8pt; color: #9CA3AF; text-align: center; }
</style></head><body>

<h1>Sodexo Kitchen Inspection Report</h1>
<div class="red-line"></div>

<table class="info-table">
  <tr><td class="info-label">Inspection Type</td><td>${inspectionType || "\u2014"}</td><td class="info-label">Date</td><td>${inspectionDate || "\u2014"}</td></tr>
  ${eventName ? `<tr><td class="info-label">Event</td><td colspan="3"><strong>${eventName}</strong></td></tr>` : ""}
  <tr><td class="info-label">Inspector</td><td>${inspectorName || "\u2014"}</td><td class="info-label">Supervisor</td><td>${supervisorName || "\u2014"}</td></tr>
  ${participantName ? `<tr><td class="info-label">Participant</td><td colspan="3"><strong>${participantName}</strong></td></tr>` : ""}
  <tr><td class="info-label">Site / Location</td><td>${siteName || "\u2014"}</td><td class="info-label">Unit #</td><td>${siteNumber || "\u2014"}</td></tr>
  ${sitePhone ? `<tr><td class="info-label">Phone</td><td>${sitePhone}</td><td></td><td></td></tr>` : ""}
  ${locationType ? `<tr><td class="info-label">Location Type</td><td colspan="3">${locationType}</td></tr>` : ""}
  ${floor ? `<tr><td class="info-label">Floor</td><td>${floor}</td><td></td><td></td></tr>` : ""}
  ${restaurantLicense && restaurantLicense !== "NO LICENSE" ? `<tr><td class="info-label">License #</td><td>${restaurantLicense}</td><td class="info-label">License Missing</td><td>${licenseMissing ? "Yes" : "No"}</td></tr>` : ""}
  <tr><td class="info-label">Hand Sink Water Temp</td><td>${inspection?.temps?.handSinkTempF ? inspection.temps.handSinkTempF + "\u00B0F" : "\u2014"} ${handT >= 95 ? "\u2705" : handT ? "\u26A0\uFE0F Below 95\u00B0F" : ""}${inspection?.temps?.handSinkNote?.trim() ? `<br/><span style="font-size:9pt;color:#475569;">${inspection.temps.handSinkNote.trim()}</span>` : ""}</td>
      <td class="info-label">3-Comp Sink Wash Temp</td><td>${inspection?.temps?.threeCompSinkTempF ? inspection.temps.threeCompSinkTempF + "\u00B0F" : "\u2014"} ${threeT >= 110 ? "\u2705" : threeT ? "\u26A0\uFE0F Below 110\u00B0F" : ""}${inspection?.temps?.threeCompSinkNote?.trim() ? `<br/><span style="font-size:9pt;color:#475569;">${inspection.temps.threeCompSinkNote.trim()}</span>` : ""}</td></tr>
  ${eTemps.length > 0 ? eTemps.map((et, i, arr) => {
    if (i % 2 === 0) {
      const next = arr[i + 1];
      const etNote = inspection?.equipment?.[et.key]?.notes?.trim() || "";
      const nextNote = next ? (inspection?.equipment?.[next.key]?.notes?.trim() || "") : "";
      return `<tr><td class="info-label">${et.label}</td><td>${et.tempF}\u00B0F ${et.pass ? "\u2705" : "\u26A0\uFE0F Above " + et.max + "\u00B0F"}${etNote ? `<br/><span style="font-size:9pt;color:#475569;">${etNote}</span>` : ""}</td>${next ? `<td class="info-label">${next.label}</td><td>${next.tempF}\u00B0F ${next.pass ? "\u2705" : "\u26A0\uFE0F Above " + next.max + "\u00B0F"}${nextNote ? `<br/><span style="font-size:9pt;color:#475569;">${nextNote}</span>` : ""}</td>` : `<td></td><td></td>`}</tr>`;
    }
    return "";
  }).filter(Boolean).join("\n  ") : ""}
  <tr><td class="info-label">Overall Status</td><td colspan="3" class="${status === "Pass" ? "status-pass" : "status-fail"}">${status === "Pass" ? "PASSED" : "NEEDS ATTENTION"}</td></tr>
</table>

<h2>Executive Summary</h2>
<div class="exec-summary">
${execSummary.split("\n\n").map(p => `<p>${p.replace(/</g, "&lt;")}</p>`).join("\n")}
</div>

<h2>Inspection Scorecard</h2>
<table class="scorecard">
  <tr><th>Section</th><th>Item</th><th>Status</th><th style="min-width:160px;">Checklist Details</th><th>Notes</th></tr>
  ${allItems.map(([sec, label, node]) => {
    const st = node?.status || "N/A";
    const cls = st === "OK" ? "pill-pass" : (st === "Not Clean" || st === "Fail") ? "pill-fail" : st === "Needs Attention" ? "pill-warn" : "pill-na";
    const cd = checklistDetail(node);
    return `<tr><td>${sec}</td><td>${label}</td><td><span class="${cls}">${st}</span></td><td style="font-size:9pt;color:#374151;">${cd || "\u2014"}</td><td>${node?.notes || "\u2014"}</td></tr>`;
  }).join("\n  ")}
  <tr><td>Temps</td><td>Hand Sink</td><td><span class="${handT >= 95 ? "pill-pass" : handT ? "pill-fail" : "pill-na"}">${inspection?.temps?.handSinkTempF ? inspection.temps.handSinkTempF + "\u00B0F" : "N/A"}</span></td><td>\u2014</td><td>${handT >= 95 ? "Meets minimum" : handT ? "Below 95\u00B0F minimum" : "\u2014"}</td></tr>
  <tr><td>Temps</td><td>3-Comp Wash</td><td><span class="${threeT >= 110 ? "pill-pass" : threeT ? "pill-fail" : "pill-na"}">${inspection?.temps?.threeCompSinkTempF ? inspection.temps.threeCompSinkTempF + "\u00B0F" : "N/A"}</span></td><td>\u2014</td><td>${threeT >= 110 ? "Meets minimum" : threeT ? "Below 110\u00B0F minimum" : "\u2014"}</td></tr>
  ${eTemps.map(et => `<tr><td>Temps</td><td>${et.label}</td><td><span class="${et.pass ? "pill-pass" : "pill-fail"}">${et.tempF}\u00B0F</span></td><td>\u2014</td><td>${et.pass ? `Meets \u2264${et.max}\u00B0F` : `Above ${et.max}\u00B0F maximum`}</td></tr>`).join("\n  ")}
</table>

${(() => {
  // ── HACCP Food Temperatures (inspector-recorded inline temps) ──
  const ftItems = HACCP_TEMP_ITEMS.filter(item => {
    const vals = ((foodTemps || {})[item.key] || []).filter(v => v !== "");
    return vals.length > 0;
  });
  if (!ftItems.length) return "";
  const rows = ftItems.map(item => {
    const vals = ((foodTemps || {})[item.key] || []).filter(v => v !== "");
    const names = (foodTempNames || {})[item.key] || [];
    return vals.map((v, vi) => {
      const pass = tempPass(item, v);
      const name = names[vi] || "";
      const statusCls = pass === true ? "pill-pass" : pass === false ? "pill-fail" : "pill-na";
      const statusTxt = pass === true ? "✓ OK" : pass === false ? "⚠️ Flag" : "—";
      return `<tr><td>${item.label}</td><td>${name || "—"}</td><td><span class="${statusCls}">${v}°F</span></td><td>${statusTxt}</td></tr>`;
    }).join("\n  ");
  }).join("\n  ");
  return `<h2>🌡️ HACCP Food Temperatures</h2>
<table class="scorecard">
  <tr><th>Item</th><th>Food Name</th><th>Temperature</th><th>Pass/Flag</th></tr>
  ${rows}
</table>`;
})()}

${(() => {
  // ── Equipment Temperatures ──
  const equipRows = [];
  if (!isNaN(handT) && handT > 0) equipRows.push(`<tr><td>Hand Sink</td><td>${handT}°F</td><td>—</td></tr>`);
  if (!isNaN(threeT) && threeT > 0) equipRows.push(`<tr><td>3-Comp Sink</td><td>${threeT}°F</td><td>—</td></tr>`);
  eTemps.forEach(e => equipRows.push(`<tr><td>${e.label}</td><td>${e.tempF}°F</td><td class="${e.pass ? "pill-pass" : "pill-fail"}">${e.pass ? "✓ OK" : "⚠️ Flag"}</td></tr>`));
  if (!equipRows.length) return "";
  return `<h2>🌡️ Equipment Temperatures</h2>
<table class="scorecard">
  <tr><th>Equipment</th><th>Temperature</th><th>Status</th></tr>
  ${equipRows.join("\n  ")}
</table>`;
})()}

${(() => {
  // ── HACCP Supervisor Submissions ──
  if (!Array.isArray(haccpSubs) || haccpSubs.length === 0) return "";
  const esc = s => String(s || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
  const rows = haccpSubs.map((sub, si) => {
    const allSubItems = [
      ...HACCP_TEMP_ITEMS,
      ...(sub.customItems || []).filter(ci => !HACCP_TEMP_ITEMS.find(d => d.key === ci.key)),
    ];
    const flagged = allSubItems.filter(item => {
      const vals = ((sub.temps || {})[item.key] || []).filter(v => v !== "");
      return vals.some(v => !tempPass(item, v));
    });
    const tempRows = allSubItems.map(item => {
      const vals = ((sub.temps || {})[item.key] || []).filter(v => v !== "");
      if (!vals.length) return "";
      const displayLabel = (sub.itemLabels || {})[item.key] || item.label;
      return vals.map((v, vi) => {
        const pass = tempPass(item, v);
        const foodName = ((sub.foodNames || {})[item.key] || [])[vi] || "";
        const statusCls = pass === true ? "pill-pass" : pass === false ? "pill-fail" : "pill-na";
        return `<tr><td>${esc(displayLabel)}</td><td>${esc(foodName) || "—"}</td><td><span class="${statusCls}">${esc(v)}°F</span></td><td>${pass === true ? "✓ OK" : pass === false ? "⚠️ Flag" : "—"}</td></tr>`;
      }).join("\n    ");
    }).filter(Boolean).join("\n    ");
    const badgeTxt = flagged.length > 0 ? `⚠️ ${flagged.length} flag${flagged.length !== 1 ? "s" : ""}` : "✓ All OK";
    const badgeCls = flagged.length > 0 ? "pill-fail" : "pill-pass";
    const submittedStr = sub.submittedAt ? new Date(sub.submittedAt).toLocaleString() : "—";
    return `<tr style="background:#F0F4FF;"><td colspan="4" style="font-weight:bold;padding:6px 8px;">👤 ${esc(sub.supervisorName || "Supervisor")} &nbsp; <span style="font-weight:400;font-size:9pt;color:#6B7280;">${esc(sub.site || "")}${sub.unit ? " · Unit " + esc(sub.unit) : ""} · ${submittedStr}</span> &nbsp; <span class="${badgeCls}">${badgeTxt}</span></td></tr>
    ${tempRows}
    ${sub.problemReport?.text ? `<tr><td colspan="4" style="background:#FFF7ED;color:#92400E;padding:5px 8px;font-size:9pt;">⚠️ Problem: ${esc(sub.problemReport.text)}</td></tr>` : ""}`;
  }).join("\n  ");
  return `<h2>🌡️ HACCP Supervisor Submissions (${haccpSubs.length})</h2>
<table class="scorecard">
  <tr><th>Item</th><th>Food Name</th><th>Temperature</th><th>Pass/Flag</th></tr>
  ${rows}
</table>`;
})()}

${findings.length > 0 ? `
<h2>Issues Found (${findings.length})</h2>
<table class="scorecard">
  <tr><th>#</th><th>Area</th><th>Item</th><th>Status</th><th style="min-width:160px;">Checklist Details</th><th>Notes</th></tr>
  ${findings.map(([sec, label, node], i) => {
    const cd = checklistDetail(node);
    return `<tr><td class="issue-num">${i + 1}</td><td>${sec}</td><td>${label}</td><td><span class="pill-fail">${node.status}</span></td><td style="font-size:9pt;color:#374151;">${cd || "\u2014"}</td><td>${node.notes || ""}</td></tr>`;
  }).join("\n  ")}
</table>` : `<h2>Issues</h2><p style="background:#ECFDF5;padding:12px;color:#15803D;font-weight:bold;text-align:center;">All areas passed inspection</p>`}

${actionItems.length > 0 ? `
<h2>Corrective Actions Required</h2>
<table class="scorecard">
  <tr><th>#</th><th>Issue</th><th>Priority</th></tr>
  ${actionItems.map((a, i) => `<tr><td style="text-align:center">${i + 1}</td><td>${a.issue}</td><td><span class="${a.priority === "High" ? "pill-fail" : "pill-warn"}">${a.priority}</span></td></tr>`).join("\n  ")}
</table>` : ""}

<h2>Inspector Notes</h2>
${(() => {
  const { grouped } = formatNotesStructured(rawNotes);
  const cats = CATEGORY_ORDER.filter(c => grouped[c]?.length);
  if (!cats.length) return `<div class="notes-box">\u2014</div>`;
  return cats.map(cat => `<div style="margin-bottom:12px;"><p style="font-weight:bold;color:#2A295C;font-size:10pt;margin:0 0 4px 0;">${CATEGORY_LABELS[cat]}</p><ul style="margin:0;padding-left:20px;">${grouped[cat].map(b => `<li style="margin-bottom:4px;font-size:10pt;line-height:1.5;">${b.replace(/</g, "&lt;")}</li>`).join("")}</ul></div>`).join("");
})()}

${photoList.length > 0 ? (() => {
  // Group photos by section label
  const groups = {};
  const groupOrder = [];
  for (const p of photoList) {
    const sec = p.label || "Other";
    if (!groups[sec]) { groups[sec] = []; groupOrder.push(sec); }
    groups[sec].push(p);
  }
  return `<h2>Photo Evidence (${photoList.length} photos)</h2>
${groupOrder.map(sec => {
  const photos = groups[sec];
  return `<div style="margin-bottom:20px;">
<p style="font-weight:bold;color:#2A295C;font-size:11pt;margin:0 0 8px 0;border-bottom:1px solid #E5E7EB;padding-bottom:4px;">${sec.replace(/</g, "&lt;")} <span style="font-weight:normal;color:#64748b;font-size:9pt;">(${photos.length} photo${photos.length !== 1 ? "s" : ""})</span></p>
<div class="photo-grid">
${photos.map(p => `<div class="photo-card">${p.previewUrl ? `<img src="${p.previewUrl}" alt="Photo #${p.num}" />` : `<div style="width:200px;height:150px;background:#F3F4F6;display:flex;align-items:center;justify-content:center;color:#9CA3AF;font-size:9pt;">No preview</div>`}<div class="photo-caption"><span class="photo-num">#${p.num}</span>${p.caption ? ` \u2014 ${p.caption.replace(/</g, "&lt;")}` : ""}</div></div>`).join("\n")}
</div>
</div>`;
}).join("\n")}`;
})() : ""}

<div class="footer">
  <p>Generated ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()} \u2022 Sodexo Kitchen Inspection System</p>
  <p>This report is confidential and intended for internal use only.</p>
</div>
</body></html>`;

  const blob = new Blob([html], { type: "application/msword" });
  const filename = `inspection_${inspectionDate || "undated"}_${(siteName || "site").replace(/\s+/g, "_")}.doc`;
  return { blob, filename };
}

function exportAsTxt({ output, inspectionDate, siteName }) {
  const blob = new Blob([output || ""], { type: "text/plain;charset=utf-8;" });
  const filename = `inspection_${inspectionDate || "undated"}_${(siteName || "site").replace(/\s+/g, "_")}.txt`;
  downloadBlob(blob, filename);
}

// Issues-only Excel export (from a saved history record)
async function exportIssuesOnlyExcel({ rec, haccpSubs = [] }) {
  const XLSX = await import("xlsx");
  const actionItems = rec.actionItems || [];
  const siteName = rec.siteName || "—";
  const inspectionDate = rec.inspectionDate || "—";
  const inspectorName = rec.inspectorName || "—";
  const supervisorName = rec.supervisorName || "—";
  const { index: photoListRaw } = buildPhotoIndex(rec.inspection);
  const str = v => (v == null ? "" : String(v));

  // Pre-fetch all photos as base64 (thumb fallback always works)
  const photoList = await Promise.all(
    photoListRaw.map(async p => ({ ...p, dataUrl: await fetchAsDataUrl(p.previewUrl, p.thumbUrl) }))
  );

  // ── SHEET 1: Issues ──────────────────────────────────────────────────────
  const metaRows = [
    [`INSPECTION ISSUES — ${siteName}`],
    [],
    ["Date", str(inspectionDate)],
    ["Inspection Type", str(rec.inspectionType || "—")],
    ["Inspector", str(inspectorName)],
    ["Supervisor", str(supervisorName)],
    ...(rec.participantName ? [["Participant", str(rec.participantName)]] : []),
    ["Site / Location", str(siteName)],
    ["Unit #", str(rec.siteNumber || "—")],
    ...(rec.locationType ? [["Location Type", str(rec.locationType)]] : []),
    ...(rec.floor ? [["Floor", str(rec.floor)]] : []),
    ...(rec.eventName ? [["Event", str(rec.eventName)]] : []),
    ...(rec.restaurantLicense && rec.restaurantLicense !== "NO LICENSE"
      ? [["License #", str(rec.restaurantLicense)], ["License Missing", rec.licenseMissing ? "Yes" : "No"]]
      : []),
    ["Overall Status", str(rec.overallStatus || "—")],
    [],
  ];

  // Executive Summary
  const summaryText = buildExportSummary(rec, haccpSubs);
  if (summaryText) {
    metaRows.push(["EXECUTIVE SUMMARY"]);
    summaryText.split(/\n+/).filter(l => l.trim()).forEach(line => metaRows.push([line]));
    metaRows.push([]);
  }

  // Inspector Notes
  const notesText = formatNotesText(rec.inspection);
  if (notesText) {
    metaRows.push(["INSPECTOR NOTES"]);
    notesText.split(/\n/).filter(l => l.trim()).forEach(line => metaRows.push([line]));
    metaRows.push([]);
  }

  const issuesHeader = ["#", "Issue", "Status", "Owner", "Due Date"];
  const issuesRows = actionItems.length > 0
    ? actionItems.map((a, i) => [i + 1, str(a.issue), str(a.status && a.status !== "OK" ? a.status : (a.priority || "")), str(a.owner || "—"), str(a.due || "—")])
    : [["", "No issues — all areas passed inspection", "", "", ""]];

  const ws1Data = [...metaRows, issuesHeader, ...issuesRows];
  const ws1 = XLSX.utils.aoa_to_sheet(ws1Data);

  const headerRowIdx = metaRows.length;
  ws1["!autofilter"] = { ref: `A${headerRowIdx + 1}:E${headerRowIdx + 1 + issuesRows.length}` };
  ws1["!freeze"] = { xSplit: 0, ySplit: headerRowIdx + 1, topLeftCell: `A${headerRowIdx + 2}`, activePane: "bottomLeft" };
  ws1["!cols"] = [{ wch: 4 }, { wch: 65 }, { wch: 12 }, { wch: 20 }, { wch: 14 }];

  // ── SHEET 2: Photos ──────────────────────────────────────────────────────
  const wb = XLSX.utils.book_new();
  XLSX.utils.book_append_sheet(wb, ws1, "Issues");

  if (photoList.length > 0) {
    const ws2Header = ["#", "Section", "Caption", "Photo URL"];
    const ws2Rows = photoList.map(p => [p.num, str(p.label), str(p.caption), str(p.previewUrl || "")]);
    const ws2Data = [ws2Header, ...ws2Rows];
    const ws2 = XLSX.utils.aoa_to_sheet(ws2Data);
    ws2["!cols"] = [{ wch: 4 }, { wch: 28 }, { wch: 40 }, { wch: 80 }];
    ws2["!autofilter"] = { ref: `A1:D${ws2Data.length}` };
    ws2["!freeze"] = { xSplit: 0, ySplit: 1, topLeftCell: "A2", activePane: "bottomLeft" };

    const images = [];
    const COLS_PER_ROW = 3;
    const ROW_OFFSET = ws2Data.length + 2;
    for (let i = 0; i < photoList.length; i++) {
      const p = photoList[i];
      if (!p.dataUrl) continue;
      const base64 = p.dataUrl.replace(/^data:[^;]+;base64,/, "");
      const imgType = p.dataUrl.startsWith("data:image/png") ? "png" : "jpeg";
      const col = (i % COLS_PER_ROW) * 2;
      const row = ROW_OFFSET + Math.floor(i / COLS_PER_ROW) * 12;
      images.push({ "!pos": { r: row, c: col, x: 0, y: 0, w: 200, h: 150 }, "!datatype": "base64", "!data": base64, "!type": imgType });
    }
    if (images.length > 0) ws2["!images"] = images;

    XLSX.utils.book_append_sheet(wb, ws2, "Photos");
  }

  // ── SHEET: Checklist Item Photos ─────────────────────────────────────────
  {
    const ciPhotoRows = [];
    const checklistSectionsExcel = [
      ["facility","ceiling"],["facility","walls"],["facility","floors"],
      ["facility","threeCompSinks"],["facility","handSink"],["facility","mopArea"],
      ["equipment","coolers"],["equipment","freezer"],["equipment","warmers"],
      ["equipment","grill"],["equipment","hood"],["equipment","iceMaker"],["equipment","otherEquip"],
      ["utensils","cleaningUtensils"],["utensils","cookingUtensils"],
      ["operations","employeePractices"],["operations","handwashing"],
      ["operations","labelingDating"],["operations","logs"],
    ];
    for (const [sec, key] of checklistSectionsExcel) {
      const node = rec.inspection?.[sec]?.[key];
      if (!Array.isArray(node?.checklist)) continue;
      for (const c of node.checklist) {
        const photos = (c.photos || []).filter(p => p.url || p.dataUrl);
        if (!photos.length) continue;
        const result = c.value === "NO" ? "Fail" : c.value === "YES" ? "Pass" : "—";
        for (const p of photos) {
          ciPhotoRows.push([
            str(c.label || "Item"),
            result,
            str(c.comment || ""),
            str(p.url || p.dataUrl || ""),
          ]);
        }
      }
    }
    if (ciPhotoRows.length > 0) {
      const ciHeader = ["Checklist Item", "Result", "Comment", "Photo URL"];
      const wsCi = XLSX.utils.aoa_to_sheet([ciHeader, ...ciPhotoRows]);
      wsCi["!cols"] = [{ wch: 40 }, { wch: 8 }, { wch: 40 }, { wch: 80 }];
      wsCi["!autofilter"] = { ref: `A1:D${ciPhotoRows.length + 1}` };
      wsCi["!freeze"] = { xSplit: 0, ySplit: 1, topLeftCell: "A2", activePane: "bottomLeft" };
      XLSX.utils.book_append_sheet(wb, wsCi, "Item Photos");
    }
  }

  // ── SHEET: Equipment Temps ────────────────────────────────────────────────
  {
    const handT = Number(rec.temps?.handSinkTempF);
    const threeT = Number(rec.temps?.threeCompSinkTempF);
    const eTemps = collectEquipTemps(rec.inspection);
    const equipHeader = ["Equipment", "Temp (°F)", "Status"];
    const equipRows = [];
    if (!isNaN(handT) && handT > 0) equipRows.push(["Hand Sink", handT, "—"]);
    if (!isNaN(threeT) && threeT > 0) equipRows.push(["3-Comp Sink", threeT, "—"]);
    eTemps.forEach(e => equipRows.push([e.label, e.tempF, e.pass ? "OK" : "Flag"]));
    if (equipRows.length > 0) {
      const wsEq = XLSX.utils.aoa_to_sheet([equipHeader, ...equipRows]);
      wsEq["!cols"] = [{ wch: 32 }, { wch: 12 }, { wch: 10 }];
      wsEq["!autofilter"] = { ref: `A1:C${equipRows.length + 1}` };
      wsEq["!freeze"] = { xSplit: 0, ySplit: 1, topLeftCell: "A2", activePane: "bottomLeft" };
      XLSX.utils.book_append_sheet(wb, wsEq, "Equipment Temps");
    }
  }

  // ── SHEET: Supervisor Log ─────────────────────────────────────────────────
  if (haccpSubs.length > 0) {
    const supHeader = ["Supervisor", "Submitted At", "HACCP Item", "Food Name", "Temp (°F)", "Result", "Problem Report"];
    const supRows = [];
    for (const sub of haccpSubs) {
      const allSubItems = [
        ...HACCP_TEMP_ITEMS,
        ...(sub.customItems || []).filter(ci => !HACCP_TEMP_ITEMS.find(d => d.key === ci.key)),
      ];
      const submittedStr = sub.submittedAt ? new Date(sub.submittedAt).toLocaleString() : "—";
      const problemText = sub.problemReport?.text || "";
      for (const item of allSubItems) {
        const vals = ((sub.temps || {})[item.key] || []).filter(v => v !== "");
        const displayLabel = (sub.itemLabels || {})[item.key] || item.label;
        for (let vi = 0; vi < vals.length; vi++) {
          const v = vals[vi];
          const pass = tempPass(item, v);
          const foodName = ((sub.foodNames || {})[item.key] || [])[vi] || "";
          const result = pass === true ? "OK" : pass === false ? "Flag" : "—";
          supRows.push([str(sub.supervisorName), submittedStr, displayLabel, foodName, v, result, problemText]);
        }
      }
    }
    if (supRows.length > 0) {
      const wsSup = XLSX.utils.aoa_to_sheet([supHeader, ...supRows]);
      wsSup["!cols"] = [{ wch: 22 }, { wch: 22 }, { wch: 24 }, { wch: 22 }, { wch: 10 }, { wch: 8 }, { wch: 40 }];
      wsSup["!autofilter"] = { ref: `A1:G${supRows.length + 1}` };
      wsSup["!freeze"] = { xSplit: 0, ySplit: 1, topLeftCell: "A2", activePane: "bottomLeft" };
      XLSX.utils.book_append_sheet(wb, wsSup, "Supervisor Log");
    }
  }

  // ── SHEET: Supplies Needed ────────────────────────────────────────────────
  const supplies = (rec.suppliesNeeded || []).filter(s => s.item && s.item.trim());
  if (supplies.length > 0) {
    const supNeedHeader = ["#", "Supply Item", "Qty", "Urgent"];
    const supNeedRows = supplies.map((s, i) => [i + 1, str(s.item), str(s.qty || ""), s.urgent ? "🔴 Yes" : "No"]);
    const wsSupN = XLSX.utils.aoa_to_sheet([supNeedHeader, ...supNeedRows]);
    wsSupN["!cols"] = [{ wch: 4 }, { wch: 40 }, { wch: 10 }, { wch: 10 }];
    wsSupN["!autofilter"] = { ref: `A1:D${supNeedRows.length + 1}` };
    wsSupN["!freeze"] = { xSplit: 0, ySplit: 1, topLeftCell: "A2", activePane: "bottomLeft" };
    XLSX.utils.book_append_sheet(wb, wsSupN, "Supplies Needed");
  }

  const wbOut = XLSX.write(wb, { bookType: "xlsx", type: "array" });
  const blob = new Blob([wbOut], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
  const filename = `issues_${inspectionDate || "undated"}_${(rec.siteName || "site").replace(/\s+/g, "_")}.xlsx`;
  return { blob, filename };
}

// Issues-only Word export (from a saved history record)
async function exportIssuesOnlyWord({ rec, haccpSubs = [] }) {
  const actionItems = rec.actionItems || [];
  const siteName = rec.siteName || "—";
  const inspectionDate = rec.inspectionDate || "—";
  const inspectorName = rec.inspectorName || "—";
  const supervisorName = rec.supervisorName || "—";
  const { index: photoListRaw } = buildPhotoIndex(rec.inspection);

  // Pre-fetch all photos as base64 so Office apps can embed them
  const photoList = await Promise.all(
    photoListRaw.map(async p => ({ ...p, previewUrl: await fetchAsDataUrl(p.previewUrl, p.thumbUrl) }))
  );

  // Group photos by section
  const photoGroups = {};
  const photoGroupOrder = [];
  for (const p of photoList) {
    const sec = p.label || "Other";
    if (!photoGroups[sec]) { photoGroups[sec] = []; photoGroupOrder.push(sec); }
    photoGroups[sec].push(p);
  }

  const html = `<html xmlns:o="urn:schemas-microsoft-com:office:office" xmlns:w="urn:schemas-microsoft-com:office:word" xmlns="http://www.w3.org/TR/REC-html40">
<head><meta charset="utf-8">
<!--[if gte mso 9]><xml><w:WordDocument><w:View>Print</w:View><w:Zoom>100</w:Zoom></w:WordDocument></xml><![endif]-->
<style>
  @page { size: letter; margin: 1in; }
  body { font-family: Calibri, Arial, sans-serif; font-size: 11pt; color: #1F2937; line-height: 1.5; }
  h1 { color: #2A295C; font-size: 20pt; margin-bottom: 4px; }
  h2 { color: #2A295C; font-size: 13pt; border-bottom: 2px solid #2A295C; padding-bottom: 4px; margin-top: 20px; }
  .red-line { border-bottom: 3px solid #EE0000; margin-bottom: 16px; }
  .info-table { width: 100%; border-collapse: collapse; margin: 12px 0; }
  .info-table td { padding: 7px 12px; border: 1px solid #E5E7EB; font-size: 10pt; }
  .info-label { background: #F7F8FA; font-weight: bold; color: #2A295C; width: 30%; }
  table.issues { width: 100%; border-collapse: collapse; margin: 12px 0; }
  table.issues th { background: #2A295C; color: white; padding: 8px 12px; text-align: left; font-size: 10pt; }
  table.issues td { padding: 7px 12px; border: 1px solid #E5E7EB; font-size: 10pt; }
  .pill-high { background: #FEF2F2; color: #DC2626; font-weight: bold; padding: 2px 8px; }
  .pill-med { background: #FFFBEB; color: #D97706; font-weight: bold; padding: 2px 8px; }
  .pill-critical { background: #7f1d1d; color: #fff; font-weight: bold; padding: 2px 8px; }
  .pill-resolved { background: #ECFDF5; color: #15803D; font-weight: bold; padding: 2px 8px; }
  .pill-pass { background: #ECFDF5; color: #15803D; font-weight: bold; padding: 2px 8px; }
  .pill-fail { background: #FEF2F2; color: #DC2626; font-weight: bold; padding: 2px 8px; }
  .pill-na { background: #F3F4F6; color: #6B7280; padding: 2px 8px; }
  .status-pass { background: #ECFDF5; color: #15803D; font-weight: bold; font-size: 12pt; text-align: center; padding: 10px; }
  .status-fail { background: #FEF2F2; color: #DC2626; font-weight: bold; font-size: 12pt; text-align: center; padding: 10px; }
  .photo-grid { display: flex; flex-wrap: wrap; gap: 12px; margin: 8px 0 16px 0; }
  .photo-card { width: 200px; border: 1px solid #E5E7EB; border-radius: 6px; overflow: hidden; break-inside: avoid; page-break-inside: avoid; }
  .photo-card img { width: 100%; height: 150px; object-fit: cover; display: block; }
  .photo-caption { padding: 6px 8px; font-size: 8pt; color: #4B5563; background: #F9FAFB; }
  .photo-num { font-weight: bold; color: #2A295C; }
  table.scorecard { width: 100%; border-collapse: collapse; margin: 12px 0; }
  table.scorecard th { background: #2A295C; color: white; padding: 8px 12px; text-align: left; font-size: 10pt; }
  table.scorecard td { padding: 7px 12px; border: 1px solid #E5E7EB; font-size: 10pt; }
  .footer { margin-top: 32px; padding-top: 12px; border-top: 1px solid #E5E7EB; font-size: 8pt; color: #9CA3AF; text-align: center; }
  .section-heading { color: #2A295C; font-size: 13pt; border-bottom: 2px solid #2A295C; padding-bottom: 4px; margin-top: 20px; }
  .summary-text { font-size: 10.5pt; color: #374151; line-height: 1.6; margin: 8px 0 14px 0; background: #F8FAFC; border-left: 4px solid #2A295C; padding: 10px 14px; border-radius: 0 4px 4px 0; }
  .notes-category { font-weight: bold; color: #2A295C; font-size: 10pt; margin-top: 10px; }
  .notes-item { font-size: 10pt; color: #374151; margin: 2px 0 2px 14px; }
</style></head><body>
<h1>Inspection Issues Report</h1>
<div class="red-line"></div>
<table class="info-table">
  <tr>
    <td class="info-label">Date</td><td>${esc(inspectionDate)}</td>
    <td class="info-label">Inspection Type</td><td>${esc(rec.inspectionType || "—")}</td>
  </tr>
  <tr>
    <td class="info-label">Inspector</td><td>${esc(inspectorName)}</td>
    <td class="info-label">Supervisor</td><td>${esc(supervisorName)}</td>
  </tr>
  ${rec.participantName ? `<tr><td class="info-label">Participant</td><td colspan="3">${esc(rec.participantName)}</td></tr>` : ""}
  <tr>
    <td class="info-label">Site / Location</td><td>${esc(siteName)}</td>
    <td class="info-label">Unit #</td><td>${esc(rec.siteNumber || "—")}</td>
  </tr>
  <tr>
    <td class="info-label">Location Type</td><td>${esc(rec.locationType || "—")}</td>
    <td></td><td></td>
  </tr>
  ${rec.floor ? `<tr><td class="info-label">Floor</td><td>${esc(rec.floor)}</td><td class="info-label">Event</td><td>${esc(rec.eventName || "—")}</td></tr>` : ""}
  ${rec.restaurantLicense && rec.restaurantLicense !== "NO LICENSE"
    ? `<tr><td class="info-label">License #</td><td>${esc(rec.restaurantLicense)}</td><td class="info-label">License Missing</td><td>${rec.licenseMissing ? "Yes" : "No"}</td></tr>`
    : ""}
  ${rec.sitePhone ? `<tr><td class="info-label">Phone</td><td>${esc(rec.sitePhone)}</td><td></td><td></td></tr>` : ""}
  <tr>
    <td class="info-label">Overall Status</td>
    <td class="${rec.overallStatus === "Pass" ? "status-pass" : "status-fail"}">
      ${rec.overallStatus === "Pass" ? "PASSED" : "NEEDS ATTENTION"}
    </td>
    <td class="info-label">Compliance Score</td>
    <td>${(() => { const s = calcInspectionScore(rec.inspection); return s ? `<strong style="color:${s.color}">${s.pct}% — Grade ${s.grade}</strong> (${s.passed}/${s.scoredTotal} items)` : "—"; })()}</td>
  </tr>
</table>

${(() => {
  const summary = buildExportSummary(rec, haccpSubs);
  return summary
    ? `<h2 class="section-heading">Executive Summary</h2><p class="summary-text">${esc(summary)}</p>`
    : "";
})()}

${(() => {
  const notesHtml = formatNotesStructured(rec.inspection);
  return notesHtml
    ? `<h2 class="section-heading">Inspector Notes</h2>${notesHtml}`
    : "";
})()}

${actionItems.length > 0 ? `
<h2>Issues &amp; Corrective Actions (${actionItems.length})</h2>
<table class="issues">
  <tr><th>#</th><th>Issue</th><th>Status</th></tr>
  ${actionItems.map((a, i) => { const st = a.status && a.status !== "OK" ? a.status : (a.priority || ""); const cls = (st === "Fail" || st === "Not Clean" || st === "Critical Violation") ? "pill-high" : st === "Maintenance" ? "pill-maint" : "pill-med"; return `<tr><td style="text-align:center;width:40px">${i + 1}</td><td>${(a.issue || "").replace(/</g, "&lt;")}</td><td><span class="${cls}">${st}</span></td></tr>`; }).join("\n  ")}
</table>` : `<h2>Issues</h2><p style="background:#ECFDF5;padding:12px;color:#15803D;font-weight:bold;text-align:center;">All areas passed — no issues found ✓</p>`}

${(() => {
  const supplies = (rec.suppliesNeeded || []).filter(s => s.item && s.item.trim());
  if (!supplies.length) return "";
  return `<h2>🛒 Supplies Needed (${supplies.length})</h2>
<table class="issues">
  <tr><th>#</th><th>Supply Item</th><th>Qty</th><th>Urgent</th></tr>
  ${supplies.map((s, i) => `<tr><td style="text-align:center;width:40px">${i + 1}</td><td>${esc(s.item)}</td><td>${esc(s.qty || "—")}</td><td>${s.urgent ? '<span class="pill-high">🔴 Urgent</span>' : "No"}</td></tr>`).join("\n  ")}
</table>`;
})()}

${(() => {
  const handT = Number(rec.temps?.handSinkTempF);
  const threeT = Number(rec.temps?.threeCompSinkTempF);
  const eTemps = collectEquipTemps(rec.inspection);
  const equipRows = [];
  if (!isNaN(handT) && handT > 0) equipRows.push(`<tr><td>Hand Sink</td><td>${handT}°F</td><td>—</td></tr>`);
  if (!isNaN(threeT) && threeT > 0) equipRows.push(`<tr><td>3-Comp Sink</td><td>${threeT}°F</td><td>—</td></tr>`);
  eTemps.forEach(e => equipRows.push(`<tr><td>${e.label}</td><td>${e.tempF}°F</td><td class="${e.pass ? "pill-pass" : "pill-fail"}">${e.pass ? "✓ OK" : "⚠️ Flag"}</td></tr>`));
  if (!equipRows.length) return "";
  return `<h2>🌡️ Equipment Temperatures</h2>
<table class="scorecard">
  <tr><th>Equipment</th><th>Temperature</th><th>Status</th></tr>
  ${equipRows.join("\n  ")}
</table>`;
})()}

${(() => {
  if (!Array.isArray(haccpSubs) || haccpSubs.length === 0) return "";
  const esc = s => String(s || "").replace(/&/g,"&amp;").replace(/</g,"&lt;").replace(/>/g,"&gt;");
  const rows = haccpSubs.map(sub => {
    const allSubItems = [
      ...HACCP_TEMP_ITEMS,
      ...(sub.customItems || []).filter(ci => !HACCP_TEMP_ITEMS.find(d => d.key === ci.key)),
    ];
    const flagged = allSubItems.filter(item => {
      const vals = ((sub.temps || {})[item.key] || []).filter(v => v !== "");
      return vals.some(v => !tempPass(item, v));
    });
    const tempRows = allSubItems.map(item => {
      const vals = ((sub.temps || {})[item.key] || []).filter(v => v !== "");
      if (!vals.length) return "";
      const displayLabel = (sub.itemLabels || {})[item.key] || item.label;
      return vals.map((v, vi) => {
        const pass = tempPass(item, v);
        const foodName = ((sub.foodNames || {})[item.key] || [])[vi] || "";
        const statusCls = pass === true ? "pill-pass" : pass === false ? "pill-fail" : "pill-na";
        return `<tr><td>${esc(displayLabel)}</td><td>${esc(foodName) || "—"}</td><td><span class="${statusCls}">${esc(v)}°F</span></td><td>${pass === true ? "✓ OK" : pass === false ? "⚠️ Flag" : "—"}</td></tr>`;
      }).join("\n    ");
    }).filter(Boolean).join("\n    ");
    const badgeTxt = flagged.length > 0 ? `⚠️ ${flagged.length} flag${flagged.length !== 1 ? "s" : ""}` : "✓ All OK";
    const badgeCls = flagged.length > 0 ? "pill-fail" : "pill-pass";
    const submittedStr = sub.submittedAt ? new Date(sub.submittedAt).toLocaleString() : "—";
    return `<tr style="background:#F0F4FF;"><td colspan="4" style="font-weight:bold;padding:6px 8px;">👤 ${esc(sub.supervisorName || "Supervisor")} &nbsp; <span style="font-weight:400;font-size:9pt;color:#6B7280;">${esc(sub.site || "")}${sub.unit ? " · Unit " + esc(sub.unit) : ""} · ${submittedStr}</span> &nbsp; <span class="${badgeCls}">${badgeTxt}</span></td></tr>
    ${tempRows}
    ${sub.problemReport?.text ? `<tr><td colspan="4" style="background:#FFF7ED;color:#92400E;padding:5px 8px;font-size:9pt;">⚠️ Problem: ${esc(sub.problemReport.text)}</td></tr>` : ""}`;
  }).join("\n  ");
  return `<h2>🌡️ HACCP Supervisor Submissions (${haccpSubs.length})</h2>
<table class="scorecard">
  <tr><th>Item</th><th>Food Name</th><th>Temperature</th><th>Pass/Flag</th></tr>
  ${rows}
</table>`;
})()}

${photoList.length > 0 ? `<h2>Photo Evidence (${photoList.length} photos)</h2>
${photoGroupOrder.map(sec => {
  const photos = photoGroups[sec];
  return `<div style="margin-bottom:20px;">
<p style="font-weight:bold;color:#2A295C;font-size:11pt;margin:0 0 8px 0;border-bottom:1px solid #E5E7EB;padding-bottom:4px;">${sec.replace(/</g, "&lt;")} <span style="font-weight:normal;color:#64748b;font-size:9pt;">(${photos.length} photo${photos.length !== 1 ? "s" : ""})</span></p>
<div class="photo-grid">
${photos.map(p => `<div class="photo-card">${p.previewUrl ? `<img src="${p.previewUrl}" alt="Photo #${p.num}" />` : `<div style="width:200px;height:150px;background:#F3F4F6;display:flex;align-items:center;justify-content:center;color:#9CA3AF;font-size:9pt;">No preview</div>`}<div class="photo-caption"><span class="photo-num">#${p.num}</span>${p.caption ? ` \u2014 ${p.caption.replace(/</g, "&lt;")}` : ""}</div></div>`).join("\n")}
</div>
</div>`;
}).join("\n")}` : ""}

${(() => {
  // Per-checklist-item photos
  const ciPhotoEntries = [];
  const checklistSectionsIssuesWord = [
    ["facility","ceiling"],["facility","walls"],["facility","floors"],
    ["facility","threeCompSinks"],["facility","handSink"],["facility","mopArea"],
    ["equipment","coolers"],["equipment","freezer"],["equipment","warmers"],
    ["equipment","grill"],["equipment","hood"],["equipment","iceMaker"],["equipment","otherEquip"],
    ["utensils","cleaningUtensils"],["utensils","cookingUtensils"],
    ["operations","employeePractices"],["operations","handwashing"],
    ["operations","labelingDating"],["operations","logs"],
  ];
  for (const [sec, key] of checklistSectionsIssuesWord) {
    const node = rec.inspection?.[sec]?.[key];
    if (!Array.isArray(node?.checklist)) continue;
    for (const c of node.checklist) {
      const photos = (c.photos || []).filter(p => p.url || p.dataUrl);
      if (!photos.length) continue;
      const result = c.value === "NO" ? "❌ Fail" : c.value === "YES" ? "✅ Pass" : "";
      ciPhotoEntries.push({ label: c.label || "Item", result, comment: c.comment || "", photos });
    }
  }
  if (!ciPhotoEntries.length) return "";
  const imgCards = ciPhotoEntries.flatMap(entry =>
    entry.photos.map(p => {
      const src = p.url || p.dataUrl || "";
      return src
        ? `<div class="photo-card"><img src="${src}" alt="${esc(entry.label)}" class="photo-img"><p class="photo-caption"><strong>${esc(entry.result)}</strong> ${esc(entry.label)}${entry.comment ? `<br><em>${esc(entry.comment)}</em>` : ""}</p></div>`
        : "";
    }).filter(Boolean)
  );
  return imgCards.length
    ? `<h2>Checklist Item Photos (${ciPhotoEntries.length} item${ciPhotoEntries.length !== 1 ? "s" : ""})</h2><div class="photo-grid">${imgCards.join("")}</div>`
    : "";
})()}

<div class="footer">
  <p>Generated ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString()} &bull; Sodexo Kitchen Inspection System</p>
</div>
</body></html>`;

  const blob = new Blob([html], { type: "application/msword" });
  const filename = `issues_${inspectionDate || "undated"}_${(rec.siteName || "site").replace(/\s+/g, "_")}.doc`;
  return { blob, filename };
}

/* ── Temperature Trend Chart (pure SVG) ─────────────────── */
function TempTrendChart({ history }) {
  const [hoveredPoint, setHoveredPoint] = useState(null);
  const [selectedLoc, setSelectedLoc] = useState(null); // active location (null = use first)
  const [locSearch, setLocSearch] = useState(""); // text filter for location search
  const [showLocDropdown, setShowLocDropdown] = useState(false); // show filtered list

  // Group by location+unit+floor, sorted by date
  const locationData = useMemo(() => {
    const map = {};
    for (const rec of history) {
      const unitNum = rec.siteNumber || "";
      const key = `${rec.siteName || rec.location || "—"}${unitNum ? ` #${unitNum}` : ""}${rec.floor ? ` - ${rec.floor}` : ""}`;
      if (!map[key]) map[key] = { points: [], unitNum };
      const hand = Number(rec.temps?.handSinkTempF);
      const three = Number(rec.temps?.threeCompSinkTempF);
      // Collect cooler/freezer temps from equipment items (per-equipment)
      let coolTemps = [], frzTemps = [];
      let coolItems = [], frzItems = []; // { label, tempF } for named equipment
      // Support new per-equipment temps
      const equip = rec.inspection?.equipment || {};
      for (const [ek, node] of Object.entries(equip)) {
        if (!node?.tempF) continue;
        const t = Number(node.tempF);
        if (!t) continue;
        const cold = COLD_EQUIPMENT[ek] || (ek.startsWith("custom_") ? detectColdType(node.label) : null);
        if (cold?.type === "cooler") { coolTemps.push(t); if (node.label) coolItems.push({ label: node.label, tempF: t }); }
        else if (cold?.type === "freezer") { frzTemps.push(t); if (node.label) frzItems.push({ label: node.label, tempF: t }); }
      }
      // Fallback: old records may have temps.coolerTempF / freezerTempF
      if (!coolTemps.length && rec.temps?.coolerTempF) { const v = Number(rec.temps.coolerTempF); if (v) { coolTemps.push(v); coolItems.push({ label: "Cooler", tempF: v }); } }
      if (!frzTemps.length && rec.temps?.freezerTempF) { const v = Number(rec.temps.freezerTempF); if (v) { frzTemps.push(v); frzItems.push({ label: "Freezer", tempF: v }); } }
      const coolAvg = coolTemps.length ? Math.round(coolTemps.reduce((a, b) => a + b, 0) / coolTemps.length) : null;
      const frzAvg = frzTemps.length ? Math.round(frzTemps.reduce((a, b) => a + b, 0) / frzTemps.length) : null;
      if (hand || three || coolAvg || frzAvg) {
        map[key].points.push({
          date: rec.inspectionDate || rec.savedAt?.slice(0, 10) || "—",
          handSink: hand || null,
          threeComp: three || null,
          cooler: coolAvg,
          coolerItems: coolItems,
          freezer: frzAvg,
          freezerItems: frzItems,
          floor: rec.floor || "",
          status: rec.overallStatus || "—",
        });
      }
    }
    for (const k of Object.keys(map)) {
      map[k].points.sort((a, b) => a.date.localeCompare(b.date));
    }
    return map;
  }, [history]);

  const locations = Object.keys(locationData);
  if (locations.length === 0) return null;

  // Determine which location is active
  const activeLoc = (selectedLoc && locations.includes(selectedLoc)) ? selectedLoc : locations[0];

  // Build a quick "at a glance" summary across all locations (latest reading per location)
  const glanceSummary = useMemo(() => {
    let handTemps = [], threeTemps = [], coolerTemps = [], freezerTemps = [];
    for (const loc of locations) {
      const pts = locationData[loc].points;
      const latest = pts[pts.length - 1];
      if (!latest) continue;
      if (latest.handSink) handTemps.push(latest.handSink);
      if (latest.threeComp) threeTemps.push(latest.threeComp);
      if (latest.cooler) coolerTemps.push(latest.cooler);
      if (latest.freezer) freezerTemps.push(latest.freezer);
    }
    const avg = arr => arr.length ? Math.round(arr.reduce((a,b)=>a+b,0)/arr.length) : null;
    return {
      hand: avg(handTemps), handPass: handTemps.length ? handTemps.every(t=>t>=95) : null,
      three: avg(threeTemps), threePass: threeTemps.length ? threeTemps.every(t=>t>=110) : null,
      cooler: avg(coolerTemps), coolerPass: coolerTemps.length ? coolerTemps.every(t=>t<=40) : null,
      freezer: avg(freezerTemps), freezerPass: freezerTemps.length ? freezerTemps.every(t=>t<=20) : null,
    };
  }, [locations, locationData]);

  const anyAlert = (glanceSummary.handPass === false || glanceSummary.threePass === false || glanceSummary.coolerPass === false || glanceSummary.freezerPass === false);

  // Compute per-location data for the active location only
  const { points: activePoints, unitNum: activeUnitNum } = locationData[activeLoc] || { points: [], unitNum: "" };
  const locKey = activeLoc.replace(/\W/g, "");

  // Helper to build an independent mini-chart for a single sensor series
  // Returns null if there are no readings for that sensor at this location
  function buildSensorChart(sensorKey, label, color, gradId, threshold, thresholdLabel, isMin, itemsKey) {
    const vals = activePoints.map((p, i) => ({ i, date: p.date, v: p[sensorKey], items: itemsKey ? (p[itemsKey] || []) : [] })).filter(d => d.v !== null && d.v !== undefined);
    if (vals.length === 0) return null;
    const avg = Math.round(vals.reduce((s, d) => s + d.v, 0) / vals.length);
    const allPass = vals.every(d => isMin ? d.v >= threshold : d.v <= threshold);
    // Collect all unique named equipment across all points for the header
    const allItemLabels = [];
    vals.forEach(d => d.items.forEach(it => { if (it.label && !allItemLabels.includes(it.label)) allItemLabels.push(it.label); }));
    const SW = 500, SH = 160, SPAD = 42, SPADR = 20, SPADT = 16, SPADB = 36;
    const xStep = vals.length > 1 ? (SW - SPAD - SPADR) / (vals.length - 1) : (SW - SPAD - SPADR) / 2;
    const xOff = vals.length === 1 ? (SW - SPAD - SPADR) / 2 : 0;
    const sToX = (idx) => SPAD + xOff + idx * xStep;
    const rawTemps = vals.map(d => d.v);
    const dataMin = Math.min(...rawTemps);
    const dataMax = Math.max(...rawTemps);
    // Tight Y range: expand by ~10% on each side, always include threshold
    const padding = Math.max(5, (dataMax - dataMin) * 0.25) + 3;
    const minT = Math.min(dataMin - padding, threshold - padding);
    const maxT = Math.max(dataMax + padding, threshold + padding);
    const rangeT = maxT - minT || 1;
    const sToY = (t) => SPADT + (SH - SPADT - SPADB) * (1 - (t - minT) / rangeT);
    const coords = vals.map((d, idx) => [sToX(idx), sToY(d.v)]);
    const pathD = coords.map((c, idx) => `${idx === 0 ? "M" : "L"}${c[0]},${c[1]}`).join(" ");
    const areaD = coords.length >= 2
      ? `${pathD} L${coords[coords.length - 1][0]},${SH - SPADB} L${coords[0][0]},${SH - SPADB} Z`
      : "";
    const gridSteps = [];
    for (let t = Math.ceil(minT / 5) * 5; t <= maxT; t += 5) gridSteps.push(t);
    const threshY = sToY(threshold);
    const uid = `${gradId}-${locKey}`;
    return { vals, avg, allPass, allItemLabels, SW, SH, SPAD, SPADR, SPADT, SPADB, sToX, sToY, coords, pathD, areaD, gridSteps, threshY, uid, label, color, threshold, thresholdLabel, isMin, sensorKey };
  }

  return (
    <div className="card" style={{ marginBottom: 24, border: anyAlert ? "2px solid #fca5a5" : undefined }}>
      {/* Card header — title + optional dropdown */}
      <div className="cardHeader" style={{ borderBottom: "1px solid #f3f4f6", paddingBottom: "0.75rem" }}>
        <div style={{ display: "flex", alignItems: "center", gap: "0.5rem", flex: 1, minWidth: 0 }}>
          <span style={{ fontSize: "1.3rem" }}>🌡️</span>
          <div style={{ flex: 1, minWidth: 0 }}>
            <div className="cardTitle" style={{ fontSize: "1.05rem" }}>Temperature Monitoring</div>
            <div style={{ fontSize: "0.72rem", color: "#6b7280", marginTop: 2 }}>
              {locations.length} location{locations.length !== 1 ? "s" : ""} — tap a pill to highlight a line
            </div>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
          {locations.length > 1 && (
            <div style={{ position: "relative" }}>
              <input
                type="text"
                placeholder="Search location…"
                value={locSearch || (showLocDropdown ? "" : activeLoc)}
                onFocus={() => { setLocSearch(""); setShowLocDropdown(true); }}
                onChange={e => { setLocSearch(e.target.value); setShowLocDropdown(true); }}
                onBlur={() => { setTimeout(() => setShowLocDropdown(false), 220); }}
                style={{
                  fontSize: "0.78rem",
                  fontWeight: 600,
                  color: "#2A295C",
                  background: "#f0f1f8",
                  border: "1.5px solid #c7c9e3",
                  borderRadius: 8,
                  padding: "0.3rem 0.55rem",
                  width: 190,
                  outline: "none",
                }}
              />
              {showLocDropdown && (
                <div style={{
                  position: "absolute",
                  top: "110%",
                  right: 0,
                  background: "#fff",
                  border: "1.5px solid #c7c9e3",
                  borderRadius: 8,
                  zIndex: 99,
                  minWidth: 220,
                  maxHeight: 220,
                  overflowY: "auto",
                  boxShadow: "0 4px 16px rgba(0,0,0,0.13)",
                }}>
                  {locations
                    .filter(loc => loc.toLowerCase().includes((locSearch || "").toLowerCase()))
                    .map(loc => {
                      const uNum = locationData[loc]?.unitNum;
                      // Split display: unit badge + name
                      const dispName = uNum ? loc.replace(` #${uNum}`, "") : loc;
                      return (
                        <div
                          key={loc}
                          onMouseDown={() => { setSelectedLoc(loc); setLocSearch(""); setShowLocDropdown(false); }}
                          style={{
                            padding: "0.45rem 0.75rem",
                            display: "flex",
                            alignItems: "center",
                            gap: 6,
                            fontWeight: loc === activeLoc ? 700 : 500,
                            color: loc === activeLoc ? "#2A295C" : "#374151",
                            background: loc === activeLoc ? "#f0f1f8" : "transparent",
                            cursor: "pointer",
                            borderBottom: "1px solid #f3f4f6",
                          }}
                        >
                          {uNum && (
                            <span style={{ background: "#2A295C", color: "#fff", borderRadius: 5, padding: "1px 6px", fontSize: "0.72rem", fontWeight: 800, flexShrink: 0 }}>
                              #{uNum}
                            </span>
                          )}
                          <span style={{ fontSize: "0.78rem" }}>{dispName}</span>
                        </div>
                      );
                    })}
                  {locations.filter(loc => loc.toLowerCase().includes((locSearch || "").toLowerCase())).length === 0 && (
                    <div style={{ padding: "0.5rem 0.75rem", fontSize: "0.75rem", color: "#9ca3af" }}>No matches</div>
                  )}
                </div>
              )}
            </div>
          )}
          {anyAlert && (
            <span style={{ background: "#fee2e2", color: "#dc2626", borderRadius: 6, padding: "0.25rem 0.65rem", fontSize: "0.75rem", fontWeight: 700, whiteSpace: "nowrap" }}>⚠️ Temp Alert</span>
          )}
        </div>
      </div>

      {/* At-a-glance summary row — averages across ALL locations */}
      <div style={{ display: "flex", alignItems: "stretch", gap: "0.5rem", padding: "0.85rem 1rem", borderBottom: "1px solid #f3f4f6" }}>
        <div style={{ fontSize: "0.7rem", color: "#9ca3af", display: "flex", alignItems: "center", marginRight: 2, fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.04em", flexShrink: 0 }}>All Avgs:</div>
        {glanceSummary.hand !== null && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", background: glanceSummary.handPass ? "#dbeafe" : "#fee2e2", borderRadius: 10, padding: "0.35rem 0.4rem", minWidth: 0, border: glanceSummary.handPass ? "1px solid #93c5fd" : "1px solid #fca5a5" }}>
            <span style={{ fontSize: "0.6rem", color: glanceSummary.handPass ? "#1d4ed8" : "#dc2626", fontWeight: 600, textTransform: "uppercase", textAlign: "center" }}>Hand Sink</span>
            <span style={{ fontSize: "1.1rem", fontWeight: 800, color: glanceSummary.handPass ? "#1d4ed8" : "#dc2626", lineHeight: 1.2 }}>{glanceSummary.hand}°F</span>
            <span style={{ fontSize: "0.55rem", color: glanceSummary.handPass ? "#1d4ed8" : "#dc2626", textAlign: "center" }}>{glanceSummary.handPass ? "✓ min 95°F" : "✗ min 95°F"}</span>
          </div>
        )}
        {glanceSummary.three !== null && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", background: glanceSummary.threePass ? "#ede9fe" : "#fee2e2", borderRadius: 10, padding: "0.35rem 0.4rem", minWidth: 0, border: glanceSummary.threePass ? "1px solid #c4b5fd" : "1px solid #fca5a5" }}>
            <span style={{ fontSize: "0.6rem", color: glanceSummary.threePass ? "#7c3aed" : "#dc2626", fontWeight: 600, textTransform: "uppercase", textAlign: "center" }}>3-Comp</span>
            <span style={{ fontSize: "1.1rem", fontWeight: 800, color: glanceSummary.threePass ? "#7c3aed" : "#dc2626", lineHeight: 1.2 }}>{glanceSummary.three}°F</span>
            <span style={{ fontSize: "0.55rem", color: glanceSummary.threePass ? "#7c3aed" : "#dc2626", textAlign: "center" }}>{glanceSummary.threePass ? "✓ min 110°F" : "✗ min 110°F"}</span>
          </div>
        )}
        {glanceSummary.cooler !== null && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", background: glanceSummary.coolerPass ? "#d1fae5" : "#fee2e2", borderRadius: 10, padding: "0.35rem 0.4rem", minWidth: 0, border: glanceSummary.coolerPass ? "1px solid #6ee7b7" : "1px solid #fca5a5" }}>
            <span style={{ fontSize: "0.6rem", color: glanceSummary.coolerPass ? "#059669" : "#dc2626", fontWeight: 600, textTransform: "uppercase", textAlign: "center" }}>Cooler</span>
            <span style={{ fontSize: "1.1rem", fontWeight: 800, color: glanceSummary.coolerPass ? "#059669" : "#dc2626", lineHeight: 1.2 }}>{glanceSummary.cooler}°F</span>
            <span style={{ fontSize: "0.55rem", color: glanceSummary.coolerPass ? "#059669" : "#dc2626", textAlign: "center" }}>{glanceSummary.coolerPass ? "✓ max 40°F" : "✗ max 40°F"}</span>
          </div>
        )}
        {glanceSummary.freezer !== null && (
          <div style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", background: glanceSummary.freezerPass ? "#cffafe" : "#fee2e2", borderRadius: 10, padding: "0.35rem 0.4rem", minWidth: 0, border: glanceSummary.freezerPass ? "1px solid #67e8f9" : "1px solid #fca5a5" }}>
            <span style={{ fontSize: "0.6rem", color: glanceSummary.freezerPass ? "#0891b2" : "#dc2626", fontWeight: 600, textTransform: "uppercase", textAlign: "center" }}>Freezer</span>
            <span style={{ fontSize: "1.1rem", fontWeight: 800, color: glanceSummary.freezerPass ? "#0891b2" : "#dc2626", lineHeight: 1.2 }}>{glanceSummary.freezer}°F</span>
            <span style={{ fontSize: "0.55rem", color: glanceSummary.freezerPass ? "#0891b2" : "#dc2626", textAlign: "center" }}>{glanceSummary.freezerPass ? "✓ max 20°F" : "✗ max 20°F"}</span>
          </div>
        )}
        {glanceSummary.hand === null && glanceSummary.three === null && glanceSummary.cooler === null && glanceSummary.freezer === null && (
          <span style={{ fontSize: "0.8rem", color: "#9ca3af" }}>No temperature data in the current filter</span>
        )}
      </div>

      <div className="cardBody" style={{ display: "flex", flexDirection: "column", gap: "1rem" }}>
        {/* Location + unit header */}
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          {activeUnitNum && (
            <span style={{ background: "#2A295C", color: "#fff", borderRadius: 6, padding: "2px 10px", fontSize: "0.82rem", fontWeight: 800, letterSpacing: "0.03em" }}>
              Unit #{activeUnitNum}
            </span>
          )}
          <span style={{ fontWeight: 700, fontSize: "0.85rem", color: "#1e293b" }}>
            {activeUnitNum ? activeLoc.replace(` #${activeUnitNum}`, "") : activeLoc}
          </span>
          <span style={{ marginLeft: "auto", fontSize: "0.72rem", color: "#6b7280", background: "#f0fdf4", borderRadius: 6, padding: "2px 8px", fontWeight: 600 }}>
            {activePoints.length} reading{activePoints.length !== 1 ? "s" : ""}
          </span>
        </div>

        {/* 4 independent mini-charts, one per sensor type */}
        {[
          buildSensorChart("handSink",  "Hand Sink",  "#3b82f6", "handGrad",   95,  "min 95°F",  true),
          buildSensorChart("threeComp", "3-Comp Sink","#8b5cf6", "threeGrad", 110, "min 110°F", true),
          buildSensorChart("cooler",    "Cooler",     "#059669", "coolerGrad",  40,  "max 40°F",  false, "coolerItems"),
          buildSensorChart("freezer",   "Freezer",    "#0891b2", "freezerGrad", 20,  "max 20°F",  false, "freezerItems"),
        ].map(chart => {
          if (!chart) return null;
          const { vals, avg, allPass, allItemLabels, SW, SH, SPAD, SPADR, SPADT, SPADB, sToX, sToY, coords, pathD, areaD, gridSteps, threshY, uid, label, color, threshold, thresholdLabel, isMin } = chart;
          return (
            <div key={uid} style={{ borderRadius: 10, border: `1.5px solid ${allPass ? "#e5e7eb" : "#fca5a5"}`, background: allPass ? "#fff" : "#fff9f9", padding: "0.6rem 0.75rem 0.4rem" }}>
              {/* Mini-chart header: sensor name + avg + pass badge */}
              <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: allItemLabels.length > 0 ? 3 : 6 }}>
                <span style={{ width: 10, height: 10, borderRadius: "50%", background: color, flexShrink: 0, display: "inline-block" }} />
                <span style={{ fontWeight: 700, fontSize: "0.82rem", color: "#1e293b" }}>{label}</span>
                <span style={{
                  fontSize: "0.75rem", fontWeight: 700,
                  background: allPass ? (color + "22") : "#fee2e2",
                  color: allPass ? color : "#dc2626",
                  borderRadius: 6, padding: "1px 7px",
                }}>
                  Avg {avg}°F
                </span>
                <span style={{
                  fontSize: "0.7rem", fontWeight: 600,
                  background: allPass ? "#d1fae5" : "#fee2e2",
                  color: allPass ? "#065f46" : "#dc2626",
                  borderRadius: 6, padding: "1px 7px",
                  marginLeft: "auto",
                }}>
                  {allPass ? "✓" : "✗"} {thresholdLabel}
                </span>
              </div>
              {/* Equipment name badges (cooler/freezer with named units) */}
              {allItemLabels.length > 0 && (
                <div style={{ display: "flex", flexWrap: "wrap", gap: 4, marginBottom: 6 }}>
                  {allItemLabels.map(lbl => (
                    <span key={lbl} style={{ fontSize: "0.68rem", fontWeight: 600, color: color, background: color + "18", borderRadius: 5, padding: "1px 6px", border: `1px solid ${color}33` }}>{lbl}</span>
                  ))}
                </div>
              )}
              <svg viewBox={`0 0 ${SW} ${SH}`} className="tempChartSvg" onMouseLeave={() => setHoveredPoint(null)}>
                <defs>
                  <linearGradient id={uid} x1="0" y1="0" x2="0" y2="1">
                    <stop offset="0%" stopColor={color} stopOpacity="0.3" />
                    <stop offset="100%" stopColor={color} stopOpacity="0.02" />
                  </linearGradient>
                </defs>

                {/* Grid lines */}
                {gridSteps.map(t => (
                  <g key={t}>
                    <line x1={SPAD} y1={sToY(t)} x2={SW - SPADR} y2={sToY(t)} stroke="#e5e7eb" strokeWidth="1" />
                    <text x={SPAD - 5} y={sToY(t) + 4} textAnchor="end" fontSize="9" fill="#9ca3af">{t}°</text>
                  </g>
                ))}

                {/* Threshold line */}
                <line x1={SPAD} y1={threshY} x2={SW - SPADR - 38} y2={threshY} stroke={color} strokeDasharray="6,4" strokeWidth="1.5" opacity="0.65" />
                <rect x={SW - SPADR - 36} y={threshY - 8} width="36" height="16" rx="3" fill={color} opacity="0.9" />
                <text x={SW - SPADR - 18} y={threshY + 4} textAnchor="middle" fontSize="8" fill="white" fontWeight="bold">{threshold}°F</text>

                {/* Area fill */}
                {coords.length >= 2 && <path d={areaD} fill={`url(#${uid})`} />}

                {/* Line */}
                {coords.length > 1 && <path d={pathD} fill="none" stroke={color} strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" />}

                {/* Out-of-range dots (always visible) */}
                {vals.map((d, idx) => {
                  const oor = isMin ? d.v < threshold : d.v > threshold;
                  if (!oor) return null;
                  return <circle key={idx} cx={sToX(idx)} cy={sToY(d.v)} r="5" fill="#ef4444" stroke="white" strokeWidth="1.5" />;
                })}

                {/* Hover crosshair + tooltip */}
                {vals.map((d, idx) => {
                  const hk = `${uid}-${idx}`;
                  const isHov = hoveredPoint === hk;
                  const px = sToX(idx);
                  const py = sToY(d.v);
                  const ok = isMin ? d.v >= threshold : d.v <= threshold;
                  // Named units for this specific data point (cooler/freezer)
                  const namedUnits = d.items && d.items.length > 0 ? d.items : [];
                  // Tooltip height: base 36 + 12 per named unit beyond first (first is shown on main row)
                  const extraUnits = namedUnits.length > 1 ? namedUnits.slice(1) : [];
                  const tipW = namedUnits.length > 0 ? 110 : 76;
                  const tipH = 36 + extraUnits.length * 13;
                  // X: prefer right of dot, flip left if it would overflow right edge (leave room for threshold badge ~40px)
                  const tipX = px + tipW + 10 > SW - SPADR - 38 ? px - tipW - 6 : px + 6;
                  // Y: prefer below dot, flip above if near bottom of chart area
                  const chartBottom = SH - SPADB;
                  const tipY = py + 8 + tipH < chartBottom - 2
                    ? py + 8
                    : Math.max(SPADT + 2, py - tipH - 8);
                  return (
                    <g key={idx} onMouseEnter={() => setHoveredPoint(hk)} onTouchStart={() => setHoveredPoint(hk)}>
                      <rect x={px - 14} y={SPADT} width="28" height={SH - SPADT - SPADB} fill="transparent" />
                      {isHov && (
                        <g>
                          <line x1={px} y1={SPADT} x2={px} y2={SH - SPADB} stroke="#94a3b8" strokeWidth="1" strokeDasharray="3,3" />
                          <circle cx={px} cy={py} r="4.5" fill="white" stroke={ok ? color : "#ef4444"} strokeWidth="2" />
                          <rect x={tipX} y={tipY} width={tipW} height={tipH} rx="5" fill="#1e293b" opacity="0.93" />
                          <text x={tipX + tipW / 2} y={tipY + 11} textAnchor="middle" fontSize="9" fill="#94a3b8" fontWeight="600">{d.date.slice(5)}</text>
                          {namedUnits.length > 0 ? (
                            namedUnits.map((unit, ui) => {
                              const uOk = isMin ? unit.tempF >= threshold : unit.tempF <= threshold;
                              return (
                                <g key={ui}>
                                  <circle cx={tipX + 9} cy={tipY + 24 + ui * 13} r="3" fill={uOk ? color : "#ef4444"} />
                                  <text x={tipX + 16} y={tipY + 28 + ui * 13} fontSize="9" fill="white">
                                    <tspan fontWeight="500">{unit.label}: </tspan>
                                    <tspan fontWeight="700" fill={uOk ? "white" : "#fca5a5"}>{unit.tempF}°F</tspan>
                                  </text>
                                </g>
                              );
                            })
                          ) : (
                            <g>
                              <circle cx={tipX + 9} cy={tipY + 24} r="3" fill={ok ? color : "#ef4444"} />
                              <text x={tipX + 16} y={tipY + 28} fontSize="9.5" fill="white">
                                <tspan fontWeight="500">{label}: </tspan>
                                <tspan fontWeight="700" fill={ok ? "white" : "#fca5a5"}>{d.v}°F</tspan>
                              </text>
                            </g>
                          )}
                        </g>
                      )}
                    </g>
                  );
                })}

                {/* X-axis date labels */}
                {vals.map((d, idx) => (
                  <text key={idx} x={sToX(idx)} y={SH - 8} textAnchor="middle" fontSize="9" fill="#6b7280" fontWeight="500">
                    {d.date.slice(5)}
                  </text>
                ))}
              </svg>
            </div>
          );
        })}
      </div>
    </div>
  );
}

/* ── Predictive AI Engine ────────────────────────────────── */
function buildPredictions(history) {
  if (!history || history.length < 2) return [];
  const predictions = [];

  // Sort history oldest → newest
  const sorted = [...history].sort((a, b) => {
    const da = new Date(a.inspectionDate || 0);
    const db = new Date(b.inspectionDate || 0);
    return da - db;
  });

  // ── 1. Per-location issue recurrence prediction ──────────
  // For each location, look at the last N inspections. If a category
  // appeared in ≥60% of them, it's predicted to appear again.
  //
  // Key normalization: lowercase + trim so "North Kitchen" and "north kitchen"
  // group together. siteNumber and floor are intentionally excluded from the key
  // so the same physical site always groups even if floor/unit varies.
  const byLocation = {};
  for (const rec of sorted) {
    const loc = (rec.siteName || rec.location || "—").trim().toLowerCase();
    if (!byLocation[loc]) byLocation[loc] = [];
    byLocation[loc].push(rec);
  }
  // Build a display-name map (use the first record's original casing for labels)
  const locDisplayName = {};
  for (const rec of sorted) {
    const key = (rec.siteName || rec.location || "—").trim().toLowerCase();
    if (!locDisplayName[key]) locDisplayName[key] = rec.siteName || rec.location || "—";
  }

  for (const [loc, recs] of Object.entries(byLocation)) {
    if (recs.length < 2) continue;
    const recent = recs.slice(-6); // last 6 inspections at this location
    const catCounts = {};
    for (const rec of recent) {
      const seen = new Set();
      for (const item of (rec.actionItems || [])) {
        const cat = item.issue?.split(":")[0]?.trim() || "Other";
        if (!seen.has(cat)) {
          seen.add(cat);
          catCounts[cat] = (catCounts[cat] || 0) + 1;
        }
      }
    }
    for (const [cat, count] of Object.entries(catCounts)) {
      const rate = count / recent.length;
      if (rate >= 0.6) {
        const risk = rate >= 0.85 ? "high" : "medium";
        const displayLoc = locDisplayName[loc] || loc;
        predictions.push({
          type: "recurrence",
          risk,
          location: displayLoc,
          category: cat,
          rate: Math.round(rate * 100),
          occurrences: count,
          total: recent.length,
          message: `"${cat}" issues have appeared in ${count} of the last ${recent.length} inspections at ${displayLoc} (${Math.round(rate * 100)}%) — likely to recur.`,
          detail: `This category has been flagged consistently. Address root cause to break the pattern.`,
        });
      }
    }
  }

  // ── 2. Temperature drift prediction (equipment) ──────────
  // If a cooler/freezer temp has been creeping upward over the last 3+
  // readings at a location, predict it will breach threshold.
  const EQUIP_KEYS = [
    { key: "doubleDoorCooler", label: "Double-Door Cooler", max: 40, type: "cooler" },
    { key: "doubleDoorFreezer", label: "Double-Door Freezer", max: 20, type: "freezer" },
    { key: "walkInCooler", label: "Walk-In Cooler", max: 40, type: "cooler" },
    { key: "walkInFreezer", label: "Walk-In Freezer", max: 20, type: "freezer" },
    { key: "prepCooler", label: "Prep Cooler", max: 40, type: "cooler" },
  ];

  for (const [loc, recs] of Object.entries(byLocation)) {
    const displayLoc = locDisplayName[loc] || loc;
    for (const equip of EQUIP_KEYS) {
      const readings = recs
        .map(r => ({ date: r.inspectionDate, val: Number(r.inspection?.equipment?.[equip.key]?.tempF || r[equip.key + "TempF"] || NaN) }))
        .filter(r => !isNaN(r.val) && r.val > 0);
      if (readings.length < 3) continue;
      const last3 = readings.slice(-3);
      // Check monotonic upward trend in last 3 readings
      const rising = last3[1].val > last3[0].val && last3[2].val > last3[1].val;
      if (!rising) continue;
      const drift = last3[2].val - last3[0].val;
      const currentTemp = last3[2].val;
      const gap = equip.max - currentTemp;
      if (drift <= 0 || gap >= 15) continue; // not significant
      const stepsToBreech = Math.ceil(gap / (drift / 2));
      const risk = gap < 5 ? "high" : "medium";
      predictions.push({
        type: "tempDrift",
        risk,
        location: displayLoc,
        category: equip.label,
        message: `${equip.label} at ${displayLoc} has risen from ${last3[0].val}°F → ${last3[2].val}°F over the last ${last3.length} inspections (${gap > 0 ? `${gap.toFixed(1)}°F below max` : "AT OR ABOVE MAX"}).`,
        detail: risk === "high"
          ? `Temperature is dangerously close to the ${equip.max}°F limit. Inspect compressor and door seals before the next visit.`
          : `Upward trend detected. Schedule preventive maintenance within ${stepsToBreech} inspection cycle(s) to avoid failure.`,
        currentTemp,
        maxTemp: equip.max,
        drift: drift.toFixed(1),
      });
    }
  }

  // ── 3. Issue escalation prediction ──────────────────────
  // If a specific category was "Needs Attention" in 2+ consecutive
  // inspections at a location, predict it will escalate to "Not Clean".
  const SECTION_MAP = {
    facility: ["ceiling", "walls", "floors", "lighting"],
    operations: ["employeePractices", "handwashing", "labelingDating", "logs"],
    equipment: ["doubleDoorCooler", "doubleDoorFreezer", "walkInCooler", "walkInFreezer", "prepCooler", "warmers", "ovens", "threeCompSink", "ecolab"],
    maintenance: ["hvac", "plumbing", "pestControl", "electricalSafety", "dumpsterArea", "structuralDamage"],
  };
  const ITEM_LABEL = {
    ceiling: "Ceiling", walls: "Walls", floors: "Floors", lighting: "Lighting",
    employeePractices: "Employee Practices", handwashing: "Handwashing",
    labelingDating: "Labeling / Dating", logs: "Logs",
    doubleDoorCooler: "Double-Door Cooler", doubleDoorFreezer: "Double-Door Freezer",
    walkInCooler: "Walk-In Cooler", walkInFreezer: "Walk-In Freezer",
    prepCooler: "Prep Cooler", warmers: "Warmers / Hot Holding", ovens: "Ovens",
    threeCompSink: "3-Compartment Sink", ecolab: "Ecolab / Chemicals",
    hvac: "HVAC", plumbing: "Plumbing", pestControl: "Pest Control",
    electricalSafety: "Electrical Safety", dumpsterArea: "Dumpster Area",
    structuralDamage: "Structural Damage",
  };

  for (const [loc, recs] of Object.entries(byLocation)) {
    if (recs.length < 2) continue;
    const displayLoc = locDisplayName[loc] || loc;
    const last3 = recs.slice(-3);
    for (const [section, keys] of Object.entries(SECTION_MAP)) {
      for (const itemKey of keys) {
        const statuses = last3
          .map(r => r.inspection?.[section]?.[itemKey]?.status || null)
          .filter(Boolean);
        if (statuses.length < 2) continue;
        // All recent readings are "Needs Attention" → escalation risk
        const allAttention = statuses.every(s => s === "Needs Attention");
        if (allAttention && statuses.length >= 2) {
          predictions.push({
            type: "escalation",
            risk: statuses.length >= 3 ? "high" : "medium",
            location: displayLoc,
            category: ITEM_LABEL[itemKey] || itemKey,
            message: `"${ITEM_LABEL[itemKey] || itemKey}" at ${displayLoc} has been "Needs Attention" for ${statuses.length} consecutive inspections.`,
            detail: `Unresolved items tend to escalate to "Not Clean". Assign ownership and set a corrective action deadline before the next visit.`,
          });
        }
      }
    }
  }

  // ── 4. Overdue inspection + prior issues risk flag ───────
  // Applies to ALL locations (even single-inspection locations) so the
  // inspector is alerted about any site that has gone 30+ days unvisited
  // and had open issues at the last visit.
  const now = new Date();
  for (const [loc, recs] of Object.entries(byLocation)) {
    const displayLoc = locDisplayName[loc] || loc;
    const lastRec = recs[recs.length - 1];
    const lastDate = new Date(lastRec.inspectionDate || 0);
    const daysSince = Math.floor((now - lastDate) / (1000 * 60 * 60 * 24));
    const hadIssues = (lastRec.actionItems || []).length > 0;
    if (daysSince >= 30 && hadIssues) {
      const risk = daysSince >= 60 ? "high" : "medium";
      predictions.push({
        type: "overdue",
        risk,
        location: displayLoc,
        category: "Inspection Gap",
        message: `${displayLoc} hasn't been inspected in ${daysSince} days and had ${lastRec.actionItems.length} unresolved issue(s) at last visit.`,
        detail: `Schedule an inspection soon — unresolved issues left unchecked increase the risk of a health code violation.`,
        daysSince,
      });
    }
  }

  // ── 5. Hand sink / 3-comp sink temperature trend ─────────
  for (const [loc, recs] of Object.entries(byLocation)) {
    const displayLoc = locDisplayName[loc] || loc;
    const handTemps = recs.map(r => Number(r.temps?.handSinkTempF || r.handSinkTempF || NaN)).filter(v => !isNaN(v) && v > 0);
    const threeTemps = recs.map(r => Number(r.temps?.threeCompSinkTempF || r.threeCompSinkTempF || NaN)).filter(v => !isNaN(v) && v > 0);

    if (handTemps.length >= 3) {
      const last3 = handTemps.slice(-3);
      const declining = last3[0] > last3[1] && last3[1] > last3[2];
      if (declining && last3[2] < 100) {
        predictions.push({
          type: "tempDrift",
          risk: last3[2] < 97 ? "high" : "medium",
          location: displayLoc,
          category: "Hand Sink Water Temp",
          message: `Hand sink temperature at ${displayLoc} has been declining: ${last3[0]}°F → ${last3[1]}°F → ${last3[2]}°F (min: 95°F).`,
          detail: `Downward trend approaching the 95°F minimum. Inspect water heater output and check for mixing valve issues.`,
        });
      }
    }
    if (threeTemps.length >= 3) {
      const last3 = threeTemps.slice(-3);
      const declining = last3[0] > last3[1] && last3[1] > last3[2];
      if (declining && last3[2] < 115) {
        predictions.push({
          type: "tempDrift",
          risk: last3[2] < 112 ? "high" : "medium",
          location: displayLoc,
          category: "3-Comp Sink Wash Temp",
          message: `3-comp sink wash temperature at ${displayLoc} declining: ${last3[0]}°F → ${last3[1]}°F → ${last3[2]}°F (min: 110°F).`,
          detail: `Trend approaching the 110°F minimum. Check water heater capacity and booster heater for the sink.`,
        });
      }
    }
  }

  // De-duplicate and sort: high risk first, then medium
  const seen = new Set();
  const deduped = predictions.filter(p => {
    const k = `${p.type}|${p.location}|${p.category}`;
    if (seen.has(k)) return false;
    seen.add(k);
    return true;
  });

  return deduped.sort((a, b) => {
    const order = { high: 0, medium: 1, watch: 2 };
    return (order[a.risk] ?? 3) - (order[b.risk] ?? 3);
  });
}

/* ── LocationsPanel — inner sub-panel for the Locations tab ────── */
function LocationsPanel({ loc, passColor, trendArrow, MiniBar, EmptyState }) {
  const [locSub, setLocSub] = React.useState("floor");
  if (!loc) return <EmptyState icon="🗺️" msg="Location profiles will appear after saving inspections with site/floor/type data." />;

  const { byFloor = [], byType = [], bySite = [] } = loc;

  return (
    <div>
      <div style={{ display: "flex", gap: 6, marginBottom: 14 }}>
        {[
          { key: "floor", label: `By Floor (${byFloor.length})` },
          { key: "type",  label: `By Type (${byType.length})` },
          { key: "site",  label: `By Site (${bySite.length})` },
        ].map(t => (
          <button key={t.key} type="button" onClick={() => setLocSub(t.key)}
            style={{
              background: locSub === t.key ? "#eff6ff" : "#f9fafb",
              border: locSub === t.key ? "1.5px solid #93c5fd" : "1px solid #e5e7eb",
              borderRadius: 7, padding: "5px 10px", cursor: "pointer",
              fontSize: "0.73rem", fontWeight: locSub === t.key ? 700 : 400,
              color: locSub === t.key ? "#1d4ed8" : "#6b7280",
            }}
          >{t.label}</button>
        ))}
      </div>

      {/* ── By Floor ── */}
      {locSub === "floor" && (
        byFloor.length === 0
          ? <EmptyState icon="🏗" msg="No floor data yet. Tag inspections with a floor name." />
          : byFloor.map(f => (
              <div key={f.floor} style={{ background: "#fff", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                  <span style={{ fontWeight: 700, fontSize: "0.88rem", color: "#1e293b", flex: 1 }}>{f.floor}</span>
                  {f.trendLabel && (() => { const a = trendArrow(f.trendLabel); return <span style={{ fontSize: "0.72rem", fontWeight: 600, color: a.color }}>{a.icon} {f.trendLabel}</span>; })()}
                  <span style={{ fontWeight: 800, fontSize: "0.9rem", color: passColor(f.passRate), minWidth: 38, textAlign: "right" }}>{f.passRate}%</span>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <MiniBar pct={f.passRate} color={passColor(f.passRate)} />
                </div>
                <div style={{ display: "flex", gap: 12, marginTop: 6, fontSize: "0.72rem", color: "#64748b" }}>
                  <span>{f.total} visit{f.total !== 1 ? "s" : ""}</span>
                  {f.topIssue && <span>Top issue: <strong style={{ color: "#374151" }}>{f.topIssue}</strong></span>}
                </div>
              </div>
            ))
      )}

      {/* ── By Type ── */}
      {locSub === "type" && (
        byType.length === 0
          ? <EmptyState icon="🏪" msg="No type data yet. Tag inspections with a site type." />
          : byType.map(t => (
              <div key={t.type} style={{ background: "#fff", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                  <span style={{ fontWeight: 700, fontSize: "0.88rem", color: "#1e293b", flex: 1 }}>{t.type}</span>
                  {t.trendLabel && (() => { const a = trendArrow(t.trendLabel); return <span style={{ fontSize: "0.72rem", fontWeight: 600, color: a.color }}>{a.icon} {t.trendLabel}</span>; })()}
                  <span style={{ fontWeight: 800, fontSize: "0.9rem", color: passColor(t.passRate), minWidth: 38, textAlign: "right" }}>{t.passRate}%</span>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <MiniBar pct={t.passRate} color={passColor(t.passRate)} />
                </div>
                <div style={{ display: "flex", gap: 12, marginTop: 6, fontSize: "0.72rem", color: "#64748b" }}>
                  <span>{t.total} visit{t.total !== 1 ? "s" : ""}</span>
                  {t.topIssue && <span>Top issue: <strong style={{ color: "#374151" }}>{t.topIssue}</strong></span>}
                </div>
              </div>
            ))
      )}

      {/* ── By Site ── */}
      {locSub === "site" && (
        bySite.length === 0
          ? <EmptyState icon="📍" msg="No site data yet. Tag inspections with a site name." />
          : bySite.map(s => (
              <div key={s.site} style={{ background: "#fff", border: "1.5px solid #e2e8f0", borderRadius: 12, padding: "12px 14px", marginBottom: 8 }}>
                <div style={{ display: "flex", alignItems: "center", gap: 8, marginBottom: 6 }}>
                  <span style={{ fontWeight: 700, fontSize: "0.88rem", color: "#1e293b", flex: 1 }}>{s.site}</span>
                  {s.trendLabel && (() => { const a = trendArrow(s.trendLabel); return <span style={{ fontSize: "0.72rem", fontWeight: 600, color: a.color }}>{a.icon} {s.trendLabel}</span>; })()}
                  <span style={{ fontWeight: 800, fontSize: "0.9rem", color: passColor(s.passRate), minWidth: 38, textAlign: "right" }}>{s.passRate}%</span>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                  <MiniBar pct={s.passRate} color={passColor(s.passRate)} />
                </div>
                <div style={{ display: "flex", gap: 12, marginTop: 6, fontSize: "0.72rem", color: "#64748b" }}>
                  <span>{s.total} visit{s.total !== 1 ? "s" : ""}</span>
                  {s.topIssue && <span>Top issue: <strong style={{ color: "#374151" }}>{s.topIssue}</strong></span>}
                </div>
              </div>
            ))
      )}
    </div>
  );
}

